    /// Stage the current file (`:Gadd`) or all changes (`:Gadd!`).
    fn cmd_git_add(&mut self, all: bool) -> EngineAction {
        let dir = self.git_dir();
        let result = if all {
            git::stage_all(&dir)
        } else {
            match self.file_path().map(|p| p.to_path_buf()) {
                Some(path) => git::stage_file(&path),
                None => Err("No file to stage".to_string()),
            }
        };
        match result {
            Ok(()) => {
                // Refresh git diff markers for all open buffers.
                let ids: Vec<_> = self.buffer_manager.list();
                for id in ids {
                    self.refresh_git_diff(id);
                }
                // Update branch (in case this was first commit)
                self.git_branch = git::current_branch(&dir);
                let label = if all { "all files" } else { "current file" };
                self.message = format!("Staged {}", label);
                EngineAction::None
            }
            Err(e) => {
                self.message = e;
                EngineAction::Error
            }
        }
    }

    /// Commit staged changes with the given message (`:Gcommit <msg>`).
    fn cmd_git_commit(&mut self, message: &str) -> EngineAction {
        let dir = self.git_dir();
        match git::commit(&dir, message) {
            Ok(summary) => {
                // Update branch name (in case first commit on new branch).
                self.git_branch = git::current_branch(&dir);
                // Refresh diffs (committed changes are no longer "modified").
                let ids: Vec<_> = self.buffer_manager.list();
                for id in ids {
                    self.refresh_git_diff(id);
                }
                self.message = summary;
                EngineAction::None
            }
            Err(e) => {
                self.message = e;
                EngineAction::Error
            }
        }
    }

    /// Push current branch to remote (`:Gpush`).
    fn cmd_git_push(&mut self) -> EngineAction {
        let dir = self.git_dir();
        match git::push(&dir) {
            Ok(summary) => {
                self.message = if summary.is_empty() {
                    "Pushed".to_string()
                } else {
                    summary
                };
                EngineAction::None
            }
            Err(e) => {
                self.message = e;
                EngineAction::Error
            }
        }
    }

    /// Open `git blame` for the current file in a vertical split.
    fn cmd_git_blame(&mut self) -> EngineAction {
        let path = match self.file_path().map(|p| p.to_path_buf()) {
            Some(p) => p,
            None => {
                self.message = "No file".to_string();
                return EngineAction::Error;
            }
        };
        match git::blame_text(&path) {
            Some(text) => {
                let buf_id = self.buffer_manager.create();
                if let Some(state) = self.buffer_manager.get_mut(buf_id) {
                    state.buffer.content = ropey::Rope::from_str(&text);
                }
                let source_win = self.active_window_id();
                self.split_window(SplitDirection::Vertical, None);
                let blame_win = self.active_window_id();
                self.active_window_mut().buffer_id = buf_id;
                self.scroll_bind_pairs.push((source_win, blame_win));
                self.message = format!("Git blame: {}", path.display());
                EngineAction::None
            }
            None => {
                self.message =
                    "No blame info (file not committed or not in a git repo)".to_string();
                EngineAction::Error
            }
        }
    }

    // =======================================================================
    // File rename / move
    // =======================================================================

    /// Rename or move a single file / directory within the filesystem.
    ///
    /// `new_name` is the bare name (no path separators).  The new location is
    /// built as `old_path.parent() / new_name`.
    ///
    /// Any open buffer whose `file_path` matches `old_path` is updated in
    /// place so the editor does not show a stale path.
    pub fn rename_file(&mut self, old_path: &Path, new_name: &str) -> Result<(), String> {
        if new_name.is_empty() {
            return Err("Name cannot be empty".to_string());
        }
        if new_name.contains('/') || new_name.contains('\\') {
            return Err("Name must not contain path separators".to_string());
        }
        let parent = old_path
            .parent()
            .ok_or_else(|| "Cannot rename root".to_string())?;
        let new_path = parent.join(new_name);
        std::fs::rename(old_path, &new_path).map_err(|e| format!("Rename failed: {}", e))?;

        // Update any open buffer that was showing the old path.
        for id in self.buffer_manager.list() {
            if let Some(state) = self.buffer_manager.get_mut(id) {
                if state.file_path.as_deref() == Some(old_path) {
                    state.canonical_path = new_path.canonicalize().ok();
                    state.file_path = Some(new_path.clone());
                    self.refresh_git_diff(id);
                }
            }
        }
        Ok(())
    }

    /// Move `src` into `dest_dir` (a directory).
    ///
    /// The filename is preserved.  Any open buffer whose `file_path` matches
    /// `src` is updated to point at the new location.
    pub fn move_file(&mut self, src: &Path, dest: &Path) -> Result<(), String> {
        // If dest is a directory, move file into it keeping the original name.
        // Otherwise treat dest as the full destination path (allows rename+move).
        let final_dest = if dest.is_dir() {
            let file_name = src
                .file_name()
                .ok_or_else(|| "Cannot determine file name".to_string())?;
            dest.join(file_name)
        } else {
            let parent = dest
                .parent()
                .ok_or_else(|| "Invalid destination path".to_string())?;
            if !parent.is_dir() {
                return Err(format!("'{}' is not a directory", parent.display()));
            }
            dest.to_path_buf()
        };
        std::fs::rename(src, &final_dest).map_err(|e| format!("Move failed: {}", e))?;

        // Update any open buffer that was showing the old path.
        for id in self.buffer_manager.list() {
            if let Some(state) = self.buffer_manager.get_mut(id) {
                if state.file_path.as_deref() == Some(src) {
                    state.canonical_path = final_dest.canonicalize().ok();
                    state.file_path = Some(final_dest.clone());
                    self.refresh_git_diff(id);
                }
            }
        }
        Ok(())
    }

    // =======================================================================
    // Two-way diff
    // =======================================================================

    /// Mark the current window as a diff participant (public for UI backends).
    ///
    /// - First call: remembers the window id in `diff_window_pair` (left side).
    /// - Second call: sets both windows and runs `compute_diff()`.
    /// - If diff is already active, resets and re-runs.
    pub fn cmd_diffthis(&mut self) -> EngineAction {
        let win = self.active_window_id();
        match self.diff_window_pair {
            None => {
                // First window: store it as the left side.
                self.diff_window_pair = Some((win, win)); // placeholder; right == left means "waiting"
                self.message = "DiffThis: select second window with :diffthis".to_string();
            }
            Some((a, b)) if a == b && a != win => {
                // Second window chosen: activate diff.
                self.diff_window_pair = Some((a, win));
                self.compute_diff();
                self.message = "Diff active".to_string();
            }
            Some(_) => {
                self.message = "Diff already active. Use :diffoff to reset.".to_string();
            }
        }
        EngineAction::None
    }

    /// Disable diff mode and clear all diff state.
    pub fn cmd_diffoff(&mut self) -> EngineAction {
        self.diff_window_pair = None;
        self.diff_results.clear();
        self.message = "Diff off".to_string();
        EngineAction::None
    }

    /// Open `path` in a new vertical split and immediately diff it against the
    /// current window.  Public for use by UI backends.
    pub fn cmd_diffsplit(&mut self, path: &Path) -> EngineAction {
        let left_win = self.active_window_id();
        self.split_window(SplitDirection::Vertical, Some(path));
        let right_win = self.active_window_id();
        self.diff_window_pair = Some((left_win, right_win));
        self.compute_diff();
        self.message = format!("Diff: {}", path.display());
        EngineAction::None
    }

    /// Internal: compute the LCS diff between the two diff windows and store
    /// results in `self.diff_results`.
    fn compute_diff(&mut self) {
        let (a_win, b_win) = match self.diff_window_pair {
            Some(pair) => pair,
            None => return,
        };
        let a_lines: Vec<String> = {
            if let Some(w) = self.windows.get(&a_win) {
                if let Some(s) = self.buffer_manager.get(w.buffer_id) {
                    s.buffer.content.lines().map(|l| l.to_string()).collect()
                } else {
                    vec![]
                }
            } else {
                vec![]
            }
        };
        let b_lines: Vec<String> = {
            if let Some(w) = self.windows.get(&b_win) {
                if let Some(s) = self.buffer_manager.get(w.buffer_id) {
                    s.buffer.content.lines().map(|l| l.to_string()).collect()
                } else {
                    vec![]
                }
            } else {
                vec![]
            }
        };
        let a_refs: Vec<&str> = a_lines.iter().map(String::as_str).collect();
        let b_refs: Vec<&str> = b_lines.iter().map(String::as_str).collect();
        let (da, db) = lcs_diff(&a_refs, &b_refs);
        self.diff_results.insert(a_win, da);
        self.diff_results.insert(b_win, db);
    }

    // =======================================================================
    // Preview mode
    // =======================================================================

    /// Promote a preview buffer to permanent.
    pub fn promote_preview(&mut self, buffer_id: BufferId) {
        if let Some(state) = self.buffer_manager.get_mut(buffer_id) {
            state.preview = false;
        }
        if self.preview_buffer_id == Some(buffer_id) {
            self.preview_buffer_id = None;
        }
    }

    /// Open a file in the current window with the given mode.
    ///
    /// - `Preview`: Replaces any existing preview buffer. The tab shows italic/dimmed.
    /// - `Permanent`: Opens the file as a normal, persistent buffer.
    ///
    /// If the file is already open as a permanent buffer, just switches to it regardless of mode.
    pub fn open_file_with_mode(&mut self, path: &Path, mode: OpenMode) -> Result<(), String> {
        // Check which buffers exist before opening (to detect reuse vs creation)
        let existing_ids: Vec<_> = self.buffer_manager.list();

        let buffer_id = self
            .buffer_manager
            .open_file(path)
            .map_err(|e| format!("Error: {}", e))?;

        let already_existed = existing_ids.contains(&buffer_id);
        let is_already_permanent = already_existed
            && self
                .buffer_manager
                .get(buffer_id)
                .is_some_and(|s| !s.preview);

        // If buffer already exists as permanent, just switch to it
        if is_already_permanent && self.preview_buffer_id != Some(buffer_id) {
            let current = self.active_buffer_id();
            if current != buffer_id {
                self.buffer_manager.alternate_buffer = Some(current);
            }
            self.switch_window_buffer(buffer_id);
            self.message = format!("\"{}\"", path.display());
            return Ok(());
        }

        match mode {
            OpenMode::Preview => {
                // Close old preview if it's a different buffer
                if let Some(old_preview) = self.preview_buffer_id {
                    if old_preview != buffer_id {
                        // Only close if no other window shows it
                        let _ = self.delete_buffer(old_preview, true);
                    }
                }
                // Mark as preview
                if let Some(state) = self.buffer_manager.get_mut(buffer_id) {
                    state.preview = true;
                }
                self.preview_buffer_id = Some(buffer_id);
            }
            OpenMode::Permanent => {
                // If it was a preview, promote it
                if self.preview_buffer_id == Some(buffer_id) {
                    self.promote_preview(buffer_id);
                }
            }
        }

        let current = self.active_buffer_id();
        if current != buffer_id {
            self.buffer_manager.alternate_buffer = Some(current);
        }
        self.switch_window_buffer(buffer_id);
        self.refresh_git_diff(buffer_id);
        self.message = format!("\"{}\"", path.display());
        self.lsp_did_open(buffer_id);
        Ok(())
    }

    // =======================================================================
    // Window operations
    // =======================================================================

    /// Create a new window ID.
    fn new_window_id(&mut self) -> WindowId {
        let id = WindowId(self.next_window_id);
        self.next_window_id += 1;
        id
    }

    /// Create a new tab ID.
    fn new_tab_id(&mut self) -> TabId {
        let id = TabId(self.next_tab_id);
        self.next_tab_id += 1;
        id
    }

    /// Split the active window in the given direction.
    pub fn split_window(&mut self, direction: SplitDirection, file_path: Option<&Path>) {
        let current_buffer_id = self.active_buffer_id();
        let current_window_id = self.active_window_id();

        // Determine which buffer the new window should show
        let new_buffer_id = if let Some(path) = file_path {
            match self.buffer_manager.open_file(path) {
                Ok(id) => id,
                Err(e) => {
                    self.message = format!("Error: {}", e);
                    return;
                }
            }
        } else {
            // Same buffer as current window
            current_buffer_id
        };

        // Create new window
        let new_window_id = self.new_window_id();
        let mut new_window = Window::new(new_window_id, new_buffer_id);

        // Copy view state if same buffer
        if new_buffer_id == current_buffer_id {
            new_window.view = self.active_window().view.clone();
        }

        self.windows.insert(new_window_id, new_window);

        // Update layout
        let tab = self.active_tab_mut();
        tab.layout
            .split_at(current_window_id, direction, new_window_id, false);
        tab.active_window = new_window_id;

        if file_path.is_some() {
            self.message = String::new();
            self.lsp_did_open(new_buffer_id);
        }
    }

    /// Close the active window. Returns true if the window was closed.
    pub fn close_window(&mut self) -> bool {
        let is_single_tab = self.active_group().tabs.len() == 1;
        let is_single_window = self.active_tab().layout.is_single_window();

        // Can't close the last window in the last tab of the last group
        if is_single_window && is_single_tab && self.group_layout.is_single_group() {
            self.message = "Cannot close last window".to_string();
            return false;
        }

        let window_id = self.active_tab().active_window;

        // If this is the last window in the tab, close the tab
        if is_single_window {
            return self.close_tab();
        }

        // Remove window from layout
        let tab = self.active_tab_mut();
        if let Some(new_layout) = tab.layout.remove(window_id) {
            tab.layout = new_layout;
            // Set new active window
            if let Some(new_active) = tab.layout.window_ids().first().copied() {
                tab.active_window = new_active;
            }
        }

        // Remove window from windows map and any scroll-bind pairs that referenced it.
        self.windows.remove(&window_id);
        self.scroll_bind_pairs
            .retain(|&(a, b)| a != window_id && b != window_id);

        true
    }

    /// Close all windows except the active one in the current tab.
    pub fn close_other_windows(&mut self) {
        let active_window_id = self.active_window_id();
        let tab = self.active_tab_mut();

        // Get all window IDs except active
        let windows_to_close: Vec<WindowId> = tab
            .layout
            .window_ids()
            .into_iter()
            .filter(|&id| id != active_window_id)
            .collect();

        // Reset layout to single window
        tab.layout = WindowLayout::leaf(active_window_id);

        // Remove closed windows and any scroll-bind pairs referencing them.
        for id in windows_to_close {
            self.windows.remove(&id);
            self.scroll_bind_pairs.retain(|&(a, b)| a != id && b != id);
        }

        self.message = String::new();
    }

    /// Move focus to the next window in the current tab.
    pub fn focus_next_window(&mut self) {
        self.active_tab_mut().cycle_next_window();
    }

    /// Move focus to the previous window in the current tab.
    pub fn focus_prev_window(&mut self) {
        self.active_tab_mut().cycle_prev_window();
    }

    /// Move focus to a window in the given direction.
    pub fn focus_window_direction(&mut self, _direction: SplitDirection, forward: bool) {
        // For now, just cycle - proper directional navigation requires geometry
        if forward {
            self.focus_next_window();
        } else {
            self.focus_prev_window();
        }
    }

    /// Switch `active_group` to whichever group owns `window_id`.
    fn focus_group_for_window(&mut self, window_id: WindowId) {
        for (&gid, group) in &self.editor_groups {
            for (ti, tab) in group.tabs.iter().enumerate() {
                if tab.window_ids().contains(&window_id) {
                    self.active_group = gid;
                    if let Some(g) = self.editor_groups.get_mut(&gid) {
                        g.active_tab = ti;
                    }
                    return;
                }
            }
        }
    }

    /// Set cursor position for a specific window and make it active.
    /// Clamps line and col to valid buffer positions.
    pub fn set_cursor_for_window(&mut self, window_id: WindowId, line: usize, col: usize) {
        // Make the window active
        if self.windows.contains_key(&window_id) {
            self.active_tab_mut().active_window = window_id;

            // Get buffer and clamp line
            let buffer = self.buffer();
            let max_line = buffer.content.len_lines().saturating_sub(1);
            let clamped_line = line.min(max_line);

            // Get max col for this line (excludes newline)
            let max_col = self.get_max_cursor_col(clamped_line);
            let clamped_col = col.min(max_col);

            // Set cursor position
            let view = self.view_mut();
            view.cursor.line = clamped_line;
            view.cursor.col = clamped_col;
        }
    }

    // =======================================================================
    // Tab operations
    // =======================================================================

    /// Create a new tab with an optional file.
    pub fn new_tab(&mut self, file_path: Option<&Path>) {
        let buffer_id = if let Some(path) = file_path {
            match self.buffer_manager.open_file(path) {
                Ok(id) => id,
                Err(e) => {
                    self.message = format!("Error: {}", e);
                    return;
                }
            }
        } else {
            self.buffer_manager.create()
        };

        let window_id = self.new_window_id();
        let window = Window::new(window_id, buffer_id);
        self.windows.insert(window_id, window);

        let tab_id = self.new_tab_id();
        let tab = Tab::new(tab_id, window_id);
        self.active_group_mut().tabs.push(tab);
        self.active_group_mut().active_tab = self.active_group().tabs.len() - 1;

        if file_path.is_some() {
            self.message = String::new();
            self.lsp_did_open(buffer_id);
            self.swap_check_on_open(buffer_id);
        }
    }

    /// Close the current tab. Returns true if closed.
    pub fn close_tab(&mut self) -> bool {
        if self.active_group().tabs.len() <= 1 {
            // If there is a second group, close this group instead of erroring.
            if !self.group_layout.is_single_group() {
                self.close_editor_group();
                return true;
            }
            self.message = "Cannot close last tab".to_string();
            return false;
        }

        // Collect the buffer IDs of windows being closed so we can clean them
        // up from the buffer manager if nothing else references them.
        let active_tab_idx = self.active_group().active_tab;
        let window_ids: Vec<WindowId> = self.active_group().tabs[active_tab_idx].window_ids();
        let closed_buffer_ids: Vec<BufferId> = window_ids
            .iter()
            .filter_map(|wid| self.windows.get(wid).map(|w| w.buffer_id))
            .collect();

        // Remove all windows in this tab
        for window_id in &window_ids {
            self.windows.remove(window_id);
        }

        self.active_group_mut().tabs.remove(active_tab_idx);

        // Adjust active tab index
        let tabs_len = self.active_group().tabs.len();
        if self.active_group().active_tab >= tabs_len {
            self.active_group_mut().active_tab = tabs_len - 1;
        }

        // Remove any buffers that are no longer referenced by any window.
        // This prevents orphaned dirty buffers from falsely triggering `:qa`
        // unsaved-changes prompts after the user discards a tab.
        let still_referenced: std::collections::HashSet<BufferId> =
            self.windows.values().map(|w| w.buffer_id).collect();
        for buf_id in closed_buffer_ids {
            if !still_referenced.contains(&buf_id) {
                // Delete swap file before removing the buffer.
                self.swap_delete_for_buffer(buf_id);
                self.swap_write_needed.remove(&buf_id);
                let _ = self.buffer_manager.delete(buf_id, true /* force */);
                // Clean up markdown preview link.
                self.md_preview_links.remove(&buf_id);
            }
        }

        true
    }

    /// Switch to the next tab.
    pub fn next_tab(&mut self) {
        let tabs_len = self.active_group().tabs.len();
        if !self.active_group().tabs.is_empty() {
            self.active_group_mut().active_tab = (self.active_group().active_tab + 1) % tabs_len;
            self.line_annotations.clear();
        }
    }

    /// Switch to the previous tab.
    pub fn prev_tab(&mut self) {
        if !self.active_group().tabs.is_empty() {
            let at = self.active_group().active_tab;
            let tabs_len = self.active_group().tabs.len();
            self.active_group_mut().active_tab = if at == 0 { tabs_len - 1 } else { at - 1 };
            self.line_annotations.clear();
        }
    }

    /// Switch to a specific tab (0-indexed).
    #[allow(dead_code)]
    pub fn goto_tab(&mut self, index: usize) {
        if index < self.active_group().tabs.len() {
            self.active_group_mut().active_tab = index;
            self.line_annotations.clear();
        }
    }

    // =======================================================================
    // Editor group management (VSCode-style split panes)
    // =======================================================================

    /// Split the active editor group in the given direction.
    /// The new group opens a view of the current buffer.
    pub fn open_editor_group(&mut self, direction: SplitDirection) {
        let buf_id = self.active_buffer_id();
        let new_window_id = self.new_window_id();
        let mut new_window = Window::new(new_window_id, buf_id);
        // Copy view state for visual continuity.
        if let Some(src) = self.windows.get(&self.active_window_id()) {
            new_window.view = src.view.clone();
        }
        self.windows.insert(new_window_id, new_window);
        let tab_id = self.new_tab_id();
        let tab = Tab::new(tab_id, new_window_id);
        let new_id = self.new_group_id();
        self.editor_groups.insert(new_id, EditorGroup::new(tab));
        self.group_layout
            .split_at(self.active_group, direction, new_id, false);
        self.active_group = new_id;
        self.message = "Editor split".to_string();
    }

    /// Close the currently focused editor group.
    /// All windows in the closing group are removed; sibling is promoted.
    pub fn close_editor_group(&mut self) {
        if self.group_layout.is_single_group() {
            return;
        }
        let closing = self.active_group;
        // Collect window IDs before modifying groups
        if let Some(group) = self.editor_groups.get(&closing) {
            let window_ids: Vec<WindowId> =
                group.tabs.iter().flat_map(|t| t.window_ids()).collect();
            for wid in window_ids {
                self.windows.remove(&wid);
            }
        }
        self.editor_groups.remove(&closing);
        self.group_layout.remove(closing);
        self.active_group = self.group_layout.group_ids()[0];
    }

    /// Move focus to the next editor group (wraps around).
    pub fn focus_other_group(&mut self) {
        if let Some(next) = self.group_layout.next_group(self.active_group) {
            self.active_group = next;
        }
    }

    /// Move the current tab from the active group to the next group.
    pub fn move_tab_to_other_group(&mut self) {
        if self.group_layout.is_single_group() {
            return;
        }
        if self.active_group().tabs.len() <= 1 {
            self.message = "Cannot move last tab out of group".to_string();
            return;
        }
        let idx = self.active_group().active_tab;
        let tab = self.active_group_mut().tabs.remove(idx);
        // Adjust active tab if needed
        let tabs_len = self.active_group().tabs.len();
        if self.active_group().active_tab >= tabs_len && tabs_len > 0 {
            self.active_group_mut().active_tab = tabs_len - 1;
        }
        let other = self
            .group_layout
            .next_group(self.active_group)
            .unwrap_or(self.active_group);
        if let Some(other_group) = self.editor_groups.get_mut(&other) {
            other_group.tabs.push(tab);
            other_group.active_tab = other_group.tabs.len() - 1;
        }
        self.active_group = other;
    }

    /// Adjust the group split ratio of the parent split containing the active group.
    /// Positive delta expands the active group (shrinks its sibling).
    pub fn group_resize(&mut self, delta: f64) {
        if let Some((split_index, _dir, is_first)) =
            self.group_layout.parent_split_of(self.active_group)
        {
            // If active group is first child, increase ratio expands it.
            // If second child, decrease ratio expands it.
            let adjusted = if is_first { delta } else { -delta };
            self.group_layout
                .adjust_ratio_at_index(split_index, adjusted);
        }
    }

    /// Compute window rectangles for all editor groups, and return group dividers.
    ///
    /// `content_bounds` is the full editor content area (excluding status/command bars).
    /// `tab_bar_height` is subtracted from each group's usable height for the window area.
    pub fn calculate_group_window_rects(
        &self,
        content_bounds: WindowRect,
        tab_bar_height: f64,
    ) -> (Vec<(WindowId, WindowRect)>, Vec<GroupDivider>) {
        let group_rects = self
            .group_layout
            .calculate_group_rects(content_bounds, tab_bar_height);
        let mut all_rects: Vec<(WindowId, WindowRect)> = Vec::new();
        for (gid, rect) in &group_rects {
            if let Some(group) = self.editor_groups.get(gid) {
                all_rects.extend(group.active_tab().layout.calculate_rects(*rect));
            }
        }
        let dividers = self.group_layout.dividers(content_bounds, &mut 0);
        (all_rects, dividers)
    }

    /// Open a file from the explorer: switch to an existing tab that shows it,
    /// or create a new tab when no tab currently displays it.
    ///
    /// This is the correct handler for sidebar file clicks — it never replaces
    /// the current tab's contents.
    pub fn open_file_in_tab(&mut self, path: &Path) {
        // Clear per-buffer virtual text annotations when switching files.
        self.line_annotations.clear();
        let buffer_id = match self.buffer_manager.open_file(path) {
            Ok(id) => id,
            Err(e) => {
                self.message = format!("Error: {}", e);
                return;
            }
        };

        // If this buffer is the current preview, just promote it in-place.
        if self.preview_buffer_id == Some(buffer_id) {
            self.promote_preview(buffer_id);
            self.refresh_git_diff(buffer_id);
            self.message = format!("\"{}\"", path.display());
            self.lsp_did_open(buffer_id);
            return;
        }

        // Switch to any existing tab whose active window already shows this buffer.
        let found = self
            .active_group()
            .tabs
            .iter()
            .enumerate()
            .find(|(_, tab)| {
                self.windows
                    .get(&tab.active_window)
                    .is_some_and(|w| w.buffer_id == buffer_id)
            })
            .map(|(idx, _)| idx);
        if let Some(tab_idx) = found {
            self.active_group_mut().active_tab = tab_idx;
            self.refresh_git_diff(buffer_id);
            self.message = format!("\"{}\"", path.display());
            self.lsp_did_open(buffer_id);
            return;
        }

        // No existing tab shows this file — open it in a new tab.
        let window_id = self.new_window_id();
        let window = Window::new(window_id, buffer_id);
        self.windows.insert(window_id, window);

        let tab_id = self.new_tab_id();
        let tab = Tab::new(tab_id, window_id);
        self.active_group_mut().tabs.push(tab);
        self.active_group_mut().active_tab = self.active_group().tabs.len() - 1;

        // Restore saved cursor/scroll position.
        let view = self.restore_file_position(buffer_id);
        if let Some(w) = self.windows.get_mut(&window_id) {
            w.view = view;
        }

        self.refresh_git_diff(buffer_id);
        // Don't overwrite a pending swap recovery message.
        if self.swap_recovery.is_none() {
            self.message = format!("\"{}\"", path.display());
        }
        self.lsp_did_open(buffer_id);

        // Swap file check: detect stale swaps and offer recovery.
        self.swap_check_on_open(buffer_id);
    }

    /// Open a file from the sidebar via single-click (preview mode).
    ///
    /// Behaviour mirrors VSCode:
    /// - If the file is already shown in any tab, just switch to that tab.
    /// - If there is an existing preview tab, replace it with this file.
    /// - Otherwise open a new preview tab.
    ///
    /// A preview buffer is marked italic/dimmed and is replaced by the next
    /// single-click. Double-clicking (or editing/saving) promotes it to
    /// permanent.
    pub fn open_file_preview(&mut self, path: &Path) {
        let buffer_id = match self.buffer_manager.open_file(path) {
            Ok(id) => id,
            Err(e) => {
                self.message = format!("Error: {}", e);
                return;
            }
        };

        // Already shown in any tab? Just switch to it (permanent or current preview).
        let found = self
            .active_group()
            .tabs
            .iter()
            .enumerate()
            .find(|(_, tab)| {
                self.windows
                    .get(&tab.active_window)
                    .is_some_and(|w| w.buffer_id == buffer_id)
            })
            .map(|(idx, _)| idx);
        if let Some(tab_idx) = found {
            self.active_group_mut().active_tab = tab_idx;
            self.refresh_git_diff(buffer_id);
            self.message = format!("\"{}\"", path.display());
            self.lsp_did_open(buffer_id);
            return;
        }

        // Find the existing preview tab, if any (within the active group).
        let mut preview_slot: Option<(usize, WindowId, BufferId)> = None;
        if let Some(preview_buf_id) = self.preview_buffer_id {
            for (idx, tab) in self.active_group().tabs.iter().enumerate() {
                let win_id = tab.active_window;
                if self
                    .windows
                    .get(&win_id)
                    .is_some_and(|w| w.buffer_id == preview_buf_id)
                {
                    preview_slot = Some((idx, win_id, preview_buf_id));
                    break;
                }
            }
        }

        if let Some((tab_idx, win_id, old_buf_id)) = preview_slot {
            // Reuse the existing preview tab: close old preview buffer and
            // point the window at the new one.
            let _ = self.delete_buffer(old_buf_id, true);
            if let Some(w) = self.windows.get_mut(&win_id) {
                w.buffer_id = buffer_id;
            }
            if let Some(state) = self.buffer_manager.get_mut(buffer_id) {
                state.preview = true;
            }
            self.preview_buffer_id = Some(buffer_id);
            self.active_group_mut().active_tab = tab_idx;
            let view = self.restore_file_position(buffer_id);
            if let Some(w) = self.windows.get_mut(&win_id) {
                w.view = view;
            }
        } else {
            // No preview tab yet — open a new one.
            let window_id = self.new_window_id();
            let window = Window::new(window_id, buffer_id);
            self.windows.insert(window_id, window);
            let tab_id = self.new_tab_id();
            let tab = Tab::new(tab_id, window_id);
            self.active_group_mut().tabs.push(tab);
            self.active_group_mut().active_tab = self.active_group().tabs.len() - 1;
            if let Some(state) = self.buffer_manager.get_mut(buffer_id) {
                state.preview = true;
            }
            self.preview_buffer_id = Some(buffer_id);
            let view = self.restore_file_position(buffer_id);
            if let Some(w) = self.windows.get_mut(&window_id) {
                w.view = view;
            }
        }

        self.refresh_git_diff(buffer_id);
        self.message = format!("\"{}\"", path.display());
        self.lsp_did_open(buffer_id);
    }

    // =======================================================================
    // Buffer navigation
    // =======================================================================

    /// Switch the current window to the next buffer.
    pub fn next_buffer(&mut self) {
        let current = self.active_buffer_id();
        if let Some(next) = self.buffer_manager.next_buffer(current) {
            self.buffer_manager.alternate_buffer = Some(current);
            self.switch_window_buffer(next);
        }
    }

    /// Switch the current window to the previous buffer.
    pub fn prev_buffer(&mut self) {
        let current = self.active_buffer_id();
        if let Some(prev) = self.buffer_manager.prev_buffer(current) {
            self.buffer_manager.alternate_buffer = Some(current);
            self.switch_window_buffer(prev);
        }
    }

    /// Switch the current window to the alternate buffer.
    pub fn alternate_buffer(&mut self) {
        if let Some(alt) = self.buffer_manager.alternate_buffer {
            let current = self.active_buffer_id();
            self.buffer_manager.alternate_buffer = Some(current);
            self.switch_window_buffer(alt);
        } else {
            self.message = "No alternate buffer".to_string();
        }
    }

    /// Switch the current window to a buffer by number (1-indexed).
    pub fn goto_buffer(&mut self, num: usize) {
        if let Some(id) = self.buffer_manager.get_by_number(num) {
            let current = self.active_buffer_id();
            if id != current {
                self.buffer_manager.alternate_buffer = Some(current);
                self.switch_window_buffer(id);
            }
        } else {
            self.message = format!("Buffer {} does not exist", num);
        }
    }

    /// Switch the current window to a different buffer.
    fn switch_window_buffer(&mut self, buffer_id: BufferId) {
        if self.buffer_manager.get(buffer_id).is_none() {
            return;
        }

        // Save current buffer's cursor/scroll position before switching
        let current_id = self.active_window().buffer_id;
        if current_id != buffer_id {
            if let Some(path) = self
                .buffer_manager
                .get(current_id)
                .and_then(|s| s.file_path.as_deref())
                .map(|p| p.to_path_buf())
            {
                let view = &self.active_window().view;
                self.session.save_file_position(
                    &path,
                    view.cursor.line,
                    view.cursor.col,
                    view.scroll_top,
                );
            }
        }

        // Switch to the new buffer
        self.active_window_mut().buffer_id = buffer_id;

        // Restore saved position, clamped to actual buffer bounds
        let new_view = self.restore_file_position(buffer_id);
        self.active_window_mut().view = new_view;

        self.search_matches.clear();
        self.search_index = None;
    }

    /// Build a View restoring the saved position for a buffer, or return View::new().
    fn restore_file_position(&self, buffer_id: BufferId) -> View {
        let path = match self
            .buffer_manager
            .get(buffer_id)
            .and_then(|s| s.file_path.as_deref())
            .map(|p| p.to_path_buf())
        {
            Some(p) => p,
            None => return View::new(),
        };

        let pos = match self.session.get_file_position(&path) {
            Some(p) => p,
            None => return View::new(),
        };

        let buf = self.buffer_manager.get(buffer_id).unwrap();
        let max_line = buf.buffer.len_lines().saturating_sub(1);
        let line = pos.line.min(max_line);
        let line_len = buf.buffer.line_len_chars(line);
        let max_col = line_len.saturating_sub(1);
        let col = pos.col.min(max_col);
        let scroll_top = pos.scroll_top.min(max_line);

        View {
            cursor: Cursor { line, col },
            scroll_top,
            ..View::new()
        }
    }

    /// Return the absolute paths of buffers currently shown in at least one window.
    /// Orphaned buffers (closed via :q but not yet freed) are intentionally excluded so
    /// that files the user explicitly closed are not restored on the next startup.
    pub fn open_file_paths(&self) -> Vec<std::path::PathBuf> {
        let in_window: std::collections::HashSet<BufferId> =
            self.windows.values().map(|w| w.buffer_id).collect();
        self.buffer_manager
            .list()
            .into_iter()
            .filter(|id| in_window.contains(id))
            .filter_map(|id| {
                self.buffer_manager
                    .get(id)
                    .and_then(|s| s.file_path.clone())
            })
            .collect()
    }

    /// Snapshot the current open-file list and active file into session state, ready for saving.
    pub fn collect_session_open_files(&mut self) {
        self.session.open_files = self.open_file_paths();
        self.session.active_file = self
            .buffer_manager
            .get(self.active_buffer_id())
            .and_then(|s| s.file_path.clone());
    }

    /// Restore open files from session state (called at startup when no CLI file is given).
    /// Each file gets its own tab; the previously-active file's tab is focused.
    /// Skips files that no longer exist. Removes the initial empty scratch buffer.
    pub fn restore_session_files(&mut self) {
        // Prefer per-workspace session if one exists for cwd
        let ws_session = SessionState::load_for_workspace(&self.cwd.clone());

        // Merge workspace file positions into current session.
        if !ws_session.open_files.is_empty() || ws_session.group_layout.is_some() {
            for (k, v) in ws_session.file_positions.clone() {
                self.session.file_positions.entry(k).or_insert(v);
            }
        }

        // New tree format takes priority if present.
        if let Some(ref tree_layout) = ws_session.group_layout {
            self.restore_session_from_tree(tree_layout, &ws_session.active_file);
            return;
        }

        // Fall back to old flat-field format.
        let paths_g1 = if !ws_session.open_files.is_empty() {
            ws_session.open_files_group1.clone()
        } else {
            vec![]
        };
        let saved_active_group = if !ws_session.open_files.is_empty() {
            ws_session.active_group
        } else {
            0
        };
        let saved_split_dir = if !ws_session.open_files.is_empty() {
            ws_session.group_split_direction
        } else {
            0u8
        };
        let saved_split_ratio = if !ws_session.open_files.is_empty() {
            ws_session.group_split_ratio
        } else {
            0.5
        };
        let (paths, active) = if !ws_session.open_files.is_empty() {
            (ws_session.open_files, ws_session.active_file)
        } else {
            // No workspace session for this directory — start with empty editor.
            // Do NOT fall back to the global session's open_files: that would
            // bleed files from a different workspace into the current one.
            (vec![], None)
        };

        if paths.is_empty() {
            return;
        }

        let initial_id = self.active_buffer_id();
        let mut any_opened = false;
        let mut first = true;

        for path in &paths {
            if !path.exists() {
                continue;
            }
            if first {
                // Reuse the initial window for the first file.
                if self.open_file_with_mode(path, OpenMode::Permanent).is_ok() {
                    any_opened = true;
                    first = false;
                }
            } else {
                // Each subsequent file gets its own tab.
                self.new_tab(Some(path));
                let buf_id = self.active_buffer_id();
                let view = self.restore_file_position(buf_id);
                let win_id = self.active_tab().active_window;
                if let Some(window) = self.windows.get_mut(&win_id) {
                    window.view = view;
                }
                any_opened = true;
            }
        }

        if !any_opened {
            return;
        }

        // Remove the initial empty scratch buffer now that real files are open.
        let _ = self.delete_buffer(initial_id, true);

        // Switch focus to the tab showing the previously-active file.
        if let Some(ref ap) = active {
            if let Ok(canonical_ap) = ap.canonicalize() {
                let tab_idx = self.active_group().tabs.iter().position(|t| {
                    self.windows
                        .get(&t.active_window)
                        .and_then(|w| self.buffer_manager.get(w.buffer_id))
                        .and_then(|s| s.file_path.as_ref())
                        .and_then(|p| p.canonicalize().ok())
                        .is_some_and(|p| p == canonical_ap)
                });
                if let Some(idx) = tab_idx {
                    self.active_group_mut().active_tab = idx;
                }
            }
        }

        // Restore editor group 1 if it was open (old flat-field format).
        let valid_g1: Vec<PathBuf> = paths_g1.into_iter().filter(|p| p.exists()).collect();
        if !valid_g1.is_empty() {
            let direction = if saved_split_dir == 1 {
                SplitDirection::Horizontal
            } else {
                SplitDirection::Vertical
            };
            self.open_editor_group(direction);
            // Set saved ratio on the root split (split_index 0).
            self.group_layout.set_ratio_at_index(0, saved_split_ratio);
            // open_editor_group switches to new group — open files there
            let mut first_g1 = true;
            for path in &valid_g1 {
                if first_g1 {
                    let _ = self.open_file_with_mode(path, OpenMode::Permanent);
                    first_g1 = false;
                } else {
                    self.new_tab(Some(path));
                }
            }
            // Restore active group: clamp to valid range
            let ids = self.group_layout.group_ids();
            if saved_active_group < ids.len() {
                self.active_group = ids[saved_active_group];
            }
        }

        // Check all restored buffers for stale swap files.
        self.swap_check_all_buffers();
    }

    /// Restore session from the recursive tree format.
    fn restore_session_from_tree(
        &mut self,
        tree_layout: &SessionGroupLayout,
        active_file: &Option<PathBuf>,
    ) {
        let initial_id = self.active_buffer_id();
        let initial_group = self.active_group;

        // Reconstruct the full group layout tree, creating groups/windows/buffers.
        let new_layout = self.restore_session_group_layout(tree_layout);

        // Remove the initial scratch group and its buffer.
        self.editor_groups.remove(&initial_group);
        let _ = self.delete_buffer(initial_id, true);

        // Install the new layout.
        self.group_layout = new_layout;
        let ids = self.group_layout.group_ids();
        self.active_group = ids.first().copied().unwrap_or(GroupId(0));

        // Focus the group+tab containing the previously-active file.
        if let Some(ref ap) = active_file {
            if let Ok(canonical_ap) = ap.canonicalize() {
                'outer: for &gid in &ids {
                    if let Some(group) = self.editor_groups.get(&gid) {
                        for (ti, tab) in group.tabs.iter().enumerate() {
                            let matches = self
                                .windows
                                .get(&tab.active_window)
                                .and_then(|w| self.buffer_manager.get(w.buffer_id))
                                .and_then(|s| s.file_path.as_ref())
                                .and_then(|p| p.canonicalize().ok())
                                .is_some_and(|p| p == canonical_ap);
                            if matches {
                                self.active_group = gid;
                                if let Some(g) = self.editor_groups.get_mut(&gid) {
                                    g.active_tab = ti;
                                }
                                break 'outer;
                            }
                        }
                    }
                }
            }
        }

        // Notify LSP for all restored buffers (tree restore bypasses open_file_with_mode).
        let restored_bids: Vec<BufferId> = self.buffer_manager.list();
        for bid in restored_bids {
            let has_file = self
                .buffer_manager
                .get(bid)
                .and_then(|s| s.file_path.as_ref())
                .is_some();
            if has_file {
                self.lsp_did_open(bid);
            }
        }

        // Check all restored buffers for stale swap files.
        self.swap_check_all_buffers();
    }

    /// Delete a buffer. Returns error if buffer is shown in any window or is dirty.
    pub fn delete_buffer(&mut self, id: BufferId, force: bool) -> Result<(), String> {
        // Check if buffer is shown in any window
        let in_use: Vec<WindowId> = self
            .windows
            .iter()
            .filter(|(_, w)| w.buffer_id == id)
            .map(|(wid, _)| *wid)
            .collect();

        if !in_use.is_empty() && self.buffer_manager.len() > 1 {
            // Switch those windows to another buffer
            let alt = self
                .buffer_manager
                .list()
                .into_iter()
                .find(|&bid| bid != id);

            if let Some(alt_id) = alt {
                for wid in in_use {
                    if let Some(window) = self.windows.get_mut(&wid) {
                        window.buffer_id = alt_id;
                        window.view = View::new();
                    }
                }
            }
        }

        // Clear preview tracking if deleting the preview buffer
        if self.preview_buffer_id == Some(id) {
            self.preview_buffer_id = None;
        }

        self.lsp_did_close(id);
        self.buffer_manager.delete(id, force)
    }

    /// Get the list of buffers for :ls display.
    pub fn list_buffers(&self) -> String {
        let active = self.active_buffer_id();
        let alternate = self.buffer_manager.alternate_buffer;

        let mut lines = Vec::new();
        for (i, id) in self.buffer_manager.list().iter().enumerate() {
            let state = self.buffer_manager.get(*id).unwrap();
            let num = i + 1;
            let active_flag = if *id == active { "%a" } else { "  " };
            let alt_flag = if Some(*id) == alternate { "#" } else { " " };
            let dirty_flag = if state.dirty { "+" } else { " " };
            let name = state.display_name();
            let preview_flag = if state.preview { " [Preview]" } else { "" };
            lines.push(format!(
                "{:3} {}{}{} \"{}\"{}",
                num, active_flag, alt_flag, dirty_flag, name, preview_flag
            ));
        }
        lines.join("\n")
    }

    // =======================================================================
    // Cursor helpers (delegating to buffer/view)
    // =======================================================================

    fn get_max_cursor_col(&self, line_idx: usize) -> usize {
        let buffer = self.buffer();
        let len = buffer.line_len_chars(line_idx);
        if len == 0 {
            return 0;
        }

        let line = buffer.content.line(line_idx);
        let ends_with_newline = line.chars().last() == Some('\n');

        if ends_with_newline {
            if len > 1 {
                len - 2
            } else {
                0
            }
        } else {
            len.saturating_sub(1)
        }
    }

    pub fn clamp_cursor_col(&mut self) {
        let line = self.view().cursor.line;
        let max_col = self.get_max_cursor_col(line);
        let view = self.view_mut();
        if view.cursor.col > max_col {
            view.cursor.col = max_col;
        }
    }

    /// Ensure the cursor is visible within the viewport, adjusting scroll_top.
    pub fn ensure_cursor_visible(&mut self) {
        if self.settings.wrap && self.view().viewport_cols > 0 {
            self.ensure_cursor_visible_wrap();
        } else {
            let scrolloff = self.settings.scrolloff;
            if scrolloff == 0 {
                self.view_mut().ensure_cursor_visible();
            } else {
                let cursor_line = self.view().cursor.line;
                let viewport_lines = self.view().viewport_lines;
                let scroll_top = self.view().scroll_top;
                if cursor_line < scroll_top + scrolloff {
                    self.view_mut().scroll_top = cursor_line.saturating_sub(scrolloff);
                } else if viewport_lines > 0
                    && cursor_line + scrolloff + 1 > scroll_top + viewport_lines
                {
                    self.view_mut().scroll_top = cursor_line + scrolloff + 1 - viewport_lines;
                }
            }
        }
    }

    /// Wrap-aware scroll-to-cursor. Counts visual rows (accounting for
    /// soft-wrapped buffer lines) to determine when to adjust `scroll_top`.
    fn ensure_cursor_visible_wrap(&mut self) {
        let viewport_cols = self.view().viewport_cols;
        let viewport_lines = self.view().viewport_lines;
        let cursor_line = self.view().cursor.line;
        let cursor_col = self.view().cursor.col;
        let scroll_top = self.view().scroll_top;
        let total_lines = self.buffer().len_lines();

        // Scroll up if cursor is above the viewport.
        if cursor_line < scroll_top {
            self.view_mut().scroll_top = cursor_line;
            return;
        }

        if viewport_lines == 0 {
            return;
        }

        // Count visual rows from scroll_top up to and including the cursor's
        // visual row within cursor_line.
        let mut visual_rows: usize = 0;
        for r in scroll_top..=cursor_line {
            let line_len = self.buffer().content.line(r).len_chars().saturating_sub(1);
            if r < cursor_line {
                visual_rows += engine_visual_rows_for_line(line_len, viewport_cols);
            } else {
                // Partial count: only up to the cursor's visual segment.
                visual_rows += cursor_col / viewport_cols + 1;
            }
        }

        // If cursor fits within the viewport, nothing to adjust.
        if visual_rows <= viewport_lines {
            return;
        }

        // Cursor is below the viewport — walk backwards from cursor_line
        // to find the new scroll_top that makes the cursor visible.
        let cursor_visual_row_within_line = cursor_col / viewport_cols;
        // Rows the cursor's line contributes, up to and including cursor segment.
        let mut rows_used = cursor_visual_row_within_line + 1;
        let mut new_scroll_top = cursor_line;
        if rows_used < viewport_lines && cursor_line > 0 {
            for r in (0..cursor_line).rev() {
                let line_len = self.buffer().content.line(r).len_chars().saturating_sub(1);
                let vrows = engine_visual_rows_for_line(line_len, viewport_cols);
                if rows_used + vrows > viewport_lines {
                    break;
                }
                rows_used += vrows;
                new_scroll_top = r;
            }
        }
        // Clamp scroll_top to valid range.
        new_scroll_top = new_scroll_top.min(total_lines.saturating_sub(1));
        self.view_mut().scroll_top = new_scroll_top;
    }

    /// Move cursor down by one visual row (within the same wrapped line if
    /// possible, otherwise to the next buffer line).  Used by `gj`.
    fn move_visual_down(&mut self) {
        let vp = self.view().viewport_cols.max(1);
        let cursor_line = self.view().cursor.line;
        let cursor_col = self.view().cursor.col;
        let total_lines = self.buffer().len_lines();
        let line_len = self
            .buffer()
            .content
            .line(cursor_line)
            .len_chars()
            .saturating_sub(1);
        let visual_col = cursor_col % vp;

        if cursor_col + vp < line_len {
            // Advance within the same buffer line (to the next wrapped segment).
            self.view_mut().cursor.col = cursor_col + vp;
        } else if cursor_line + 1 < total_lines {
            // Move to the next buffer line, keeping the same visual column offset.
            let next_len = self
                .buffer()
                .content
                .line(cursor_line + 1)
                .len_chars()
                .saturating_sub(1);
            self.view_mut().cursor.line = cursor_line + 1;
            self.view_mut().cursor.col = visual_col.min(next_len.saturating_sub(1));
        }
        self.clamp_cursor_col();
        self.ensure_cursor_visible();
    }

    /// Move cursor up by one visual row (within the same wrapped line if
    /// possible, otherwise to the previous buffer line).  Used by `gk`.
    fn move_visual_up(&mut self) {
        let vp = self.view().viewport_cols.max(1);
        let cursor_line = self.view().cursor.line;
        let cursor_col = self.view().cursor.col;
        let visual_col = cursor_col % vp;

        if cursor_col >= vp {
            // Move up within the same buffer line (to the previous wrapped segment).
            self.view_mut().cursor.col = cursor_col - vp;
        } else if cursor_line > 0 {
            // Move to the previous buffer line's last visual segment.
            let prev_len = self
                .buffer()
                .content
                .line(cursor_line - 1)
                .len_chars()
                .saturating_sub(1);
            let last_seg_start = (prev_len / vp) * vp;
            let target_col = (last_seg_start + visual_col).min(prev_len.saturating_sub(1));
            self.view_mut().cursor.line = cursor_line - 1;
            self.view_mut().cursor.col = target_col;
        }
        self.clamp_cursor_col();
        self.ensure_cursor_visible();
    }

    /// Synchronise the scroll_top of scroll-bound window pairs.
    /// Called after every key that may move the cursor or scroll, and also
    /// after direct scroll_top mutations (e.g. scrollbar drag).
    pub fn sync_scroll_binds(&mut self) {
        if self.scroll_bind_pairs.is_empty() {
            return;
        }
        let active_id = self.active_window_id();
        let active_win = &self.windows[&active_id];
        let active_scroll = active_win.view.scroll_top;
        let active_buf_id = active_win.buffer_id;
        let active_lines = self
            .buffer_manager
            .get(active_buf_id)
            .map(|s| s.buffer.len_lines())
            .unwrap_or(1)
            .max(1);

        let pairs = self.scroll_bind_pairs.clone();
        for (a, b) in pairs {
            let partner = if a == active_id {
                Some(b)
            } else if b == active_id {
                Some(a)
            } else {
                None
            };
            if let Some(pid) = partner {
                let partner_buf_id = self.windows.get(&pid).map(|w| w.buffer_id);
                let is_md_pair = partner_buf_id.is_some_and(|pb| {
                    self.md_preview_links.contains_key(&pb)
                        || self.md_preview_links.contains_key(&active_buf_id)
                });
                if let Some(w) = self.windows.get_mut(&pid) {
                    if is_md_pair {
                        // Proportional scroll: map source position to preview position.
                        let partner_lines = partner_buf_id
                            .and_then(|id| self.buffer_manager.get(id))
                            .map(|s| s.buffer.len_lines())
                            .unwrap_or(1)
                            .max(1);
                        let ratio = active_scroll as f64 / active_lines as f64;
                        w.view.scroll_top = ((ratio * partner_lines as f64).round() as usize)
                            .min(partner_lines.saturating_sub(1));
                    } else {
                        w.view.scroll_top = active_scroll;
                    }
                }
            }
        }
    }

    // =======================================================================
    // Project search
    // =======================================================================

    /// Run a project-wide search synchronously (blocks until complete).
    ///
    /// Prefer `start_project_search` + `poll_project_search` for UI use.
    /// Used directly in tests.
    #[allow(dead_code)]
    pub fn run_project_search(&mut self, root: &Path) {
        let query = self.project_search_query.clone();
        if query.is_empty() {
            self.project_search_results.clear();
            self.project_search_selected = 0;
            self.message = "Search query is empty".to_string();
            return;
        }
        let opts = self.project_search_options.clone();
        match project_search::search_in_project(root, &query, &opts) {
            Ok(results) => self.apply_search_results(results, &query),
            Err(e) => {
                self.project_search_results.clear();
                self.project_search_selected = 0;
                self.message = format!("Invalid regex: {}", e.0);
            }
        }
    }

    /// Spawn a background thread to search `root` for `self.project_search_query`.
    ///
    /// Call `poll_project_search` on each UI tick to collect results.
    pub fn start_project_search(&mut self, root: PathBuf) {
        let query = self.project_search_query.clone();
        if query.is_empty() {
            self.project_search_results.clear();
            self.project_search_selected = 0;
            self.message = "Search query is empty".to_string();
            return;
        }
        self.project_search_running = true;
        self.message = format!("Searching for \"{}\"…", query);
        let opts = self.project_search_options.clone();
        let (tx, rx) = std::sync::mpsc::channel();
        self.project_search_receiver = Some(rx);
        std::thread::spawn(move || {
            let result = project_search::search_in_project(&root, &query, &opts);
            let _ = tx.send(result);
        });
    }

    /// Check whether the background search thread has finished and, if so, store results.
    ///
    /// Returns `true` when new results have just arrived (UI should redraw).
    pub fn poll_project_search(&mut self) -> bool {
        let result = match self.project_search_receiver {
            Some(ref rx) => match rx.try_recv() {
                Ok(r) => r,
                Err(_) => return false,
            },
            None => return false,
        };
        let query = self.project_search_query.clone();
        self.project_search_receiver = None;
        self.project_search_running = false;
        match result {
            Ok(results) => self.apply_search_results(results, &query),
            Err(e) => {
                self.project_search_results.clear();
                self.project_search_selected = 0;
                self.message = format!("Invalid regex: {}", e.0);
            }
        }
        true
    }

    /// Store search results and update the status message. Called by both sync and async paths.
    fn apply_search_results(&mut self, results: Vec<ProjectMatch>, query: &str) {
        let capped = results.len() >= 10_000;
        if results.is_empty() {
            self.message = format!("No results for \"{}\"", query);
        } else {
            let file_count = {
                let mut files: Vec<&std::path::Path> =
                    results.iter().map(|m| m.file.as_path()).collect();
                files.sort();
                files.dedup();
                files.len()
            };
            self.message = format!(
                "{} match{} in {} file{}{}",
                results.len(),
                if results.len() == 1 { "" } else { "es" },
                file_count,
                if file_count == 1 { "" } else { "s" },
                if capped { " (capped at 10000)" } else { "" }
            );
        }
        self.project_search_results = results;
        self.project_search_selected = 0;
    }

    /// Toggle case-sensitive project search.
    pub fn toggle_project_search_case(&mut self) {
        self.project_search_options.case_sensitive = !self.project_search_options.case_sensitive;
    }

    /// Toggle whole-word project search.
    pub fn toggle_project_search_whole_word(&mut self) {
        self.project_search_options.whole_word = !self.project_search_options.whole_word;
    }

    /// Toggle regex project search.
    pub fn toggle_project_search_regex(&mut self) {
        self.project_search_options.use_regex = !self.project_search_options.use_regex;
    }

    /// Move the project search selection down by one, clamped to the last result.
    pub fn project_search_select_next(&mut self) {
        if !self.project_search_results.is_empty() {
            self.project_search_selected =
                (self.project_search_selected + 1).min(self.project_search_results.len() - 1);
        }
    }

    /// Move the project search selection up by one, clamped to 0.
    pub fn project_search_select_prev(&mut self) {
        self.project_search_selected = self.project_search_selected.saturating_sub(1);
    }

    // =======================================================================
    // Project replace
    // =======================================================================

    /// Collect canonical paths of all dirty (unsaved) buffers.
    fn dirty_buffer_paths(&self) -> std::collections::HashSet<PathBuf> {
        let mut paths = std::collections::HashSet::new();
        for id in self.buffer_manager.list() {
            if let Some(state) = self.buffer_manager.get(id) {
                if state.dirty {
                    if let Some(ref p) = state.file_path {
                        let canonical = p.canonicalize().unwrap_or_else(|_| p.clone());
                        paths.insert(canonical);
                    }
                }
            }
        }
        paths
    }

    /// Run a project-wide replace synchronously (blocks until complete).
    /// Used directly in tests.
    #[allow(dead_code)]
    pub fn run_project_replace(&mut self, root: &Path) {
        let query = self.project_search_query.clone();
        let replacement = self.project_replace_text.clone();
        if query.is_empty() {
            self.message = "Search query is empty".to_string();
            return;
        }
        let opts = self.project_search_options.clone();
        let skip = self.dirty_buffer_paths();
        match project_search::replace_in_project(root, &query, &replacement, &opts, &skip) {
            Ok(rr) => self.apply_replace_result(rr),
            Err(e) => {
                self.message = format!("Invalid regex: {}", e.0);
            }
        }
    }

    /// Spawn a background thread to replace across `root`.
    ///
    /// Call `poll_project_replace` on each UI tick to collect results.
    pub fn start_project_replace(&mut self, root: PathBuf) {
        let query = self.project_search_query.clone();
        let replacement = self.project_replace_text.clone();
        if query.is_empty() {
            self.message = "Search query is empty".to_string();
            return;
        }
        self.project_replace_running = true;
        self.message = format!("Replacing \"{}\" → \"{}\"…", query, replacement);
        let opts = self.project_search_options.clone();
        let skip = self.dirty_buffer_paths();
        let (tx, rx) = std::sync::mpsc::channel();
        self.project_replace_receiver = Some(rx);
        std::thread::spawn(move || {
            let result =
                project_search::replace_in_project(&root, &query, &replacement, &opts, &skip);
            let _ = tx.send(result);
        });
    }

    /// Check whether the background replace thread has finished.
    ///
    /// Returns `true` when the replace has just completed (UI should redraw).
    pub fn poll_project_replace(&mut self) -> bool {
        let result = match self.project_replace_receiver {
            Some(ref rx) => match rx.try_recv() {
                Ok(r) => r,
                Err(_) => return false,
            },
            None => return false,
        };
        self.project_replace_receiver = None;
        self.project_replace_running = false;
        match result {
            Ok(rr) => self.apply_replace_result(rr),
            Err(e) => {
                self.message = format!("Replace error: {}", e.0);
            }
        }
        true
    }

    /// Apply a completed replace result: reload modified buffers, update status.
    fn apply_replace_result(&mut self, rr: ReplaceResult) {
        // Reload open buffers for modified files.
        for modified_path in &rr.modified_files {
            let canonical = modified_path
                .canonicalize()
                .unwrap_or_else(|_| modified_path.clone());
            // Find the buffer for this file and reload its content from disk.
            let buf_id = self.buffer_manager.list().into_iter().find(|&id| {
                self.buffer_manager.get(id).is_some_and(|s| {
                    s.file_path.as_ref().is_some_and(|p| {
                        p.canonicalize().unwrap_or_else(|_| p.clone()) == canonical
                    })
                })
            });
            if let Some(id) = buf_id {
                if let Ok(content) = std::fs::read_to_string(modified_path) {
                    if let Some(state) = self.buffer_manager.get_mut(id) {
                        state.buffer.content = ropey::Rope::from_str(&content);
                        state.dirty = false;
                        state.undo_stack.clear();
                        state.redo_stack.clear();
                    }
                    self.refresh_git_diff(id);
                }
            }
        }

        // Build status message.
        let mut msg = format!(
            "Replaced {} occurrence{} in {} file{}",
            rr.replacement_count,
            if rr.replacement_count == 1 { "" } else { "s" },
            rr.file_count,
            if rr.file_count == 1 { "" } else { "s" },
        );
        if !rr.skipped_files.is_empty() {
            msg.push_str(&format!(
                " ({} file{} skipped — unsaved changes)",
                rr.skipped_files.len(),
                if rr.skipped_files.len() == 1 { "" } else { "s" },
            ));
        }
        self.message = msg;

        // Clear stale search results since files have changed.
        self.project_search_results.clear();
        self.project_search_selected = 0;
    }

    // =======================================================================
    // Key handling
    // =======================================================================

    /// Process a key event and return an action the UI should perform.
    pub fn handle_key(
        &mut self,
        key_name: &str,
        unicode: Option<char>,
        ctrl: bool,
    ) -> EngineAction {
        // Clear message on any keypress (unless we're in command/search mode)
        if self.mode != Mode::Command && self.mode != Mode::Search {
            self.message.clear();
        }
        // Dismiss LSP hover popup on any keypress
        self.lsp_hover_text = None;

        // Record keystroke if macro recording is active
        // Skip recording the 'q' that stops recording
        if self.macro_recording.is_some() {
            let is_stop_q =
                self.mode == Mode::Normal && unicode == Some('q') && self.pending_key.is_none();

            if !is_stop_q {
                // Encode the keystroke for recording
                let encoded = self.encode_key_for_macro(key_name, unicode, ctrl);
                for ch in encoded.chars() {
                    self.recording_buffer.push(ch);
                }
            }
        }

        // Swap recovery dialog intercepts R/D/A keys.
        if self.swap_recovery.is_some() {
            return self.handle_swap_recovery_key(key_name);
        }

        // Command palette intercepts all keys when open.
        if self.palette_open {
            return self.handle_palette_key(key_name, unicode, ctrl);
        }

        // Fuzzy finder intercepts all keys when open.
        if self.fuzzy_open {
            return self.handle_fuzzy_key(key_name, unicode, ctrl);
        }

        // Live grep intercepts all keys when open.
        if self.grep_open {
            return self.handle_grep_key(key_name, unicode, ctrl);
        }

        // Quickfix panel intercepts all keys when it has focus.
        if self.quickfix_has_focus {
            return self.handle_quickfix_key(key_name, ctrl);
        }

        // Debug sidebar intercepts all keys when it has focus.
        if self.dap_sidebar_has_focus {
            return self.handle_debug_sidebar_key(key_name, ctrl);
        }

        // Source Control panel intercepts all keys when it has focus.
        if self.sc_has_focus {
            self.handle_sc_key(key_name, ctrl, unicode);
            return EngineAction::None;
        }

        // Ctrl-S: save in any mode (does not change mode).
        if ctrl && key_name == "s" {
            if let Err(e) = self.save_with_format(false) {
                self.message = format!("Save failed: {}", e);
            }
            return EngineAction::None;
        }

        // VSCode mode: all keys go through the vscode handler, which internally
        // delegates to handle_command_key() / handle_search_key() when those overlays
        // are open (e.g. after F1 opens the command bar).
        if self.is_vscode_mode() {
            return self.handle_vscode_key(key_name, unicode, ctrl);
        }

        let mut changed = false;
        let mut action = EngineAction::None;
        let was_normal = matches!(self.mode, Mode::Normal);

        // N-to-dismiss extension hint: intercept 'N' in Normal mode when a hint is visible.
        // Only active while the hint is still the current status message (cleared on any edit).
        if let Some(ref name) = self.ext_hint_pending_name.clone() {
            if !self.message.contains(name.as_str()) {
                // Message was overwritten — forget the pending name silently.
                self.ext_hint_pending_name = None;
            } else if key_name == "N"
                && !ctrl
                && matches!(self.mode, Mode::Normal)
                && self.pending_key.is_none()
                && self.pending_operator.is_none()
            {
                let name = self.ext_hint_pending_name.take().unwrap();
                self.extension_state.mark_dismissed(&name);
                let _ = self.extension_state.save();
                self.message =
                    format!("Extension '{name}' dismissed — :ExtEnable {name} to re-enable");
                return EngineAction::None;
            }
        }

        // Capture cursor position before dispatching (used by cursor_move hook below).
        let pre_cursor_line = self.cursor().line;
        let pre_cursor_col = self.cursor().col;

        match self.mode {
            Mode::Normal => {
                action = self.handle_normal_key(key_name, unicode, ctrl, &mut changed);
            }
            Mode::Insert => {
                self.handle_insert_key(key_name, unicode, ctrl, &mut changed);
            }
            Mode::Replace => {
                self.handle_replace_key(key_name, unicode, ctrl, &mut changed);
            }
            Mode::Command => {
                action = self.handle_command_key(key_name, unicode, ctrl);
            }
            Mode::Search => {
                self.handle_search_key(key_name, unicode, ctrl);
            }
            Mode::Visual | Mode::VisualLine | Mode::VisualBlock => {
                // Save pre-call visual state for 'gv' support
                let pre_mode = self.mode;
                let pre_anchor = self.visual_anchor;
                let pre_cursor = self.view().cursor;
                action = self.handle_visual_key(key_name, unicode, ctrl, &mut changed);
                // If we just left visual mode, record the selection for gv and '< / '>
                if !matches!(
                    self.mode,
                    Mode::Visual | Mode::VisualLine | Mode::VisualBlock
                ) {
                    self.last_visual_mode = pre_mode;
                    self.last_visual_anchor = pre_anchor;
                    self.last_visual_cursor = Some(pre_cursor);
                    // Save '< and '> marks (sorted)
                    if let Some(anchor) = pre_anchor {
                        let (start, end) =
                            if (anchor.line, anchor.col) <= (pre_cursor.line, pre_cursor.col) {
                                (anchor, pre_cursor)
                            } else {
                                (pre_cursor, anchor)
                            };
                        self.visual_mark_start = Some((start.line, start.col));
                        self.visual_mark_end = Some((end.line, end.col));
                    }
                }
            }
        }

        if changed {
            // Track last edit position for '. mark and change list
            let cur = self.view().cursor;
            self.last_edit_pos = Some((cur.line, cur.col));
            self.push_change_location(cur.line, cur.col);

            // A normal-mode buffer modification (paste, delete, replace…) invalidates
            // any extra-cursor positions — clear them so stale cursors don't appear.
            if was_normal && !self.view().extra_cursors.is_empty() {
                self.view_mut().extra_cursors.clear();
            }
            self.set_dirty(true);
            self.update_syntax();
            // Auto-promote preview buffer on text modification
            let active_id = self.active_buffer_id();
            if self.preview_buffer_id == Some(active_id) {
                self.promote_preview(active_id);
            }
            // Mark buffer as needing an LSP didChange (debounced)
            self.lsp_dirty_buffers.insert(active_id, true);
            // Live-refresh any linked markdown preview.
            self.refresh_md_previews();
            // Mark swap file as needing a write.
            self.swap_mark_dirty();
            // Refresh search highlights so they track the new buffer content.
            if !self.search_matches.is_empty() {
                self.run_search();
            }
        }

        self.ensure_cursor_visible();
        self.sync_scroll_binds();

        // Fire cursor_move plugin hook when the cursor position changed.
        // Excluded from Insert mode: cursor moves caused by typing call git blame
        // on the committed file, which produces stale annotations for lines that
        // don't exist yet in the commit (e.g. the empty line created by Enter).
        // cursor_move is fired explicitly when Escape exits insert mode instead.
        if !matches!(self.mode, Mode::Command | Mode::Search | Mode::Insert) {
            let (cur_line, cur_col) = {
                let cur = self.cursor();
                (cur.line, cur.col)
            };
            if cur_line != pre_cursor_line || cur_col != pre_cursor_col {
                let arg = format!("{},{}", cur_line + 1, cur_col + 1);
                self.plugin_event("cursor_move", &arg);
            }
        }

        action
    }

    /// Decode a sequence from the macro playback queue.
    /// Returns (key_name, unicode, ctrl) tuple and the number of characters consumed.
    fn decode_macro_sequence(&mut self) -> Option<(String, Option<char>, bool, usize)> {
        if self.macro_playback_queue.is_empty() {
            return None;
        }

        let first_char = *self.macro_playback_queue.front().unwrap();

        // Check for angle-bracket notation (e.g., <Left>, <C-D>)
        if first_char == '<' {
            // Collect characters until we find '>'
            let mut sequence = String::new();
            let temp_queue: Vec<char> = self.macro_playback_queue.iter().copied().collect();

            for (i, &ch) in temp_queue.iter().enumerate() {
                sequence.push(ch);
                if ch == '>' {
                    // Found complete sequence
                    let len = i + 1;

                    // Parse the sequence
                    if let Some((key_name, unicode, ctrl)) = self.parse_key_sequence(&sequence) {
                        return Some((key_name, unicode, ctrl, len));
                    } else {
                        // Invalid sequence, treat '<' as literal
                        return Some(("".to_string(), Some('<'), false, 1));
                    }
                }
            }

            // No closing '>', treat '<' as literal
            return Some(("".to_string(), Some('<'), false, 1));
        }

        // Handle ESC
        if first_char == '\x1b' {
            return Some(("Escape".to_string(), None, false, 1));
        }

        // Regular character
        Some(("".to_string(), Some(first_char), false, 1))
    }

    /// Parse a key sequence like "<Left>", "<C-D>", "<CR>", etc.
    fn parse_key_sequence(&self, seq: &str) -> Option<(String, Option<char>, bool)> {
        if !seq.starts_with('<') || !seq.ends_with('>') {
            return None;
        }

        let inner = &seq[1..seq.len() - 1];

        // Check for Ctrl combinations: <C-X>
        if inner.starts_with("C-") && inner.len() == 3 {
            let ch = inner.chars().nth(2).unwrap().to_lowercase().next().unwrap();
            return Some((ch.to_string(), Some(ch), true));
        }

        // Special keys
        match inner {
            "CR" => Some(("Return".to_string(), None, false)),
            "BS" => Some(("BackSpace".to_string(), None, false)),
            "Del" => Some(("Delete".to_string(), None, false)),
            "Left" => Some(("Left".to_string(), None, false)),
            "Right" => Some(("Right".to_string(), None, false)),
            "Up" => Some(("Up".to_string(), None, false)),
            "Down" => Some(("Down".to_string(), None, false)),
            "Home" => Some(("Home".to_string(), None, false)),
            "End" => Some(("End".to_string(), None, false)),
            "PageUp" => Some(("Page_Up".to_string(), None, false)),
            "PageDown" => Some(("Page_Down".to_string(), None, false)),
            _ => None,
        }
    }

    /// Advance macro playback by processing the next keystroke in the queue.
    /// Returns true if there are more keys to process.
    pub fn advance_macro_playback(&mut self) -> (bool, EngineAction) {
        // Decode the next key sequence
        if let Some((key_name, unicode, ctrl, consume_count)) = self.decode_macro_sequence() {
            // Remove consumed characters from queue
            for _ in 0..consume_count {
                self.macro_playback_queue.pop_front();
            }

            self.macro_recursion_depth += 1;
            let action = self.handle_key(&key_name, unicode, ctrl);
            self.macro_recursion_depth -= 1;

            // Check if we hit recursion limit
            if self.macro_recursion_depth >= MAX_MACRO_RECURSION {
                self.macro_playback_queue.clear();
                self.message = "Macro recursion limit reached".to_string();
                return (false, EngineAction::Error);
            }

            (!self.macro_playback_queue.is_empty(), action)
        } else {
            (false, EngineAction::None)
        }
    }

    fn handle_normal_key(
        &mut self,
        key_name: &str,
        unicode: Option<char>,
        ctrl: bool,
        changed: &mut bool,
    ) -> EngineAction {
        // Read-only guard: block keys that would enter Insert/Replace mode.
        if self.active_buffer_state().read_only {
            let blocked = matches!(
                unicode,
                Some('i' | 'a' | 'o' | 'O' | 'I' | 'A' | 's' | 'S' | 'c' | 'C' | 'R')
            );
            if blocked && self.pending_key.is_none() && self.pending_operator.is_none() {
                self.message = "Buffer is read-only".to_string();
                return EngineAction::None;
            }
        }

        // If leader mode is active, route all keypresses there first.
        if self.leader_partial.is_some() {
            return self.handle_leader_key(unicode);
        }

        // Detect leader keypress (non-ctrl, no pending key sequence, matches configured leader char).
        if !ctrl && self.pending_key.is_none() && unicode == Some(self.settings.leader) {
            self.leader_partial = Some(String::new());
            return EngineAction::None;
        }

        // Handle Ctrl combinations first
        if ctrl {
            match key_name {
                "d" => {
                    // Half-page down
                    let count = self.take_count();
                    let half = self.viewport_lines() / 2;
                    let scroll_amount = half * count;
                    let max_line = self.buffer().len_lines().saturating_sub(1);
                    self.view_mut().cursor.line =
                        (self.view().cursor.line + scroll_amount).min(max_line);
                    self.clamp_cursor_col();
                    return EngineAction::None;
                }
                "u" => {
                    // Ctrl-U: Half-page up
                    let count = self.take_count();
                    let half = self.viewport_lines() / 2;
                    let scroll_amount = half * count;
                    self.view_mut().cursor.line =
                        self.view().cursor.line.saturating_sub(scroll_amount);
                    self.clamp_cursor_col();
                    return EngineAction::None;
                }
                "r" => {
                    // Ctrl-R: Redo
                    self.redo();
                    self.refresh_md_previews();
                    return EngineAction::None;
                }
                "f" => {
                    // Full page down
                    let count = self.take_count();
                    let viewport = self.viewport_lines();
                    let scroll_amount = viewport * count;
                    let max_line = self.buffer().len_lines().saturating_sub(1);
                    self.view_mut().cursor.line =
                        (self.view().cursor.line + scroll_amount).min(max_line);
                    self.clamp_cursor_col();
                    return EngineAction::None;
                }
                "b" => {
                    // Full page up
                    let count = self.take_count();
                    let viewport = self.viewport_lines();
                    let scroll_amount = viewport * count;
                    self.view_mut().cursor.line =
                        self.view().cursor.line.saturating_sub(scroll_amount);
                    self.clamp_cursor_col();
                    return EngineAction::None;
                }
                "w" => {
                    // Ctrl-W prefix for window commands
                    self.pending_key = Some('\x17'); // Ctrl-W marker
                    return EngineAction::None;
                }
                "v" => {
                    // Ctrl-V: Enter visual block mode
                    self.mode = Mode::VisualBlock;
                    self.visual_anchor = Some(self.view().cursor);
                    return EngineAction::None;
                }
                "o" => {
                    // Ctrl-O: Jump list back
                    self.jump_list_back();
                    return EngineAction::None;
                }
                "i" => {
                    // Ctrl-I: Jump list forward (same as Tab in many terminals)
                    self.jump_list_forward();
                    return EngineAction::None;
                }
                "p" => {
                    // Ctrl-P: Open fuzzy file finder
                    self.open_fuzzy_finder();
                    return EngineAction::None;
                }
                "P" => {
                    // Ctrl-Shift-P: Open command palette
                    self.open_command_palette();
                    return EngineAction::None;
                }
                "g" => {
                    // Ctrl-G: Open live grep modal
                    self.open_live_grep();
                    return EngineAction::None;
                }
                "e" => {
                    // Ctrl-E: scroll down one line (cursor stays in place if possible)
                    let count = self.take_count();
                    let max_scroll = self.buffer().len_lines().saturating_sub(1);
                    let new_top = (self.view().scroll_top + count).min(max_scroll);
                    self.view_mut().scroll_top = new_top;
                    // Keep cursor visible
                    let viewport = self.viewport_lines();
                    if viewport > 0 && self.view().cursor.line < self.view().scroll_top {
                        self.view_mut().cursor.line = self.view().scroll_top;
                        self.clamp_cursor_col();
                    }
                    return EngineAction::None;
                }
                "y" => {
                    // Ctrl-Y: scroll up one line (cursor stays in place if possible)
                    let count = self.take_count();
                    let new_top = self.view().scroll_top.saturating_sub(count);
                    self.view_mut().scroll_top = new_top;
                    // Keep cursor visible
                    let viewport = self.viewport_lines();
                    if viewport > 0 && self.view().cursor.line >= self.view().scroll_top + viewport
                    {
                        self.view_mut().cursor.line = self.view().scroll_top + viewport - 1;
                        self.clamp_cursor_col();
                    }
                    return EngineAction::None;
                }
                "a" => {
                    // Ctrl-A: increment number under cursor
                    let count = self.take_count();
                    self.increment_number_at_cursor(count as i64, &mut false);
                    return EngineAction::None;
                }
                "x" => {
                    // Ctrl-X: decrement number under cursor
                    let count = self.take_count();
                    self.increment_number_at_cursor(-(count as i64), &mut false);
                    return EngineAction::None;
                }
                "backslash" => {
                    // Ctrl+\: Split editor group to the right (VSCode style)
                    self.open_editor_group(SplitDirection::Vertical);
                    return EngineAction::None;
                }
                "1" | "2" | "3" | "4" | "5" | "6" | "7" | "8" | "9" => {
                    // Ctrl+N: Focus group N (1-indexed)
                    let n: usize = key_name.parse().unwrap_or(1);
                    if let Some(gid) = self.group_layout.nth_leaf(n - 1) {
                        self.active_group = gid;
                    }
                    return EngineAction::None;
                }
                _ => {}
            }
        }

        // Handle pending multi-key sequences (gg, dd, Ctrl-W x, gt, r, f, t, m, etc.)
        // MUST come before count accumulation: pending keys like 'r' expect the next
        // character verbatim, including digits (e.g. r1 replaces with '1', not a count).
        if let Some(pending) = self.pending_key.take() {
            return self.handle_pending_key(pending, key_name, unicode, changed);
        }

        // Handle count accumulation (digits 1-9, and 0 when count already exists)
        if let Some(ch) = unicode {
            match ch {
                '1'..='9' => {
                    let digit = ch.to_digit(10).unwrap() as usize;
                    let new_count = self.count.unwrap_or(0) * 10 + digit;
                    if new_count > 10_000 {
                        self.count = Some(10_000);
                        self.message = "Count limited to 10,000".to_string();
                    } else {
                        self.count = Some(new_count);
                    }
                    return EngineAction::None;
                }
                '0' => {
                    if self.count.is_some() {
                        // Accumulate: 10, 20, 100, etc.
                        let new_count = self.count.unwrap() * 10;
                        if new_count > 10_000 {
                            self.count = Some(10_000);
                            self.message = "Count limited to 10,000".to_string();
                        } else {
                            self.count = Some(new_count);
                        }
                        return EngineAction::None;
                    }
                    // Fall through to handle '0' as "go to column 0" below
                }
                _ => {}
            }
        }

        // Handle pending find operator (dfx, dtx, dFx, dTx — waiting for target char)
        if let Some((op, find_type)) = self.pending_find_operator.take() {
            if let Some(target) = unicode {
                self.apply_operator_find_char(op, find_type, target, changed);
            } else {
                self.count = None;
            }
            return EngineAction::None;
        }

        // Handle pending operator + motion (dw, cw, etc.)
        if let Some(op) = self.pending_operator.take() {
            return self.handle_operator_motion(op, key_name, unicode, changed);
        }

        // In normal mode, check the unicode char for vim keys
        match unicode {
            Some('h') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_left();
                }
            }
            Some('j') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_down();
                }
            }
            Some('k') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_up();
                }
            }
            Some('l') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_right();
                }
            }
            Some('i') => {
                self.start_undo_group();
                self.insert_text_buffer.clear();
                self.mode = Mode::Insert;
                self.count = None; // Clear count when entering insert mode
            }
            Some('a') => {
                self.start_undo_group();
                self.insert_text_buffer.clear();
                let max_col = self.get_max_cursor_col(self.view().cursor.line);
                if self.view().cursor.col < max_col {
                    self.view_mut().cursor.col += 1;
                } else {
                    let line = self.view().cursor.line;
                    let insert_max = self.get_line_len_for_insert(line);
                    self.view_mut().cursor.col = insert_max;
                }
                self.mode = Mode::Insert;
                self.count = None; // Clear count when entering insert mode
            }
            Some('A') => {
                self.start_undo_group();
                self.insert_text_buffer.clear();
                let line = self.view().cursor.line;
                self.view_mut().cursor.col = self.get_line_len_for_insert(line);
                self.mode = Mode::Insert;
                self.count = None; // Clear count when entering insert mode
            }
            Some('I') => {
                self.start_undo_group();
                self.insert_text_buffer.clear();
                let line = self.view().cursor.line;
                let line_start = self.buffer().line_to_char(line);
                let line_len = self.buffer().line_len_chars(line);
                let mut col = 0;
                for i in 0..line_len {
                    let ch = self.buffer().content.char(line_start + i);
                    if ch != ' ' && ch != '\t' {
                        break;
                    }
                    col = i + 1;
                }
                self.view_mut().cursor.col = col;
                self.mode = Mode::Insert;
                self.count = None; // Clear count when entering insert mode
            }
            Some('o') => {
                let count = self.take_count();
                self.start_undo_group();
                let line = self.view().cursor.line;
                let indent = if self.settings.auto_indent {
                    self.get_line_indent_str(line)
                } else {
                    String::new()
                };
                let indent_len = indent.len();
                let line_end =
                    self.buffer().line_to_char(line) + self.buffer().line_len_chars(line);
                let line_content = self.buffer().content.line(line);
                let insert_pos = if self.buffer().line_len_chars(line) > 0 {
                    if line_content.chars().last() == Some('\n') {
                        line_end - 1
                    } else {
                        line_end
                    }
                } else {
                    line_end
                };
                // Insert newlines (with indent on the first new line for count==1).
                // For count > 1 only the first new line gets the indent; the rest are blank.
                let text = if count == 1 {
                    format!("\n{}", indent)
                } else {
                    format!("\n{}{}", indent, "\n".repeat(count - 1))
                };
                self.insert_with_undo(insert_pos, &text);
                self.insert_text_buffer.clear();
                self.view_mut().cursor.line += 1;
                self.view_mut().cursor.col = indent_len;
                self.mode = Mode::Insert;
                self.count = None; // Clear count when entering insert mode
                *changed = true;
            }
            Some('O') => {
                let count = self.take_count();
                self.start_undo_group();
                let line = self.view().cursor.line;
                let indent = if self.settings.auto_indent {
                    self.get_line_indent_str(line)
                } else {
                    String::new()
                };
                let indent_len = indent.len();
                let line_start = self.buffer().line_to_char(line);
                // Insert indent + newlines above current line.
                let text = if count == 1 {
                    format!("{}\n", indent)
                } else {
                    format!("{}\n{}", indent, "\n".repeat(count - 1))
                };
                self.insert_with_undo(line_start, &text);
                self.insert_text_buffer.clear();
                self.view_mut().cursor.col = indent_len;
                self.mode = Mode::Insert;
                self.count = None; // Clear count when entering insert mode
                *changed = true;
            }
            Some('0') => self.view_mut().cursor.col = 0,
            Some('^') => {
                // ^ : first non-blank character of line
                let line = self.view().cursor.line;
                self.view_mut().cursor.col = self.first_non_blank_col(line);
            }
            Some('+') => {
                // + : first non-blank of next line (count supported)
                let count = self.take_count();
                let max_line = self.buffer().len_lines().saturating_sub(1);
                let target = (self.view().cursor.line + count).min(max_line);
                self.view_mut().cursor.line = target;
                self.view_mut().cursor.col = self.first_non_blank_col(target);
            }
            Some('-') => {
                // - : first non-blank of previous line (count supported)
                let count = self.take_count();
                let target = self.view().cursor.line.saturating_sub(count);
                self.view_mut().cursor.line = target;
                self.view_mut().cursor.col = self.first_non_blank_col(target);
            }
            Some('_') => {
                // _ : first non-blank of N-1 lines down (1_ = current line)
                let count = self.take_count();
                let max_line = self.buffer().len_lines().saturating_sub(1);
                let target = (self.view().cursor.line + count - 1).min(max_line);
                self.view_mut().cursor.line = target;
                self.view_mut().cursor.col = self.first_non_blank_col(target);
            }
            Some('|') => {
                // | : go to column N (1-indexed, default 1)
                let count = self.take_count();
                let target_col = count.saturating_sub(1);
                let line = self.view().cursor.line;
                let max_col = self.get_max_cursor_col(line);
                self.view_mut().cursor.col = target_col.min(max_col);
            }
            Some('&') => {
                // & : repeat last :s on current line
                if let Some((pattern, replacement, flags)) = self.last_substitute.clone() {
                    let line = self.view().cursor.line;
                    match self.replace_in_range(Some((line, line)), &pattern, &replacement, &flags)
                    {
                        Ok(count) => {
                            self.message = format!(
                                "{} substitution{}",
                                count,
                                if count == 1 { "" } else { "s" }
                            );
                        }
                        Err(e) => {
                            self.message = e;
                        }
                    }
                    *changed = true;
                } else {
                    self.message = "No previous substitute command".to_string();
                }
            }
            Some('$') => {
                let line = self.view().cursor.line;
                self.view_mut().cursor.col = self.get_max_cursor_col(line);
            }
            Some('x') => {
                let count = self.take_count();
                let line = self.view().cursor.line;
                let col = self.view().cursor.col;
                let max_col = self.get_max_cursor_col(line);
                if max_col > 0 || self.buffer().line_len_chars(line) > 0 {
                    let char_idx = self.buffer().line_to_char(line) + col;
                    // Calculate how many chars we can actually delete
                    let line_end =
                        self.buffer().line_to_char(line) + self.buffer().line_len_chars(line);
                    let available = line_end - char_idx;
                    let to_delete = count.min(available);

                    if to_delete > 0 && char_idx < self.buffer().len_chars() {
                        // Save deleted chars to register (characterwise)
                        let deleted_chars: String = self
                            .buffer()
                            .content
                            .slice(char_idx..char_idx + to_delete)
                            .chars()
                            .collect();
                        let reg = self.active_register();
                        self.set_delete_register(reg, deleted_chars, false);
                        self.clear_selected_register();

                        self.start_undo_group();
                        self.delete_with_undo(char_idx, char_idx + to_delete);
                        self.finish_undo_group();
                        self.clamp_cursor_col();
                        *changed = true;

                        // Record for repeat
                        self.last_change = Some(Change {
                            op: ChangeOp::Delete,
                            text: String::new(),
                            count,
                            motion: Some(Motion::Right),
                        });
                    }
                }
            }
            Some('X') => {
                // X: delete character(s) before cursor (like Backspace in normal mode)
                let count = self.take_count();
                let line = self.view().cursor.line;
                let col = self.view().cursor.col;
                if col > 0 {
                    let to_delete = count.min(col);
                    let line_start = self.buffer().line_to_char(line);
                    let char_idx = line_start + col - to_delete;
                    let deleted_chars: String = self
                        .buffer()
                        .content
                        .slice(char_idx..char_idx + to_delete)
                        .chars()
                        .collect();
                    let reg = self.active_register();
                    self.set_delete_register(reg, deleted_chars, false);
                    self.clear_selected_register();

                    self.start_undo_group();
                    self.delete_with_undo(char_idx, char_idx + to_delete);
                    self.finish_undo_group();
                    self.view_mut().cursor.col = col - to_delete;
                    *changed = true;
                }
            }
            Some('w') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_word_forward();
                }
            }
            Some('W') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_bigword_forward();
                }
            }
            Some('b') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_word_backward();
                }
            }
            Some('B') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_bigword_backward();
                }
            }
            Some('e') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_word_end();
                }
            }
            Some('E') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_bigword_end();
                }
            }
            Some('H') => {
                // H: jump to top of visible screen
                let count = self.take_count().max(1);
                let scroll_top = self.view().scroll_top;
                let viewport = self.viewport_lines();
                let max_line = self.buffer().len_lines().saturating_sub(1);
                let target = (scroll_top + count - 1).min(max_line);
                let target = target.min(scroll_top + viewport.saturating_sub(1));
                self.push_jump_location();
                self.view_mut().cursor.line = target;
                self.clamp_cursor_col();
            }
            Some('M') => {
                // M: jump to middle of visible screen
                let scroll_top = self.view().scroll_top;
                let viewport = self.viewport_lines();
                let max_line = self.buffer().len_lines().saturating_sub(1);
                let mid = scroll_top + viewport / 2;
                self.push_jump_location();
                self.view_mut().cursor.line = mid.min(max_line);
                self.clamp_cursor_col();
            }
            Some('L') => {
                // L: jump to bottom of visible screen
                let count = self.take_count().max(1);
                let scroll_top = self.view().scroll_top;
                let viewport = self.viewport_lines();
                let max_line = self.buffer().len_lines().saturating_sub(1);
                let target_from_bottom = scroll_top + viewport.saturating_sub(count);
                self.push_jump_location();
                self.view_mut().cursor.line = target_from_bottom.min(max_line);
                self.clamp_cursor_col();
            }
            Some('R') => {
                // R: enter Replace mode
                self.start_undo_group();
                self.insert_text_buffer.clear();
                self.mode = Mode::Replace;
                self.count = None;
            }
            Some('(') => {
                // (: backward sentence
                let count = self.take_count();
                self.push_jump_location();
                for _ in 0..count {
                    self.move_sentence_backward();
                }
            }
            Some(')') => {
                // ): forward sentence
                let count = self.take_count();
                self.push_jump_location();
                for _ in 0..count {
                    self.move_sentence_forward();
                }
            }
            Some('f') => {
                self.pending_key = Some('f');
            }
            Some('F') => {
                self.pending_key = Some('F');
            }
            Some('t') => {
                self.pending_key = Some('t');
            }
            Some('T') => {
                self.pending_key = Some('T');
            }
            Some('r') => {
                self.pending_key = Some('r');
            }
            Some(';') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.repeat_find(false);
                }
            }
            Some(',') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.repeat_find(true);
                }
            }
            Some('{') => {
                let count = self.take_count();
                self.push_jump_location();
                for _ in 0..count {
                    self.move_paragraph_backward();
                }
            }
            Some('}') => {
                let count = self.take_count();
                self.push_jump_location();
                for _ in 0..count {
                    self.move_paragraph_forward();
                }
            }
            Some('d') => {
                // 'd' can be both operator (dw) and motion (dd)
                // Set as pending_operator first
                self.pending_operator = Some('d');
            }
            Some('D') => {
                let count = self.take_count();
                self.start_undo_group();
                // D with count deletes from cursor to end of line, then (count-1) full lines below
                self.delete_to_end_of_line_with_count(count, changed);
                self.finish_undo_group();
            }
            Some('c') => {
                // 'c' operator (change) - delete then enter insert mode
                self.pending_operator = Some('c');
            }
            Some('C') => {
                // C: delete from cursor to end of line, enter insert mode
                let count = self.take_count();
                self.start_undo_group();
                self.delete_to_end_of_line_with_count(count, changed);
                self.insert_text_buffer.clear();
                self.mode = Mode::Insert;
                self.count = None;
                // Don't finish_undo_group here - let insert mode do it
            }
            Some('s') => {
                // s: substitute char (delete char under cursor, enter insert mode)
                let count = self.take_count();
                let line = self.view().cursor.line;
                let col = self.view().cursor.col;
                let max_col = self.get_max_cursor_col(line);
                if max_col > 0 || self.buffer().line_len_chars(line) > 0 {
                    let char_idx = self.buffer().line_to_char(line) + col;
                    let line_end =
                        self.buffer().line_to_char(line) + self.buffer().line_len_chars(line);
                    let available = line_end - char_idx;
                    let to_delete = count.min(available);

                    if to_delete > 0 && char_idx < self.buffer().len_chars() {
                        let deleted_chars: String = self
                            .buffer()
                            .content
                            .slice(char_idx..char_idx + to_delete)
                            .chars()
                            .collect();
                        let reg = self.active_register();
                        self.set_register(reg, deleted_chars, false);
                        self.clear_selected_register();

                        self.start_undo_group();
                        self.delete_with_undo(char_idx, char_idx + to_delete);
                        *changed = true;
                    } else {
                        self.start_undo_group();
                    }
                } else {
                    self.start_undo_group();
                }
                self.insert_text_buffer.clear();
                self.mode = Mode::Insert;
                self.count = None;
            }
            Some('S') => {
                // S: substitute line (delete entire line content, enter insert mode)
                let count = self.take_count();
                let start_line = self.view().cursor.line;
                let _end_line = (start_line + count).min(self.buffer().len_lines());

                self.start_undo_group();

                // Delete content of lines but keep one line structure
                for i in 0..count {
                    let line_idx = start_line + i;
                    if line_idx >= self.buffer().len_lines() {
                        break;
                    }

                    let line_start = self.buffer().line_to_char(line_idx);
                    let line_len = self.buffer().line_len_chars(line_idx);
                    let line_content = self.buffer().content.line(line_idx);

                    // Calculate what to delete (exclude trailing newline)
                    let delete_end = if line_content.chars().last() == Some('\n') && line_len > 0 {
                        line_start + line_len - 1
                    } else {
                        line_start + line_len
                    };

                    if line_start < delete_end {
                        let deleted: String = self
                            .buffer()
                            .content
                            .slice(line_start..delete_end)
                            .chars()
                            .collect();
                        let reg = self.active_register();
                        self.set_register(reg, deleted, false);
                        self.clear_selected_register();

                        self.delete_with_undo(line_start, delete_end);
                        *changed = true;
                        break; // After first deletion, line indices change
                    }
                }

                self.view_mut().cursor.col = 0;
                self.insert_text_buffer.clear();
                self.mode = Mode::Insert;
                self.count = None;
            }
            Some('K') => {
                // K: Show LSP hover information at cursor
                self.lsp_request_hover();
            }
            Some('g') => {
                self.pending_key = Some('g');
            }
            Some(']') => {
                self.pending_key = Some(']');
            }
            Some('[') => {
                self.pending_key = Some('[');
            }
            Some('z') => {
                // Fold + scroll commands
                self.pending_key = Some('z');
                self.message =
                    "z: a/o/c=fold  M=closeAll  R=openAll  d/D=del  f=create  j/k=nav  z/t/b=scroll  h/l=hscroll"
                        .to_string();
            }
            Some('m') => {
                // Set mark: m{a-z}
                self.pending_key = Some('m');
            }
            Some('\'') => {
                // Jump to mark line: '{a-z}
                self.pending_key = Some('\'');
            }
            Some('`') => {
                // Jump to exact mark position: `{a-z}
                self.pending_key = Some('`');
            }
            Some('G') => {
                self.push_jump_location();
                if self.peek_count().is_some() {
                    // Count provided: go to line N (1-indexed)
                    let count = self.take_count();
                    let target_line = (count - 1).min(self.buffer().len_lines().saturating_sub(1));
                    self.view_mut().cursor.line = target_line;
                } else {
                    // No count: go to last line
                    let last = self.buffer().len_lines().saturating_sub(1);
                    self.view_mut().cursor.line = last;
                }
                self.clamp_cursor_col();
            }
            Some('~') => {
                // Toggle case of char(s) under cursor
                let count = self.take_count();
                self.toggle_case_at_cursor(count, changed);
                self.last_change = Some(Change {
                    op: ChangeOp::ToggleCase,
                    text: String::new(),
                    count,
                    motion: None,
                });
            }
            Some('J') => {
                // Join lines
                let count = self.take_count().max(1);
                self.push_jump_location();
                self.join_lines(count, changed);
                self.last_change = Some(Change {
                    op: ChangeOp::Join,
                    text: String::new(),
                    count,
                    motion: None,
                });
            }
            Some('*') => {
                // Search forward for word under cursor
                let count = self.take_count();
                self.push_jump_location();
                self.search_word_under_cursor(true);
                for _ in 1..count {
                    self.search_next();
                }
            }
            Some('#') => {
                // Search backward for word under cursor
                let count = self.take_count();
                self.push_jump_location();
                self.search_word_under_cursor(false);
                for _ in 1..count {
                    self.search_prev();
                }
            }
            Some('>') => {
                // > operator: set pending for >>
                self.pending_operator = Some('>');
            }
            Some('<') => {
                // < operator: set pending for <<
                self.pending_operator = Some('<');
            }
            Some('=') => {
                // = operator: auto-indent (== indents current line)
                self.pending_operator = Some('=');
            }
            Some('u') => {
                self.undo();
                self.refresh_md_previews();
            }
            Some('U') => {
                *changed = self.undo_line();
            }
            Some('.') => {
                // Repeat last change
                let count = self.take_count();
                self.repeat_last_change(count, changed);
            }
            Some('y') => {
                self.pending_operator = Some('y');
            }
            Some('Y') => {
                let count = self.take_count();
                self.yank_lines(count);
            }
            Some('p') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.paste_after(changed);
                }
            }
            Some('P') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.paste_before(changed);
                }
            }
            Some('q') => {
                // If already recording, stop recording
                if self.macro_recording.is_some() {
                    self.stop_macro_recording();
                    return EngineAction::None;
                }

                // Otherwise, start pending key for register selection
                self.pending_key = Some('q');
            }
            Some('@') => {
                // Start pending key for register selection (@ + register)
                // @@ is handled in handle_pending_key
                self.pending_key = Some('@');
            }
            Some('"') => {
                self.pending_key = Some('"');
            }
            Some('n') => {
                let count = self.take_count();
                self.push_jump_location();
                for _ in 0..count {
                    match self.search_direction {
                        SearchDirection::Forward => self.search_next(),
                        SearchDirection::Backward => self.search_prev(),
                    }
                }
            }
            Some('N') => {
                let count = self.take_count();
                self.push_jump_location();
                for _ in 0..count {
                    match self.search_direction {
                        SearchDirection::Forward => self.search_prev(),
                        SearchDirection::Backward => self.search_next(),
                    }
                }
            }
            Some('v') => {
                self.mode = Mode::Visual;
                self.visual_anchor = Some(self.view().cursor);
            }
            Some('V') => {
                self.mode = Mode::VisualLine;
                self.visual_anchor = Some(self.view().cursor);
            }
            Some('%') => {
                self.push_jump_location();
                self.move_to_matching_bracket();
            }
            Some(':') => {
                self.mode = Mode::Command;
                self.command_buffer.clear();
                self.command_cursor = 0;
                self.count = None; // Clear count when entering command mode
            }
            Some('/') => {
                self.mode = Mode::Search;
                self.command_buffer.clear();
                self.command_cursor = 0;
                self.search_direction = SearchDirection::Forward;
                self.search_start_cursor = Some(self.view().cursor);
                self.search_word_bounded = false; // Clear word-boundary mode
                self.count = None; // Clear count when entering search mode
            }
            Some('?') => {
                self.mode = Mode::Search;
                self.command_buffer.clear();
                self.command_cursor = 0;
                self.search_direction = SearchDirection::Backward;
                self.search_start_cursor = Some(self.view().cursor);
                self.search_word_bounded = false; // Clear word-boundary mode
                self.count = None; // Clear count when entering search mode
            }
            _ => match key_name {
                "Escape" => {
                    // Clear count, pending key, and any extra cursors in normal mode
                    self.count = None;
                    self.pending_key = None;
                    self.view_mut().extra_cursors.clear();
                    // Clear search highlights (like :noh)
                    if !self.search_matches.is_empty() {
                        self.search_matches.clear();
                        self.search_index = None;
                    }
                }
                "Left" => {
                    let count = self.take_count();
                    for _ in 0..count {
                        self.move_left();
                    }
                }
                "Down" => {
                    let count = self.take_count();
                    for _ in 0..count {
                        self.move_down();
                    }
                }
                "Up" => {
                    let count = self.take_count();
                    for _ in 0..count {
                        self.move_up();
                    }
                }
                "Right" => {
                    let count = self.take_count();
                    for _ in 0..count {
                        self.move_right();
                    }
                }
                "Home" => self.view_mut().cursor.col = 0,
                "End" => {
                    let line = self.view().cursor.line;
                    self.view_mut().cursor.col = self.get_max_cursor_col(line);
                }
                // Tab = Ctrl-I in terminals (same byte 0x09); both advance the jump list
                "Tab" => self.jump_list_forward(),
                // Debug / DAP function keys
                "F5" => {
                    let cmd = if self.dap_session_active {
                        "continue"
                    } else {
                        "debug"
                    };
                    let _ = self.execute_command(cmd);
                }
                "F6" => {
                    let _ = self.execute_command("pause");
                }
                "F9" => {
                    let _ = self.execute_command("brkpt");
                }
                "F10" => {
                    let _ = self.execute_command("stepover");
                }
                "F11" => {
                    let _ = self.execute_command("stepin");
                }
                _ => {}
            },
        }
        EngineAction::None
    }

    fn handle_pending_key(
        &mut self,
        pending: char,
        key_name: &str,
        unicode: Option<char>,
        changed: &mut bool,
    ) -> EngineAction {
        match pending {
            'g' => match unicode {
                Some('g') => {
                    if let Some(op) = self.pending_operator.take() {
                        // dgg/ygg/cgg/zfgg etc: linewise operator to target line
                        let count = self.count.take();
                        let target_line = count
                            .map(|n| {
                                n.saturating_sub(1)
                                    .min(self.buffer().len_lines().saturating_sub(1))
                            })
                            .unwrap_or(0);
                        let current_line = self.view().cursor.line;
                        let (start, end) = if target_line <= current_line {
                            (target_line, current_line)
                        } else {
                            (current_line, target_line)
                        };
                        if op == 'Z' {
                            // zfgg: fold from cursor to target
                            if end > start {
                                self.cmd_fold_create(start, end);
                            }
                        } else {
                            self.apply_linewise_operator(op, start, end, changed);
                        }
                    } else {
                        self.push_jump_location();
                        if self.peek_count().is_some() {
                            let count = self.take_count();
                            let target_line =
                                (count - 1).min(self.buffer().len_lines().saturating_sub(1));
                            self.view_mut().cursor.line = target_line;
                        } else {
                            self.view_mut().cursor.line = 0;
                        }
                        self.view_mut().cursor.col = 0;
                    }
                }
                Some('e') => {
                    if let Some(op) = self.pending_operator.take() {
                        // dge: delete backward to end of previous word (charwise)
                        let count = self.take_count();
                        let start_pos = self.buffer().line_to_char(self.view().cursor.line)
                            + self.view().cursor.col;
                        for _ in 0..count {
                            self.move_word_end_backward();
                        }
                        let end_pos = self.buffer().line_to_char(self.view().cursor.line)
                            + self.view().cursor.col;
                        if end_pos < start_pos {
                            // Include the character at end_pos
                            self.apply_charwise_operator(op, end_pos, start_pos + 1, changed);
                        }
                    } else {
                        let count = self.take_count();
                        for _ in 0..count {
                            self.move_word_end_backward();
                        }
                    }
                }
                Some('E') => {
                    if let Some(op) = self.pending_operator.take() {
                        // dgE: delete backward to end of previous WORD (charwise)
                        let count = self.take_count();
                        let start_pos = self.buffer().line_to_char(self.view().cursor.line)
                            + self.view().cursor.col;
                        for _ in 0..count {
                            self.move_bigword_end_backward();
                        }
                        let end_pos = self.buffer().line_to_char(self.view().cursor.line)
                            + self.view().cursor.col;
                        if end_pos < start_pos {
                            self.apply_charwise_operator(op, end_pos, start_pos + 1, changed);
                        }
                    } else {
                        let count = self.take_count();
                        for _ in 0..count {
                            self.move_bigword_end_backward();
                        }
                    }
                }
                Some('_') => {
                    // g_: last non-blank character of line (count: Nth line below)
                    let count = self.take_count();
                    let line = (self.view().cursor.line + count - 1)
                        .min(self.buffer().len_lines().saturating_sub(1));
                    self.view_mut().cursor.line = line;
                    self.view_mut().cursor.col = self.last_non_blank_col(line);
                }
                Some('*') => {
                    // g*: forward search for word under cursor (no word boundaries)
                    let count = self.take_count();
                    self.push_jump_location();
                    self.search_word_under_cursor_partial(true);
                    for _ in 1..count {
                        self.search_next();
                    }
                }
                Some('#') => {
                    // g#: backward search for word under cursor (no word boundaries)
                    let count = self.take_count();
                    self.push_jump_location();
                    self.search_word_under_cursor_partial(false);
                    for _ in 1..count {
                        self.search_prev();
                    }
                }
                Some('J') => {
                    // gJ: join lines without inserting space
                    let count = self.take_count().max(1);
                    self.push_jump_location();
                    self.join_lines_no_space(count, changed);
                }
                Some('f') => {
                    // gf: open file path under cursor
                    if let Some(path) = self.file_path_under_cursor() {
                        let abs_path = if path.is_absolute() {
                            path
                        } else {
                            self.cwd.join(&path)
                        };
                        return EngineAction::OpenFile(abs_path);
                    } else {
                        self.message = "No file path under cursor".to_string();
                    }
                }
                Some('t') => {
                    self.next_tab();
                }
                Some('T') => {
                    self.prev_tab();
                }
                Some('s') => {
                    return self.cmd_git_stage_hunk();
                }
                Some('d') => {
                    self.push_jump_location();
                    self.lsp_request_definition();
                }
                Some('r') => {
                    self.push_jump_location();
                    self.lsp_request_references();
                }
                Some('i') => {
                    self.push_jump_location();
                    self.lsp_request_implementation();
                }
                Some('y') => {
                    self.push_jump_location();
                    self.lsp_request_type_definition();
                }
                Some('j') => {
                    // gj: move down one visual row (stays in wrapped line when possible)
                    let count = self.take_count().max(1);
                    for _ in 0..count {
                        self.move_visual_down();
                    }
                }
                Some('k') => {
                    // gk: move up one visual row (stays in wrapped line when possible)
                    let count = self.take_count().max(1);
                    for _ in 0..count {
                        self.move_visual_up();
                    }
                }
                Some('~') => {
                    // g~{motion}: toggle case operator — set pending_operator and await motion
                    self.pending_operator = Some('~');
                }
                Some('u') => {
                    // gu{motion}: lowercase operator
                    // Check if operator is pending (e.g. c/d + g + u) — handled elsewhere
                    self.pending_operator = Some('u');
                }
                Some('U') => {
                    // gU{motion}: uppercase operator
                    self.pending_operator = Some('U');
                }
                Some('n') => {
                    // gn: enter visual mode selecting next search match
                    // If an operator was saved (cgn), apply it; otherwise just select
                    let op = self.pending_operator.take();
                    self.cmd_gn(op, false, changed);
                }
                Some('N') => {
                    // gN: enter visual mode selecting previous search match
                    let op = self.pending_operator.take();
                    self.cmd_gn(op, true, changed);
                }
                Some('p') => {
                    // gp: paste after, leave cursor after pasted text
                    let count = self.take_count();
                    for _ in 0..count {
                        self.paste_after_cursor_after(changed);
                    }
                }
                Some('P') => {
                    // gP: paste before, leave cursor after pasted text
                    let count = self.take_count();
                    for _ in 0..count {
                        self.paste_before_cursor_after(changed);
                    }
                }
                Some('v') => {
                    // gv: reselect last visual selection
                    if let (Some(anchor), Some(cursor)) =
                        (self.last_visual_anchor, self.last_visual_cursor)
                    {
                        let mode = self.last_visual_mode;
                        self.mode = mode;
                        self.visual_anchor = Some(anchor);
                        self.view_mut().cursor = cursor;
                    }
                }
                Some(';') => {
                    // g;: jump to previous change position
                    if self.change_list.is_empty() {
                        self.message = "Change list is empty".to_string();
                    } else if self.change_list_pos == 0 {
                        self.message = "Already at oldest change".to_string();
                    } else {
                        self.change_list_pos -= 1;
                        let (line, col) = self.change_list[self.change_list_pos];
                        let max_line = self.buffer().len_lines().saturating_sub(1);
                        self.view_mut().cursor.line = line.min(max_line);
                        self.view_mut().cursor.col = col;
                        self.clamp_cursor_col();
                    }
                }
                Some(',') => {
                    // g,: jump to next change position
                    if self.change_list.is_empty() {
                        self.message = "Change list is empty".to_string();
                    } else if self.change_list_pos >= self.change_list.len() {
                        self.message = "Already at newest change".to_string();
                    } else {
                        let (line, col) = self.change_list[self.change_list_pos];
                        let max_line = self.buffer().len_lines().saturating_sub(1);
                        self.view_mut().cursor.line = line.min(max_line);
                        self.view_mut().cursor.col = col;
                        self.clamp_cursor_col();
                        self.change_list_pos =
                            (self.change_list_pos + 1).min(self.change_list.len());
                    }
                }
                _ => {}
            },
            ']' => match unicode {
                Some('c') => self.jump_next_hunk(),
                Some('d') => self.jump_next_diagnostic(),
                Some('p') => {
                    // ]p: paste after with indent matching current line
                    let count = self.take_count();
                    for _ in 0..count {
                        self.paste_after_adjusted_indent(changed);
                    }
                }
                Some(']') => {
                    // ]]: jump to next section ('{' in column 0)
                    let count = self.take_count();
                    for _ in 0..count {
                        self.jump_section_forward(false);
                    }
                }
                Some('[') => {
                    // ][: jump to next section end ('}' in column 0)
                    let count = self.take_count();
                    for _ in 0..count {
                        self.jump_section_forward(true);
                    }
                }
                Some('m') => {
                    // ]m: jump to next method start
                    let count = self.take_count();
                    for _ in 0..count {
                        self.jump_method_start_forward();
                    }
                }
                Some('M') => {
                    // ]M: jump to next method end
                    let count = self.take_count();
                    for _ in 0..count {
                        self.jump_method_end_forward();
                    }
                }
                Some('}') => {
                    // ]}: jump to next unmatched '}'
                    let count = self.take_count();
                    for _ in 0..count {
                        self.jump_unmatched_forward('{', '}');
                    }
                }
                Some(')') => {
                    // ]): jump to next unmatched ')'
                    let count = self.take_count();
                    for _ in 0..count {
                        self.jump_unmatched_forward('(', ')');
                    }
                }
                _ => {}
            },
            '[' => match unicode {
                Some('c') => self.jump_prev_hunk(),
                Some('d') => self.jump_prev_diagnostic(),
                Some('p') => {
                    // [p: paste before with indent matching current line
                    let count = self.take_count();
                    for _ in 0..count {
                        self.paste_before_adjusted_indent(changed);
                    }
                }
                Some('[') => {
                    // [[: jump to previous section ('{' in column 0)
                    let count = self.take_count();
                    for _ in 0..count {
                        self.jump_section_backward(false);
                    }
                }
                Some(']') => {
                    // []: jump to previous section end ('}' in column 0)
                    let count = self.take_count();
                    for _ in 0..count {
                        self.jump_section_backward(true);
                    }
                }
                Some('m') => {
                    // [m: jump to previous method start
                    let count = self.take_count();
                    for _ in 0..count {
                        self.jump_method_start_backward();
                    }
                }
                Some('M') => {
                    // [M: jump to previous method end
                    let count = self.take_count();
                    for _ in 0..count {
                        self.jump_method_end_backward();
                    }
                }
                Some('{') => {
                    // [{: jump to previous unmatched '{'
                    let count = self.take_count();
                    for _ in 0..count {
                        self.jump_unmatched_backward('{', '}');
                    }
                }
                Some('(') => {
                    // [(: jump to previous unmatched '('
                    let count = self.take_count();
                    for _ in 0..count {
                        self.jump_unmatched_backward('(', ')');
                    }
                }
                _ => {}
            },
            'd' => {
                // This should not be reached - 'd' is now handled as pending_operator
                // But keep for backward compatibility during transition
                if unicode == Some('d') {
                    let count = self.take_count();
                    self.start_undo_group();
                    self.delete_lines(count, changed);
                    self.finish_undo_group();
                }
            }
            '"' => {
                // Register selection: "x sets selected_register for next operation
                if let Some(ch) = unicode {
                    if ch.is_ascii_lowercase() || ch == '"' || ch == '+' || ch == '*' {
                        self.selected_register = Some(ch);
                    }
                }
            }
            'q' => {
                // Macro recording: q<register>
                if let Some(ch) = unicode {
                    if ch.is_ascii_lowercase() {
                        self.start_macro_recording(ch);
                    } else {
                        self.message = "Invalid register for macro".to_string();
                    }
                }
            }
            '@' => {
                // Macro playback: @<register> or @@ or @:
                if let Some(ch) = unicode {
                    if ch == '@' {
                        // @@ - repeat last macro
                        if let Some(last_reg) = self.last_macro_register {
                            let count = self.take_count();
                            let _ = self.play_macro_with_count(last_reg, count);
                        } else {
                            self.message = "No previous macro".to_string();
                        }
                    } else if ch == ':' {
                        // @: - repeat last ex command
                        if let Some(last_cmd) = self.last_ex_command.clone() {
                            let count = self.take_count();
                            for _ in 0..count {
                                let _ = self.execute_command(&last_cmd);
                            }
                        } else {
                            self.message = "No previous command".to_string();
                        }
                    } else if ch.is_ascii_lowercase() {
                        let count = self.take_count();
                        let _ = self.play_macro_with_count(ch, count);
                    } else {
                        self.message = "Invalid register for macro playback".to_string();
                    }
                }
            }
            'f' | 'F' | 't' | 'T' => {
                // Character find motions
                if let Some(target) = unicode {
                    let count = self.take_count();
                    for _ in 0..count {
                        self.find_char(pending, target);
                    }
                    // Remember this find for ; and , repeat
                    self.last_find = Some((pending, target));
                }
            }
            'r' => {
                // Replace character: r followed by a character replaces char under cursor
                if let Some(replacement) = unicode {
                    let count = self.take_count();
                    self.start_undo_group();
                    self.replace_chars(replacement, count, changed);
                    self.finish_undo_group();

                    // Record for repeat (.)
                    self.last_change = Some(Change {
                        op: ChangeOp::Replace,
                        text: replacement.to_string(),
                        count,
                        motion: None,
                    });
                }
            }
            '\x17' => {
                // Ctrl-W prefix
                match unicode {
                    Some('h') | Some('H') => {
                        self.focus_window_direction(SplitDirection::Vertical, false)
                    }
                    Some('j') | Some('J') => {
                        self.focus_window_direction(SplitDirection::Horizontal, true)
                    }
                    Some('k') | Some('K') => {
                        self.focus_window_direction(SplitDirection::Horizontal, false)
                    }
                    Some('l') | Some('L') => {
                        self.focus_window_direction(SplitDirection::Vertical, true)
                    }
                    Some('w') | Some('W') => self.focus_next_window(),
                    Some('c') | Some('C') => {
                        self.close_window();
                    }
                    Some('o') | Some('O') => self.close_other_windows(),
                    Some('s') | Some('S') => self.split_window(SplitDirection::Horizontal, None),
                    Some('v') | Some('V') => self.split_window(SplitDirection::Vertical, None),
                    Some('e') => self.open_editor_group(SplitDirection::Vertical),
                    Some('E') => self.open_editor_group(SplitDirection::Horizontal),
                    Some('q') => {
                        // Ctrl-W q: quit window (alias for close)
                        self.close_window();
                    }
                    Some('n') => {
                        // Ctrl-W n: new window (horizontal split with empty buffer)
                        let _ = self.execute_command("new");
                    }
                    Some('+') => {
                        // Ctrl-W +: increase height (adjust parent horizontal split)
                        let count = self.take_count().max(1);
                        self.resize_window_split(SplitDirection::Horizontal, true, count);
                    }
                    Some('-') => {
                        // Ctrl-W -: decrease height
                        let count = self.take_count().max(1);
                        self.resize_window_split(SplitDirection::Horizontal, false, count);
                    }
                    Some('>') => {
                        // Ctrl-W >: increase width (adjust parent vertical split)
                        let count = self.take_count().max(1);
                        self.resize_window_split(SplitDirection::Vertical, true, count);
                    }
                    Some('<') => {
                        // Ctrl-W <: decrease width
                        let count = self.take_count().max(1);
                        self.resize_window_split(SplitDirection::Vertical, false, count);
                    }
                    Some('=') => {
                        // Ctrl-W =: equalize all splits
                        self.equalize_splits();
                    }
                    Some('_') => {
                        // Ctrl-W _: maximize height (set horizontal split to extreme)
                        self.maximize_window_split(SplitDirection::Horizontal);
                    }
                    Some('|') => {
                        // Ctrl-W |: maximize width (set vertical split to extreme)
                        self.maximize_window_split(SplitDirection::Vertical);
                    }
                    _ => {
                        // Also handle by key_name for special keys
                        match key_name {
                            "Left" => self.focus_window_direction(SplitDirection::Vertical, false),
                            "Down" => self.focus_window_direction(SplitDirection::Horizontal, true),
                            "Up" => self.focus_window_direction(SplitDirection::Horizontal, false),
                            "Right" => self.focus_window_direction(SplitDirection::Vertical, true),
                            _ => {}
                        }
                    }
                }
            }
            'm' => {
                // Set mark: m{a-z} (local) or m{A-Z} (global)
                if let Some(ch) = unicode {
                    if ch.is_ascii_lowercase() {
                        let buffer_id = self.active_window().buffer_id;
                        let cursor = self.view().cursor;
                        self.marks.entry(buffer_id).or_default().insert(ch, cursor);
                        self.message = format!("Mark '{}' set", ch);
                    } else if ch.is_ascii_uppercase() {
                        let file = self.active_buffer_state().file_path.clone();
                        let line = self.view().cursor.line;
                        let col = self.view().cursor.col;
                        self.global_marks.insert(ch, (file, line, col));
                        self.message = format!("Mark '{}' set", ch);
                    } else {
                        self.message = "Marks must be a letter (a-z or A-Z)".to_string();
                    }
                }
            }
            '\'' => {
                // Jump to mark line: '{a-z|A-Z|'|.|<|>}
                if let Some(ch) = unicode {
                    match ch {
                        '\'' => {
                            // '' jump to position before last jump
                            if let Some((line, _)) = self.last_jump_pos {
                                let max_line = self.buffer().len_lines().saturating_sub(1);
                                self.view_mut().cursor.line = line.min(max_line);
                                self.view_mut().cursor.col = 0;
                                self.clamp_cursor_col();
                            } else {
                                self.message = "No previous jump position".to_string();
                            }
                        }
                        '.' => {
                            // '. jump to last edit position
                            if let Some((line, _)) = self.last_edit_pos {
                                let max_line = self.buffer().len_lines().saturating_sub(1);
                                self.view_mut().cursor.line = line.min(max_line);
                                self.view_mut().cursor.col = 0;
                                self.clamp_cursor_col();
                            } else {
                                self.message = "No previous edit position".to_string();
                            }
                        }
                        '<' => {
                            // '< jump to start of last visual selection
                            if let Some((line, _)) = self.visual_mark_start {
                                let max_line = self.buffer().len_lines().saturating_sub(1);
                                self.view_mut().cursor.line = line.min(max_line);
                                self.view_mut().cursor.col = 0;
                                self.clamp_cursor_col();
                            } else {
                                self.message = "No previous visual selection".to_string();
                            }
                        }
                        '>' => {
                            // '> jump to end of last visual selection
                            if let Some((line, _)) = self.visual_mark_end {
                                let max_line = self.buffer().len_lines().saturating_sub(1);
                                self.view_mut().cursor.line = line.min(max_line);
                                self.view_mut().cursor.col = 0;
                                self.clamp_cursor_col();
                            } else {
                                self.message = "No previous visual selection".to_string();
                            }
                        }
                        _ if ch.is_ascii_lowercase() => {
                            let buffer_id = self.active_window().buffer_id;
                            if let Some(buffer_marks) = self.marks.get(&buffer_id) {
                                if let Some(mark_cursor) = buffer_marks.get(&ch) {
                                    self.view_mut().cursor.line = mark_cursor.line;
                                    self.view_mut().cursor.col = 0;
                                    self.clamp_cursor_col();
                                } else {
                                    self.message = format!("Mark '{}' not set", ch);
                                }
                            } else {
                                self.message = format!("Mark '{}' not set", ch);
                            }
                        }
                        _ if ch.is_ascii_uppercase() => {
                            if let Some(&(_, line, _)) = self.global_marks.get(&ch) {
                                let max_line = self.buffer().len_lines().saturating_sub(1);
                                self.view_mut().cursor.line = line.min(max_line);
                                self.view_mut().cursor.col = 0;
                                self.clamp_cursor_col();
                            } else {
                                self.message = format!("Mark '{}' not set", ch);
                            }
                        }
                        _ => {
                            self.message = "Marks must be a letter or special char".to_string();
                        }
                    }
                }
            }
            '`' => {
                // Jump to exact mark position: `{a-z|A-Z|`|.|<|>}
                if let Some(ch) = unicode {
                    match ch {
                        '`' => {
                            // `` jump to exact position before last jump
                            if let Some((line, col)) = self.last_jump_pos {
                                let max_line = self.buffer().len_lines().saturating_sub(1);
                                self.view_mut().cursor.line = line.min(max_line);
                                self.view_mut().cursor.col = col;
                                self.clamp_cursor_col();
                            } else {
                                self.message = "No previous jump position".to_string();
                            }
                        }
                        '.' => {
                            if let Some((line, col)) = self.last_edit_pos {
                                let max_line = self.buffer().len_lines().saturating_sub(1);
                                self.view_mut().cursor.line = line.min(max_line);
                                self.view_mut().cursor.col = col;
                                self.clamp_cursor_col();
                            } else {
                                self.message = "No previous edit position".to_string();
                            }
                        }
                        '<' => {
                            if let Some((line, col)) = self.visual_mark_start {
                                let max_line = self.buffer().len_lines().saturating_sub(1);
                                self.view_mut().cursor.line = line.min(max_line);
                                self.view_mut().cursor.col = col;
                                self.clamp_cursor_col();
                            } else {
                                self.message = "No previous visual selection".to_string();
                            }
                        }
                        '>' => {
                            if let Some((line, col)) = self.visual_mark_end {
                                let max_line = self.buffer().len_lines().saturating_sub(1);
                                self.view_mut().cursor.line = line.min(max_line);
                                self.view_mut().cursor.col = col;
                                self.clamp_cursor_col();
                            } else {
                                self.message = "No previous visual selection".to_string();
                            }
                        }
                        _ if ch.is_ascii_lowercase() => {
                            let buffer_id = self.active_window().buffer_id;
                            if let Some(buffer_marks) = self.marks.get(&buffer_id) {
                                if let Some(mark_cursor) = buffer_marks.get(&ch) {
                                    self.view_mut().cursor = *mark_cursor;
                                    self.clamp_cursor_col();
                                } else {
                                    self.message = format!("Mark `{}` not set", ch);
                                }
                            } else {
                                self.message = format!("Mark `{}` not set", ch);
                            }
                        }
                        _ if ch.is_ascii_uppercase() => {
                            if let Some(&(_, line, col)) = self.global_marks.get(&ch) {
                                let max_line = self.buffer().len_lines().saturating_sub(1);
                                self.view_mut().cursor.line = line.min(max_line);
                                self.view_mut().cursor.col = col;
                                self.clamp_cursor_col();
                            } else {
                                self.message = format!("Mark `{}` not set", ch);
                            }
                        }
                        _ => {
                            self.message = "Marks must be a letter or special char".to_string();
                        }
                    }
                }
            }
            'z' => {
                // Scroll position + fold commands
                match unicode {
                    // Scroll: cursor position
                    Some('z') => self.scroll_cursor_center(),
                    Some('t') => self.scroll_cursor_top(),
                    Some('b') => self.scroll_cursor_bottom(),
                    // Scroll + first non-blank
                    Some('.') => self.scroll_cursor_center_first_nonblank(),
                    Some('-') => self.scroll_cursor_bottom_first_nonblank(),
                    // Horizontal scroll
                    Some('h') => {
                        let count = self.take_count();
                        self.scroll_left_by(count);
                    }
                    Some('l') => {
                        let count = self.take_count();
                        self.scroll_right_by(count);
                    }
                    Some('H') => self.scroll_left_half_screen(),
                    Some('L') => self.scroll_right_half_screen(),
                    // Fold: basic
                    Some('a') => self.cmd_fold_toggle(),
                    Some('o') => self.cmd_fold_open(),
                    Some('c') => self.cmd_fold_close(),
                    Some('R') => self.view_mut().open_all_folds(),
                    Some('M') => self.cmd_fold_close_all(),
                    // Fold: recursive
                    Some('A') => self.cmd_fold_toggle_recursive(),
                    Some('O') => self.cmd_fold_open_recursive(),
                    Some('C') => self.cmd_fold_close_recursive(),
                    // Fold: delete
                    Some('d') => self.cmd_fold_delete(),
                    Some('D') => self.cmd_fold_delete_recursive(),
                    // Fold: create (zf{motion})
                    Some('f') => {
                        self.pending_operator = Some('Z');
                    }
                    Some('F') => {
                        // zF: create fold for N lines from cursor
                        let count = self.take_count();
                        let line = self.view().cursor.line;
                        let total = self.buffer().len_lines();
                        let end = (line + count).min(total.saturating_sub(1));
                        if end > line {
                            self.cmd_fold_create(line, end);
                        }
                    }
                    // Fold: utilities
                    Some('v') => self.cmd_fold_open_cursor_visible(),
                    Some('x') => self.cmd_fold_recompute(),
                    // Fold: navigation
                    Some('j') => self.cmd_fold_move_next(),
                    Some('k') => self.cmd_fold_move_prev(),
                    _ => {
                        // z<CR> — scroll cursor to top + first non-blank
                        if key_name == "Return" {
                            self.scroll_cursor_top_first_nonblank();
                        }
                    }
                }
            }
            _ => {}
        }
        // Try plugin normal-mode keymaps as a fallback
        self.plugin_run_keymap("n", key_name);
        EngineAction::None
    }

    fn handle_operator_motion(
        &mut self,
        operator: char,
        _key_name: &str,
        unicode: Option<char>,
        changed: &mut bool,
    ) -> EngineAction {
        // Handle 'Z' sentinel for zf{motion} — fold creation operator.
        if operator == 'Z' {
            let cursor_line = self.view().cursor.line;
            let total = self.buffer().len_lines();
            let target = match unicode {
                Some('j') => {
                    let count = self.take_count();
                    Some((cursor_line + count).min(total.saturating_sub(1)))
                }
                Some('k') => {
                    let count = self.take_count();
                    Some(cursor_line.saturating_sub(count))
                }
                Some('G') => {
                    let count = self.count.take();
                    Some(
                        count
                            .map(|n| n.saturating_sub(1).min(total.saturating_sub(1)))
                            .unwrap_or_else(|| total.saturating_sub(1)),
                    )
                }
                Some('}') => {
                    let count = self.take_count();
                    let saved = self.view().cursor;
                    for _ in 0..count {
                        self.move_paragraph_forward();
                    }
                    let target = self.view().cursor.line;
                    self.view_mut().cursor = saved;
                    Some(target)
                }
                Some('{') => {
                    let count = self.take_count();
                    let saved = self.view().cursor;
                    for _ in 0..count {
                        self.move_paragraph_backward();
                    }
                    let target = self.view().cursor.line;
                    self.view_mut().cursor = saved;
                    Some(target)
                }
                Some('g') => {
                    // zfg -> wait for 'g' to complete (zfgg)
                    self.pending_key = Some('g');
                    self.pending_operator = Some('Z');
                    return EngineAction::None;
                }
                _ => None,
            };
            if let Some(target_line) = target {
                let start = cursor_line.min(target_line);
                let end = cursor_line.max(target_line);
                if end > start {
                    self.cmd_fold_create(start, end);
                }
            }
            return EngineAction::None;
        }

        // Handle 'g' motion for operator + g{x} (cgn/dgn, dgg, dge, etc.)
        if unicode == Some('g') {
            // Re-set pending_key = 'g' and pending_operator = operator so next key
            // is handled by handle_pending_key('g') which checks pending_operator.
            self.pending_key = Some('g');
            self.pending_operator = Some(operator);
            return EngineAction::None;
        }

        // Handle case-transform operators (~=toggle, u=lower, U=upper)
        if operator == '~' || operator == 'u' || operator == 'U' {
            // Doubled operator (g~~, guu, gUU) = apply to current line
            let is_doubled = match operator {
                '~' => unicode == Some('~'),
                'u' => unicode == Some('u'),
                'U' => unicode == Some('U'),
                _ => false,
            };
            if is_doubled {
                let count = self.take_count();
                let line = self.view().cursor.line;
                let num_lines = self.buffer().len_lines();
                for i in 0..count {
                    let ln = line + i;
                    if ln >= num_lines {
                        break;
                    }
                    let line_start = self.buffer().line_to_char(ln);
                    let line_len = self.buffer().line_len_chars(ln);
                    // Exclude trailing newline
                    let line_end = line_start
                        + if self.buffer().content.line(ln).chars().last() == Some('\n') {
                            line_len.saturating_sub(1)
                        } else {
                            line_len
                        };
                    if line_start < line_end {
                        self.apply_case_range(line_start, line_end, operator, changed);
                    }
                }
            } else if unicode == Some('i') || unicode == Some('a') {
                // Text object: g~iw, guaw, etc.
                self.pending_text_object = unicode;
                self.pending_operator = Some(operator);
            } else if unicode == Some('f')
                || unicode == Some('t')
                || unicode == Some('F')
                || unicode == Some('T')
            {
                self.pending_find_operator = Some((operator, unicode.unwrap()));
            } else if unicode.is_some() {
                // Fall through to common motion dispatch below
            } else {
                self.count = None; // Cancel
                return EngineAction::None;
            }
            if is_doubled
                || unicode == Some('i')
                || unicode == Some('a')
                || unicode == Some('f')
                || unicode == Some('t')
                || unicode == Some('F')
                || unicode == Some('T')
            {
                return EngineAction::None;
            }
            // Fall through to the common motion match block below
        }

        // Handle indent/dedent operators (>> and <<)
        if operator == '>' || operator == '<' {
            let is_doubled = (operator == '>' && unicode == Some('>'))
                || (operator == '<' && unicode == Some('<'));
            if is_doubled {
                let count = self.take_count();
                let line = self.view().cursor.line;
                if operator == '>' {
                    self.indent_lines(line, count, changed);
                    self.last_change = Some(Change {
                        op: ChangeOp::Indent,
                        text: String::new(),
                        count,
                        motion: None,
                    });
                } else {
                    self.dedent_lines(line, count, changed);
                    self.last_change = Some(Change {
                        op: ChangeOp::Dedent,
                        text: String::new(),
                        count,
                        motion: None,
                    });
                }
                return EngineAction::None;
            }
            if unicode == Some('i') || unicode == Some('a') {
                self.pending_text_object = unicode;
                self.pending_operator = Some(operator);
                return EngineAction::None;
            }
            if unicode == Some('f')
                || unicode == Some('t')
                || unicode == Some('F')
                || unicode == Some('T')
            {
                self.pending_find_operator = Some((operator, unicode.unwrap()));
                return EngineAction::None;
            }
            // Fall through to common motion match block below
        }

        // Handle auto-indent operator (=)
        if operator == '=' {
            if unicode == Some('=') {
                let count = self.take_count();
                let line = self.view().cursor.line;
                self.auto_indent_lines(line, count, changed);
                return EngineAction::None;
            }
            if unicode == Some('i') || unicode == Some('a') {
                self.pending_text_object = unicode;
                self.pending_operator = Some(operator);
                return EngineAction::None;
            }
            if unicode == Some('f')
                || unicode == Some('t')
                || unicode == Some('F')
                || unicode == Some('T')
            {
                self.pending_find_operator = Some((operator, unicode.unwrap()));
                return EngineAction::None;
            }
            // Fall through to common motion match block below
        }

        // Check if we're waiting for a text object type (after 'i' or 'a')
        if let Some(modifier) = self.pending_text_object.take() {
            if let Some(obj_type) = unicode {
                self.apply_operator_text_object(operator, modifier, obj_type, changed);
            }
            return EngineAction::None;
        }

        // Check if the next character is a text object modifier ('i' or 'a')
        if unicode == Some('i') || unicode == Some('a') {
            self.pending_text_object = unicode;
            self.pending_operator = Some(operator); // Put the operator back!
            return EngineAction::None;
        }

        // Handle operator + motion combinations (dw, cw, db, cb, de, ce, etc.)
        match unicode {
            Some('y') if operator == 'y' => {
                // yy: yank current line(s)
                let count = self.take_count();
                self.yank_lines(count);
            }
            Some('d') if operator == 'd' => {
                // dd: delete line
                let count = self.take_count();
                self.start_undo_group();
                self.delete_lines(count, changed);
                self.finish_undo_group();

                // Record for repeat
                self.last_change = Some(Change {
                    op: ChangeOp::Delete,
                    text: String::new(),
                    count,
                    motion: Some(Motion::DeleteLine),
                });
            }
            Some('c') if operator == 'c' => {
                // cc: change line (like S)
                let count = self.take_count();
                let start_line = self.view().cursor.line;

                self.start_undo_group();

                // Delete content of lines
                for i in 0..count {
                    let line_idx = start_line + i;
                    if line_idx >= self.buffer().len_lines() {
                        break;
                    }

                    let line_start = self.buffer().line_to_char(line_idx);
                    let line_len = self.buffer().line_len_chars(line_idx);
                    let line_content = self.buffer().content.line(line_idx);

                    let delete_end = if line_content.chars().last() == Some('\n') && line_len > 0 {
                        line_start + line_len - 1
                    } else {
                        line_start + line_len
                    };

                    if line_start < delete_end {
                        let deleted: String = self
                            .buffer()
                            .content
                            .slice(line_start..delete_end)
                            .chars()
                            .collect();
                        let reg = self.active_register();
                        self.set_register(reg, deleted, false);
                        self.clear_selected_register();

                        self.delete_with_undo(line_start, delete_end);
                        *changed = true;
                        break;
                    }
                }

                self.view_mut().cursor.col = 0;
                self.insert_text_buffer.clear();
                self.mode = Mode::Insert;
                self.count = None;
            }
            Some('w') => {
                // dw/cw: delete/change to start of next word
                // Special case: cw behaves like ce (Vim compatibility)
                let count = self.take_count();
                if operator == 'c' {
                    self.apply_operator_with_motion(operator, 'e', count, changed);
                } else {
                    self.apply_operator_with_motion(operator, 'w', count, changed);
                }
            }
            Some('W') => {
                // dW/cW: delete/change WORD forward
                let count = self.take_count();
                let start_cursor = self.view().cursor;
                let start_pos = self.buffer().line_to_char(start_cursor.line) + start_cursor.col;
                if operator == 'c' {
                    // cW behaves like cE (Vim compat)
                    for _ in 0..count {
                        self.move_bigword_end();
                    }
                } else {
                    for _ in 0..count {
                        self.move_bigword_forward();
                    }
                }
                let end_cursor = self.view().cursor;
                let mut end_pos = self.buffer().line_to_char(end_cursor.line) + end_cursor.col;
                self.view_mut().cursor = start_cursor;
                // For cW (treated as cE), include the character under cursor
                if operator == 'c' {
                    end_pos = (end_pos + 1).min(self.buffer().len_chars());
                }
                // Clamp at line boundary for forward W (like w)
                if operator != 'c' && end_cursor.line > start_cursor.line {
                    let line_char_start = self.buffer().line_to_char(start_cursor.line);
                    let line_len = self.buffer().line_len_chars(start_cursor.line);
                    let has_nl =
                        self.buffer().content.line(start_cursor.line).chars().last() == Some('\n');
                    end_pos = if has_nl {
                        (line_char_start + line_len - 1).min(end_pos)
                    } else {
                        (line_char_start + line_len).min(end_pos)
                    };
                }
                if start_pos < end_pos {
                    self.apply_charwise_operator(operator, start_pos, end_pos, changed);
                }
            }
            Some('B') => {
                // dB: delete WORD backward
                let count = self.take_count();
                let start_cursor = self.view().cursor;
                let start_pos = self.buffer().line_to_char(start_cursor.line) + start_cursor.col;
                for _ in 0..count {
                    self.move_bigword_backward();
                }
                let end_pos =
                    self.buffer().line_to_char(self.view().cursor.line) + self.view().cursor.col;
                if end_pos < start_pos {
                    self.apply_charwise_operator(operator, end_pos, start_pos, changed);
                }
            }
            Some('E') => {
                // dE: delete to end of WORD
                let count = self.take_count();
                let start_cursor = self.view().cursor;
                let start_pos = self.buffer().line_to_char(start_cursor.line) + start_cursor.col;
                for _ in 0..count {
                    self.move_bigword_end();
                }
                let end_pos =
                    self.buffer().line_to_char(self.view().cursor.line) + self.view().cursor.col;
                self.view_mut().cursor = start_cursor;
                if end_pos >= start_pos {
                    let end = (end_pos + 1).min(self.buffer().len_chars());
                    self.apply_charwise_operator(operator, start_pos, end, changed);
                }
            }
            Some('b') => {
                // db/cb: delete/change back to start of word
                let count = self.take_count();
                self.apply_operator_with_motion(operator, 'b', count, changed);
            }
            Some('e') => {
                // de/ce: delete/change to end of word
                let count = self.take_count();
                self.apply_operator_with_motion(operator, 'e', count, changed);
            }
            Some('%') => {
                // d%/c%: delete/change to matching bracket
                self.apply_operator_bracket_motion(operator, changed);
            }
            Some('$') => {
                // y$/d$/c$: to end of current line (does not include the newline)
                let _ = self.take_count(); // count ignored for simplicity (same as D/C)
                let line = self.view().cursor.line;
                let col = self.view().cursor.col;
                let line_char_start = self.buffer().line_to_char(line);
                let line_len = self.buffer().line_len_chars(line);
                let has_newline = self.buffer().content.line(line).chars().last() == Some('\n');
                let line_end = if has_newline {
                    line_char_start + line_len - 1
                } else {
                    line_char_start + line_len
                };
                let start_pos = line_char_start + col;
                if start_pos >= line_end {
                    return EngineAction::None;
                }
                self.apply_charwise_operator(operator, start_pos, line_end, changed);
            }
            Some('0') => {
                // y0/d0: from start of line to (not including) cursor
                let _ = self.take_count();
                let line = self.view().cursor.line;
                let col = self.view().cursor.col;
                if col == 0 {
                    return EngineAction::None;
                }
                let line_char_start = self.buffer().line_to_char(line);
                self.view_mut().cursor.col = 0;
                self.apply_charwise_operator(
                    operator,
                    line_char_start,
                    line_char_start + col,
                    changed,
                );
            }
            Some('^') => {
                // d^: delete to first non-blank char
                let _ = self.take_count();
                let line = self.view().cursor.line;
                let col = self.view().cursor.col;
                let target = self.first_non_blank_col(line);
                if col == target {
                    return EngineAction::None;
                }
                let line_char_start = self.buffer().line_to_char(line);
                let (start, end) = if col > target {
                    (line_char_start + target, line_char_start + col)
                } else {
                    (line_char_start + col, line_char_start + target)
                };
                self.view_mut().cursor.col = target.min(col);
                self.apply_charwise_operator(operator, start, end, changed);
            }
            Some('h') => {
                // dh: delete count chars to the left
                let count = self.take_count();
                let line = self.view().cursor.line;
                let col = self.view().cursor.col;
                let chars_to_delete = count.min(col);
                if chars_to_delete == 0 {
                    return EngineAction::None;
                }
                let line_char_start = self.buffer().line_to_char(line);
                let start = line_char_start + col - chars_to_delete;
                let end = line_char_start + col;
                self.view_mut().cursor.col = col - chars_to_delete;
                self.apply_charwise_operator(operator, start, end, changed);
            }
            Some('l') => {
                // dl: delete count chars to the right
                let count = self.take_count();
                let line = self.view().cursor.line;
                let col = self.view().cursor.col;
                let line_len = self.buffer().line_len_chars(line);
                let has_nl = self.buffer().content.line(line).chars().last() == Some('\n');
                let max_col = if has_nl {
                    line_len.saturating_sub(1)
                } else {
                    line_len
                };
                let chars_to_delete = count.min(max_col.saturating_sub(col));
                if chars_to_delete == 0 {
                    return EngineAction::None;
                }
                let line_char_start = self.buffer().line_to_char(line);
                let start = line_char_start + col;
                let end = line_char_start + col + chars_to_delete;
                self.apply_charwise_operator(operator, start, end, changed);
            }
            Some('j') => {
                // dj: delete current line + count lines below (linewise)
                let count = self.take_count();
                let current_line = self.view().cursor.line;
                let last_line = self.buffer().len_lines().saturating_sub(1);
                let end_line = (current_line + count).min(last_line);
                self.apply_linewise_operator(operator, current_line, end_line, changed);
            }
            Some('k') => {
                // dk: delete current line + count lines above (linewise)
                let count = self.take_count();
                let current_line = self.view().cursor.line;
                let start_line = current_line.saturating_sub(count);
                self.apply_linewise_operator(operator, start_line, current_line, changed);
            }
            Some('G') => {
                // dG: delete from current line to end (or to line N if count given)
                let count = self.count.take();
                let current_line = self.view().cursor.line;
                let target_line = count
                    .map(|n| {
                        n.saturating_sub(1)
                            .min(self.buffer().len_lines().saturating_sub(1))
                    })
                    .unwrap_or_else(|| self.buffer().len_lines().saturating_sub(1));
                let (start, end) = if target_line >= current_line {
                    (current_line, target_line)
                } else {
                    (target_line, current_line)
                };
                self.apply_linewise_operator(operator, start, end, changed);
            }
            Some('{') => {
                // d{: delete from current line backward to previous blank line (linewise)
                let count = self.take_count();
                let start_line = self.view().cursor.line;
                for _ in 0..count {
                    self.move_paragraph_backward();
                }
                let end_line = self.view().cursor.line;
                let (s, e) = if end_line <= start_line {
                    (end_line, start_line)
                } else {
                    (start_line, end_line)
                };
                self.apply_linewise_operator(operator, s, e, changed);
            }
            Some('}') => {
                // d}: delete from current line forward to next blank line (linewise)
                let count = self.take_count();
                let start_line = self.view().cursor.line;
                for _ in 0..count {
                    self.move_paragraph_forward();
                }
                let end_line = self.view().cursor.line;
                let (s, e) = if start_line <= end_line {
                    (start_line, end_line)
                } else {
                    (end_line, start_line)
                };
                self.apply_linewise_operator(operator, s, e, changed);
            }
            Some('(') => {
                // d(: delete to previous sentence start (charwise)
                let count = self.take_count();
                let start_pos =
                    self.buffer().line_to_char(self.view().cursor.line) + self.view().cursor.col;
                for _ in 0..count {
                    self.move_sentence_backward();
                }
                let end_pos =
                    self.buffer().line_to_char(self.view().cursor.line) + self.view().cursor.col;
                if end_pos < start_pos {
                    self.apply_charwise_operator(operator, end_pos, start_pos, changed);
                }
            }
            Some(')') => {
                // d): delete to next sentence start (charwise)
                let count = self.take_count();
                let start_pos =
                    self.buffer().line_to_char(self.view().cursor.line) + self.view().cursor.col;
                for _ in 0..count {
                    self.move_sentence_forward();
                }
                let end_pos =
                    self.buffer().line_to_char(self.view().cursor.line) + self.view().cursor.col;
                if end_pos > start_pos {
                    self.view_mut().cursor.col = start_pos
                        - self
                            .buffer()
                            .line_to_char(self.buffer().content.char_to_line(start_pos));
                    self.view_mut().cursor.line = self.buffer().content.char_to_line(start_pos);
                    self.apply_charwise_operator(operator, start_pos, end_pos, changed);
                }
            }
            Some('H') => {
                // dH: delete from current line to top of screen (linewise)
                let _ = self.take_count();
                let current_line = self.view().cursor.line;
                let top = self.view().scroll_top;
                let (s, e) = if top <= current_line {
                    (top, current_line)
                } else {
                    (current_line, top)
                };
                self.apply_linewise_operator(operator, s, e, changed);
            }
            Some('M') => {
                // dM: delete from current line to middle of screen (linewise)
                let _ = self.take_count();
                let current_line = self.view().cursor.line;
                let viewport_lines = self.view().viewport_lines.max(1);
                let mid = self.view().scroll_top + viewport_lines / 2;
                let mid = mid.min(self.buffer().len_lines().saturating_sub(1));
                let (s, e) = if mid <= current_line {
                    (mid, current_line)
                } else {
                    (current_line, mid)
                };
                self.apply_linewise_operator(operator, s, e, changed);
            }
            Some('L') => {
                // dL: delete from current line to bottom of screen (linewise)
                let _ = self.take_count();
                let current_line = self.view().cursor.line;
                let viewport_lines = self.view().viewport_lines.max(1);
                let bot = (self.view().scroll_top + viewport_lines).saturating_sub(1);
                let bot = bot.min(self.buffer().len_lines().saturating_sub(1));
                let (s, e) = if bot >= current_line {
                    (current_line, bot)
                } else {
                    (bot, current_line)
                };
                self.apply_linewise_operator(operator, s, e, changed);
            }
            Some('+') => {
                // d+: delete from current line through N lines down (linewise)
                let count = self.take_count();
                let current_line = self.view().cursor.line;
                let last_line = self.buffer().len_lines().saturating_sub(1);
                let end_line = (current_line + count).min(last_line);
                self.apply_linewise_operator(operator, current_line, end_line, changed);
            }
            Some('-') => {
                // d-: delete from current line through N lines up (linewise)
                let count = self.take_count();
                let current_line = self.view().cursor.line;
                let start_line = current_line.saturating_sub(count);
                self.apply_linewise_operator(operator, start_line, current_line, changed);
            }
            Some('_') => {
                // d_: delete from current line through N-1 lines down (linewise)
                let count = self.take_count();
                let current_line = self.view().cursor.line;
                let last_line = self.buffer().len_lines().saturating_sub(1);
                let end_line = (current_line + count - 1).min(last_line);
                self.apply_linewise_operator(operator, current_line, end_line, changed);
            }
            Some('|') => {
                // d|: delete from cursor to column N (charwise)
                let count = self.take_count();
                let target_col = count.saturating_sub(1);
                let line = self.view().cursor.line;
                let col = self.view().cursor.col;
                let max_col = self.get_max_cursor_col(line);
                let target = target_col.min(max_col);
                if target != col {
                    let line_start = self.buffer().line_to_char(line);
                    let (start, end) = if col > target {
                        (line_start + target, line_start + col)
                    } else {
                        (line_start + col, line_start + target)
                    };
                    self.view_mut().cursor.col = target.min(col);
                    self.apply_charwise_operator(operator, start, end, changed);
                }
            }
            Some(';') => {
                // d;: delete to next find repeat
                if let Some((find_type, target)) = self.last_find {
                    self.apply_operator_find_char(operator, find_type, target, changed);
                }
            }
            Some(',') => {
                // d,: delete to previous find repeat (reverse direction)
                if let Some((find_type, target)) = self.last_find {
                    let reversed = match find_type {
                        'f' => 'F',
                        'F' => 'f',
                        't' => 'T',
                        'T' => 't',
                        _ => find_type,
                    };
                    self.apply_operator_find_char(operator, reversed, target, changed);
                }
            }
            Some('f') | Some('t') | Some('F') | Some('T') => {
                // Deferred: need one more keystroke for the target char
                self.pending_find_operator = Some((operator, unicode.unwrap()));
            }
            _ => {
                // Invalid motion - cancel operator
                self.count = None;
            }
        }
        EngineAction::None
    }

    /// Apply a case transform (toggle/lower/upper) over a char range in the buffer.
    fn apply_case_range(&mut self, start: usize, end: usize, op: char, changed: &mut bool) {
        if start >= end {
            return;
        }
        let original: String = self.buffer().content.slice(start..end).chars().collect();
        let transformed: String = original
            .chars()
            .map(|c| match op {
                '~' => {
                    if c.is_uppercase() {
                        c.to_lowercase().next().unwrap_or(c)
                    } else if c.is_lowercase() {
                        c.to_uppercase().next().unwrap_or(c)
                    } else {
                        c
                    }
                }
                'u' => c.to_lowercase().next().unwrap_or(c),
                'U' => c.to_uppercase().next().unwrap_or(c),
                _ => c,
            })
            .collect();
        if transformed != original {
            self.start_undo_group();
            self.delete_with_undo(start, end);
            self.insert_with_undo(start, &transformed);
            self.finish_undo_group();
            *changed = true;
        }
    }

    /// Apply a charwise operator on a byte/char range [start..end).
    fn apply_charwise_operator(
        &mut self,
        operator: char,
        start: usize,
        end: usize,
        changed: &mut bool,
    ) {
        if start >= end {
            return;
        }
        match operator {
            'y' => {
                let text: String = self.buffer().content.slice(start..end).chars().collect();
                let reg = self.active_register();
                self.set_yank_register(reg, text.clone(), false);
                self.clear_selected_register();
                // Record yank highlight
                let start_line = self.buffer().content.char_to_line(start);
                let start_line_char = self.buffer().line_to_char(start_line);
                let start_col = start - start_line_char;
                let end_char = end.saturating_sub(1).max(start);
                let end_line = self.buffer().content.char_to_line(end_char);
                let end_line_char = self.buffer().line_to_char(end_line);
                let end_col = end_char - end_line_char;
                self.record_yank_highlight(
                    Cursor {
                        line: start_line,
                        col: start_col,
                    },
                    Cursor {
                        line: end_line,
                        col: end_col,
                    },
                    false,
                );
            }
            'd' => {
                let text: String = self.buffer().content.slice(start..end).chars().collect();
                let reg = self.active_register();
                self.set_delete_register(reg, text, false);
                self.clear_selected_register();
                self.start_undo_group();
                self.delete_with_undo(start, end);
                self.clamp_cursor_col();
                self.finish_undo_group();
                *changed = true;
            }
            'c' => {
                let text: String = self.buffer().content.slice(start..end).chars().collect();
                let reg = self.active_register();
                self.set_delete_register(reg, text, false);
                self.clear_selected_register();
                self.start_undo_group();
                self.delete_with_undo(start, end);
                self.clamp_cursor_col_insert();
                self.mode = Mode::Insert;
                self.insert_text_buffer.clear();
                self.count = None;
                *changed = true;
            }
            '~' | 'u' | 'U' => {
                self.apply_case_range(start, end, operator, changed);
            }
            '>' | '<' | '=' => {
                // Indent/dedent/auto-indent: operate on full lines containing the range
                let start_line = self.buffer().content.char_to_line(start);
                let end_line = self
                    .buffer()
                    .content
                    .char_to_line(end.saturating_sub(1).max(start));
                let count = end_line - start_line + 1;
                if operator == '>' {
                    self.indent_lines(start_line, count, changed);
                } else if operator == '<' {
                    self.dedent_lines(start_line, count, changed);
                } else {
                    self.auto_indent_lines(start_line, count, changed);
                }
            }
            _ => {}
        }
    }

    /// Apply a linewise operator on a range of lines [start_line..=end_line].
    fn apply_linewise_operator(
        &mut self,
        operator: char,
        start_line: usize,
        end_line: usize,
        changed: &mut bool,
    ) {
        if start_line > end_line {
            return;
        }
        let count = end_line - start_line + 1;
        self.view_mut().cursor.line = start_line;
        self.view_mut().cursor.col = 0;
        match operator {
            'y' => {
                self.yank_lines(count);
            }
            'd' => {
                self.start_undo_group();
                self.delete_lines(count, changed);
                self.finish_undo_group();
            }
            'c' => {
                // Delete lines content, enter insert mode (like cc on range)
                self.start_undo_group();
                // Delete the remaining lines below (count - 1)
                if count > 1 {
                    let next_line = start_line + 1;
                    let next_start = self.buffer().line_to_char(next_line);
                    let last_line = (start_line + count).min(self.buffer().len_lines());
                    let last_end = self.buffer().line_to_char(last_line);
                    if next_start < last_end {
                        let deleted: String = self
                            .buffer()
                            .content
                            .slice(next_start..last_end)
                            .chars()
                            .collect();
                        let reg = self.active_register();
                        self.set_delete_register(reg, deleted, true);
                        self.clear_selected_register();
                        self.delete_with_undo(next_start, last_end);
                    }
                }
                // Clear first line content
                let first_line_start = self.buffer().line_to_char(start_line);
                let first_line_len = self.buffer().line_len_chars(start_line);
                let first_has_nl =
                    self.buffer().content.line(start_line).chars().last() == Some('\n');
                let first_end = if first_has_nl && first_line_len > 0 {
                    first_line_start + first_line_len - 1
                } else {
                    first_line_start + first_line_len
                };
                if first_line_start < first_end {
                    self.delete_with_undo(first_line_start, first_end);
                }
                self.view_mut().cursor.col = 0;
                self.mode = Mode::Insert;
                self.insert_text_buffer.clear();
                self.count = None;
                *changed = true;
            }
            '>' => {
                self.indent_lines(start_line, count, changed);
            }
            '<' => {
                self.dedent_lines(start_line, count, changed);
            }
            '=' => {
                self.auto_indent_lines(start_line, count, changed);
            }
            '~' | 'u' | 'U' => {
                let start = self.buffer().line_to_char(start_line);
                let end = self
                    .buffer()
                    .line_to_char((end_line + 1).min(self.buffer().len_lines()));
                self.apply_case_range(start, end, operator, changed);
            }
            _ => {}
        }
    }

    /// Apply an operator with a find-char motion (dfx, dtx, dFx, dTx).
    fn apply_operator_find_char(
        &mut self,
        operator: char,
        find_type: char,
        target: char,
        changed: &mut bool,
    ) {
        let start_col = self.view().cursor.col;
        let line = self.view().cursor.line;
        let line_start = self.buffer().line_to_char(line);

        // Execute the find motion
        self.find_char(find_type, target);
        self.last_find = Some((find_type, target));

        let end_col = self.view().cursor.col;
        if end_col == start_col {
            return; // find_char didn't move — no match found
        }

        // Calculate range
        let (range_start, range_end) = if find_type == 'f' || find_type == 't' {
            // Forward: start_col..=end_col (inclusive of end for operators)
            (line_start + start_col, line_start + end_col + 1)
        } else {
            // Backward (F/T): end_col..start_col (exclusive of start — don't delete char under cursor)
            (line_start + end_col, line_start + start_col)
        };

        // Restore cursor to start of range for charwise operations
        self.view_mut().cursor.col = if find_type == 'F' || find_type == 'T' {
            end_col
        } else {
            start_col
        };

        self.apply_charwise_operator(operator, range_start, range_end, changed);
    }

    /// gn: find next (or prev if `backward`) search match, enter Visual mode selecting it.
    /// If `op` is Some('c'), delete the match and enter Insert (cgn).
    fn cmd_gn(&mut self, op: Option<char>, backward: bool, changed: &mut bool) {
        if self.search_matches.is_empty() {
            self.message = format!("Pattern not found: {}", self.search_query);
            return;
        }
        let line = self.view().cursor.line;
        let col = self.view().cursor.col;
        let cursor_char = self.buffer().line_to_char(line) + col;

        let idx = if backward {
            self.search_matches
                .iter()
                .rposition(|(start, _)| *start < cursor_char)
                .unwrap_or(self.search_matches.len() - 1)
        } else {
            self.search_matches
                .iter()
                .position(|(start, _)| *start >= cursor_char)
                .unwrap_or(0)
        };

        let (match_start, match_end) = self.search_matches[idx];

        // Convert char positions to line/col
        let start_line = self.buffer().content.char_to_line(match_start);
        let start_line_char = self.buffer().line_to_char(start_line);
        let start_col = match_start - start_line_char;

        let end_char = match_end.saturating_sub(1).max(match_start);
        let end_line = self.buffer().content.char_to_line(end_char);
        let end_line_char = self.buffer().line_to_char(end_line);
        let end_col = end_char - end_line_char;

        if let Some(op_char) = op {
            // Operator mode: delete the match, optionally enter Insert
            self.view_mut().cursor.line = start_line;
            self.view_mut().cursor.col = start_col;
            let delete_start = match_start;
            let delete_end = match_end;
            let deleted: String = self
                .buffer()
                .content
                .slice(delete_start..delete_end)
                .chars()
                .collect();
            let reg = self.active_register();
            self.set_delete_register(reg, deleted, false);
            self.start_undo_group();
            self.delete_with_undo(delete_start, delete_end);
            *changed = true;
            if op_char == 'c' {
                self.mode = Mode::Insert;
                self.insert_text_buffer.clear();
                // Don't finish_undo_group — let insert mode do it
            } else {
                self.finish_undo_group();
                self.clamp_cursor_col();
            }
        } else {
            // Select the match in Visual mode
            self.mode = Mode::Visual;
            self.visual_anchor = Some(Cursor {
                line: start_line,
                col: start_col,
            });
            self.view_mut().cursor.line = end_line;
            self.view_mut().cursor.col = end_col;
            self.search_index = Some(idx);
        }
    }

    /// Handle a key press while leader mode is active (after pressing the leader key).
    fn handle_leader_key(&mut self, unicode: Option<char>) -> EngineAction {
        let ch = match unicode {
            Some(c) => c,
            None => {
                // Non-unicode key (e.g. arrow) — cancel leader
                self.leader_partial = None;
                return EngineAction::None;
            }
        };
        let mut partial = self.leader_partial.take().unwrap_or_default();
        partial.push(ch);

        // All known leader sequences
        const SEQUENCES: &[&str] = &["rn", "gf", "gF"];

        match partial.as_str() {
            "rn" => {
                // LSP rename — enter command mode pre-filled with :Rename <word>
                let word = self.word_under_cursor().unwrap_or_default();
                self.mode = crate::core::Mode::Command;
                self.command_buffer = format!("Rename {word}");
                self.command_cursor = self.command_buffer.chars().count();
            }
            "gf" | "gF" => {
                // LSP format whole file
                self.lsp_format_current();
            }
            // Partial match — keep accumulating if the partial is a prefix of some sequence
            s if SEQUENCES.iter().any(|seq| seq.starts_with(s)) => {
                self.leader_partial = Some(partial);
            }
            _ => {
                self.message = format!("Unknown leader sequence: <leader>{partial}");
            }
        }
        EngineAction::None
    }

    fn apply_operator_with_motion(
        &mut self,
        operator: char,
        motion: char,
        count: usize,
        changed: &mut bool,
    ) {
        // Save cursor position
        let start_cursor = self.view().cursor;
        let start_pos = self.buffer().line_to_char(start_cursor.line) + start_cursor.col;

        // Execute motion to find end position
        for _ in 0..count {
            match motion {
                'w' => self.move_word_forward(),
                'b' => self.move_word_backward(),
                'e' => self.move_word_end(),
                _ => return,
            }
        }

        let end_cursor = self.view().cursor;
        let end_pos = self.buffer().line_to_char(end_cursor.line) + end_cursor.col;

        // Restore cursor to start position
        self.view_mut().cursor = start_cursor;

        // Vim rule: 'w' operator motion does not cross line boundaries.
        // When the motion lands on the next line (col 0), clamp the end to
        // just before the newline on the start line, so dw/yw on the last word
        // of a line does not delete/yank the newline character.
        let end_pos = if motion == 'w' && end_cursor.line > start_cursor.line {
            let line = start_cursor.line;
            let line_char_start = self.buffer().line_to_char(line);
            let line_len = self.buffer().line_len_chars(line);
            let has_newline = self.buffer().content.line(line).chars().last() == Some('\n');
            if has_newline {
                (line_char_start + line_len - 1).min(end_pos) // before the \n
            } else {
                (line_char_start + line_len).min(end_pos)
            }
        } else {
            end_pos
        };

        // Determine range to delete
        let (delete_start, delete_end) = match start_pos.cmp(&end_pos) {
            std::cmp::Ordering::Less => {
                // Forward motion: delete from start to end (inclusive for 'e', exclusive for 'w')
                if motion == 'e' {
                    // 'e' moves to end of word, so include that character
                    (start_pos, (end_pos + 1).min(self.buffer().len_chars()))
                } else {
                    // 'w' moves to start of next word (exclusive end).
                    // Exception: when the file has no trailing newline and the word
                    // is the last one, move_word_forward clamps to total_chars-1
                    // (the last char) instead of going past it.  The normal range
                    // [start, end_pos) would then miss that final character.
                    // Detect this by checking that end_pos is the last char and it
                    // is not a newline (if it were '\n', the existing line-boundary
                    // clamping has already handled things correctly).
                    let total = self.buffer().len_chars();
                    let end = if end_pos + 1 == total
                        && total > 0
                        && self.buffer().content.char(end_pos) != '\n'
                    {
                        total
                    } else {
                        end_pos
                    };
                    (start_pos, end)
                }
            }
            std::cmp::Ordering::Greater => {
                // Backward motion (db): delete from end to start
                (end_pos, start_pos)
            }
            std::cmp::Ordering::Equal => {
                // No movement (e.g. single word on line, w clamps to end of word)
                return;
            }
        };

        if delete_start >= delete_end {
            return;
        }

        // For backward motion, move cursor to start of range
        if start_pos > end_pos {
            self.view_mut().cursor = end_cursor;
        }

        self.apply_charwise_operator(operator, delete_start, delete_end, changed);
    }

    fn apply_operator_bracket_motion(&mut self, operator: char, changed: &mut bool) {
        let start_line = self.view().cursor.line;
        let start_col = self.view().cursor.col;
        let start_pos = self.buffer().line_to_char(start_line) + start_col;

        if start_pos >= self.buffer().len_chars() {
            return;
        }

        let current_char = self.buffer().content.char(start_pos);

        // Find matching bracket and determine search parameters
        let (is_opening, open_char, close_char) = match current_char {
            '(' => (true, '(', ')'),
            ')' => (false, '(', ')'),
            '{' => (true, '{', '}'),
            '}' => (false, '{', '}'),
            '[' => (true, '[', ']'),
            ']' => (false, '[', ']'),
            _ => {
                // Not on a bracket - cancel operation
                return;
            }
        };

        // Find the matching bracket position
        if let Some(match_pos) =
            self.find_matching_bracket(start_pos, open_char, close_char, is_opening)
        {
            // Determine range to delete (inclusive of both brackets)
            let (delete_start, delete_end) = if is_opening {
                (start_pos, match_pos + 1)
            } else {
                (match_pos, start_pos + 1)
            };

            // Save text to register
            let text: String = self
                .buffer()
                .content
                .slice(delete_start..delete_end)
                .chars()
                .collect();
            let reg = self.active_register();
            self.set_register(reg, text, false);
            self.clear_selected_register();

            if operator == 'y' {
                // Yank only — move cursor to start of range, no deletion
                let start_line = self.buffer().content.char_to_line(delete_start);
                let start_line_char = self.buffer().line_to_char(start_line);
                let end_line = self
                    .buffer()
                    .content
                    .char_to_line((delete_end).saturating_sub(1));
                let end_line_char = self.buffer().line_to_char(end_line);
                self.view_mut().cursor.line = start_line;
                self.view_mut().cursor.col = delete_start - start_line_char;
                self.record_yank_highlight(
                    Cursor {
                        line: start_line,
                        col: delete_start - start_line_char,
                    },
                    Cursor {
                        line: end_line,
                        col: (delete_end - 1) - end_line_char,
                    },
                    false,
                );
            } else {
                // Delete or change
                self.start_undo_group();
                self.delete_with_undo(delete_start, delete_end);

                // Move cursor to start of deletion
                let new_line = self.buffer().content.char_to_line(delete_start);
                let line_start = self.buffer().line_to_char(new_line);
                self.view_mut().cursor.line = new_line;
                self.view_mut().cursor.col = delete_start - line_start;

                self.clamp_cursor_col();
                *changed = true;

                if operator == 'c' {
                    self.mode = Mode::Insert;
                    self.count = None;
                    // Don't finish_undo_group - let insert mode do it
                } else {
                    self.finish_undo_group();
                }
            }
        }
    }

    fn handle_insert_key(
        &mut self,
        key_name: &str,
        unicode: Option<char>,
        ctrl: bool,
        changed: &mut bool,
    ) {
        // ── Configured completion trigger (e.g. Ctrl-Space) ──────────────────
        {
            let trigger = self.settings.completion_keys.trigger.clone();
            if let Some((t_ctrl, _t_shift, _t_alt, t_ch)) =
                crate::core::settings::parse_key_binding(&trigger)
            {
                let key_char = key_name.chars().next().unwrap_or('\0');
                if ctrl == t_ctrl && (key_char == t_ch || (key_name == "space" && t_ch == ' ')) {
                    self.trigger_auto_completion();
                    return;
                }
            } else if ctrl && key_name == "space" {
                // Fallback for default <C-Space> trigger
                self.trigger_auto_completion();
                return;
            }
        }

        // ── Ctrl-N / Ctrl-P: word completion ─────────────────────────────────
        if ctrl && (key_name == "n" || key_name == "p") {
            let next = key_name == "n";
            if self.completion_display_only && self.completion_idx.is_some() {
                // Auto-popup is active: just cycle the index (don't insert)
                let len = self.completion_candidates.len();
                let cur = self.completion_idx.unwrap();
                let new_idx = if next {
                    (cur + 1) % len
                } else {
                    (cur + len - 1) % len
                };
                self.completion_idx = Some(new_idx);
                return;
            }
            if self.completion_idx.is_none() {
                let (prefix, start_col) = self.completion_prefix_at_cursor();
                let candidates = self.word_completions_for_prefix(&prefix);
                if candidates.is_empty() {
                    self.message = "No completions".to_string();
                    return;
                }
                self.completion_start_col = start_col;
                self.completion_candidates = candidates;
                let idx = if next {
                    0
                } else {
                    self.completion_candidates.len() - 1
                };
                self.completion_idx = Some(idx);
                self.apply_completion_candidate(idx);
            } else {
                let len = self.completion_candidates.len();
                let cur = self.completion_idx.unwrap();
                let new_idx = if next {
                    (cur + 1) % len
                } else {
                    (cur + len - 1) % len
                };
                self.completion_idx = Some(new_idx);
                self.apply_completion_candidate(new_idx);
            }
            *changed = true;
            return;
        }

        // ── AI ghost text: accept with Tab; clear on any other key ───────────
        if self.ai_ghost_text.is_some() {
            if !ctrl && key_name == "Tab" {
                self.ai_accept_ghost();
                *changed = true;
                return;
            }
            // If the typed character matches the start of the ghost text,
            // consume it rather than clearing — avoids doubled characters
            // when the AI includes a character the user just typed (e.g.
            // typing `"` when ghost starts with `"PlayerObject":`).
            if let Some(ch) = unicode {
                if !ctrl {
                    let ghost_starts_with_ch =
                        self.ai_ghost_text.as_deref().and_then(|g| g.chars().next()) == Some(ch);
                    if ghost_starts_with_ch {
                        // Advance all alternatives past this character.
                        for alt in &mut self.ai_ghost_alternatives {
                            if alt.starts_with(ch) {
                                *alt = alt[ch.len_utf8()..].to_string();
                            } else {
                                alt.clear();
                            }
                        }
                        self.ai_ghost_text = self
                            .ai_ghost_alternatives
                            .get(self.ai_ghost_alt_idx)
                            .cloned();
                        if self.ai_ghost_text.as_deref() == Some("") {
                            self.ai_ghost_clear();
                        }
                        // Fall through — let the character be inserted normally.
                    } else {
                        self.ai_ghost_clear();
                    }
                } else {
                    self.ai_ghost_clear();
                }
            } else {
                // Non-printable key (arrow, backspace, etc.) — clear ghost.
                self.ai_ghost_clear();
            }
        }

        // ── Tab: accept display-only popup OR fall through ────────────────────
        if !ctrl && key_name == "Tab" && self.completion_display_only {
            if let Some(idx) = self.completion_idx {
                self.apply_completion_candidate(idx);
                self.completion_candidates.clear();
                self.completion_idx = None;
                self.completion_display_only = false;
                *changed = true;
                return;
            }
        }
        // No display-only popup — fall through to regular Tab handling in match below.

        // ── Down/Up: navigate completion popup if active ──────────────────────
        if !ctrl
            && (key_name == "Down" || key_name == "Up")
            && self.completion_display_only
            && self.completion_idx.is_some()
        {
            let next = key_name == "Down";
            let len = self.completion_candidates.len();
            let cur = self.completion_idx.unwrap();
            let new_idx = if next {
                (cur + 1) % len
            } else {
                (cur + len - 1) % len
            };
            self.completion_idx = Some(new_idx);
            return;
        }

        // Clear completion state on any non-completion key.
        if self.completion_idx.is_some() {
            self.completion_candidates.clear();
            self.completion_idx = None;
            self.completion_display_only = false;
        }

        // Ctrl+R: insert register content at cursor
        if ctrl && key_name == "r" {
            self.insert_ctrl_r_pending = true;
            return;
        }
        // When Ctrl+R pending, next char selects the register to insert
        if self.insert_ctrl_r_pending {
            self.insert_ctrl_r_pending = false;
            if let Some(reg_char) = unicode {
                if let Some((content, _)) = self.get_register_content(reg_char) {
                    let content_clone = content.clone();
                    let line = self.view().cursor.line;
                    let col = self.view().cursor.col;
                    let char_idx = self.buffer().line_to_char(line) + col;
                    let char_count = content_clone.chars().count();
                    self.insert_with_undo(char_idx, &content_clone);
                    self.view_mut().cursor.col += char_count;
                    *changed = true;
                }
            }
            return;
        }

        // Ctrl+U: delete from cursor to start of line
        if ctrl && key_name == "u" {
            let line = self.view().cursor.line;
            let col = self.view().cursor.col;
            if col > 0 {
                let line_start = self.buffer().line_to_char(line);
                let char_idx = line_start + col;
                self.delete_with_undo(line_start, char_idx);
                self.view_mut().cursor.col = 0;
                *changed = true;
            }
            return;
        }

        // Ctrl+O: execute one normal-mode command then return to insert
        if ctrl && key_name == "o" {
            // We'll handle this via a pending state — set mode to Normal for one command
            // After one command, the next handle_key call will restore Insert mode
            // This is simplified: we just switch modes; full Ctrl+O would track return
            self.finish_undo_group();
            self.mode = Mode::Normal;
            // Note: full re-entry to insert is complex; for now mode returns to Normal.
            // The user must press i to go back to Insert. Full Ctrl+O support is deferred.
            return;
        }

        // Ctrl+W: delete word backward from cursor
        if ctrl && key_name == "w" {
            let line = self.view().cursor.line;
            let col = self.view().cursor.col;
            if col > 0 {
                // Find start of word backward
                let line_start = self.buffer().line_to_char(line);
                let char_idx = line_start + col;
                let line_text: String = self
                    .buffer()
                    .content
                    .slice(line_start..char_idx)
                    .chars()
                    .collect();
                // Skip trailing spaces, then skip non-spaces
                let chars: Vec<char> = line_text.chars().collect();
                let mut i = chars.len();
                // Skip trailing whitespace
                while i > 0 && chars[i - 1] == ' ' {
                    i -= 1;
                }
                // Skip word chars
                while i > 0 && chars[i - 1] != ' ' {
                    i -= 1;
                }
                let delete_start = line_start + i;
                let delete_end = char_idx;
                if delete_start < delete_end {
                    self.delete_with_undo(delete_start, delete_end);
                    self.view_mut().cursor.col = i;
                    *changed = true;
                }
            }
            return;
        }

        // Ctrl+T: indent current line by shiftwidth
        if ctrl && key_name == "t" {
            let line = self.view().cursor.line;
            let line_start = self.buffer().line_to_char(line);
            let sw = self.settings.shift_width as usize;
            let indent = if self.settings.expand_tab {
                " ".repeat(sw)
            } else {
                "\t".to_string()
            };
            self.insert_with_undo(line_start, &indent);
            self.view_mut().cursor.col += indent.len();
            *changed = true;
            return;
        }

        // Ctrl+E: insert character from line below cursor
        if ctrl && key_name == "e" {
            let line = self.view().cursor.line;
            let col = self.view().cursor.col;
            if line + 1 < self.buffer().len_lines() {
                let below_line = line + 1;
                let below_len = self.buffer().line_len_chars(below_line);
                let below_start = self.buffer().line_to_char(below_line);
                if col < below_len {
                    let ch = self.buffer().content.char(below_start + col);
                    if ch != '\n' {
                        let char_idx = self.buffer().line_to_char(line) + col;
                        let s = ch.to_string();
                        self.insert_with_undo(char_idx, &s);
                        self.insert_text_buffer.push_str(&s);
                        self.view_mut().cursor.col += 1;
                        *changed = true;
                    }
                }
            }
            return;
        }

        // Ctrl+Y: insert character from line above cursor
        if ctrl && key_name == "y" {
            let line = self.view().cursor.line;
            let col = self.view().cursor.col;
            if line > 0 {
                let above_line = line - 1;
                let above_len = self.buffer().line_len_chars(above_line);
                let above_start = self.buffer().line_to_char(above_line);
                if col < above_len {
                    let ch = self.buffer().content.char(above_start + col);
                    if ch != '\n' {
                        let char_idx = self.buffer().line_to_char(line) + col;
                        let s = ch.to_string();
                        self.insert_with_undo(char_idx, &s);
                        self.insert_text_buffer.push_str(&s);
                        self.view_mut().cursor.col += 1;
                        *changed = true;
                    }
                }
            }
            return;
        }

        // Ctrl+D: dedent current line by shiftwidth
        if ctrl && key_name == "d" {
            let line = self.view().cursor.line;
            let line_start = self.buffer().line_to_char(line);
            let sw = self.settings.shift_width as usize;
            // Count leading spaces
            let line_text: String = self.buffer().content.line(line).chars().take(sw).collect();
            let spaces = line_text.chars().take_while(|c| *c == ' ').count();
            let to_remove = spaces.min(sw);
            if to_remove > 0 {
                self.delete_with_undo(line_start, line_start + to_remove);
                self.view_mut().cursor.col = self.view().cursor.col.saturating_sub(to_remove);
                *changed = true;
            }
            return;
        }

        match key_name {
            "Escape" => {
                self.finish_undo_group();
                // Record the insert operation for repeat and ". register
                if !self.insert_text_buffer.is_empty() {
                    self.last_inserted_text = self.insert_text_buffer.clone();
                    self.last_change = Some(Change {
                        op: ChangeOp::Insert,
                        text: self.insert_text_buffer.clone(),
                        count: 1,
                        motion: None,
                    });
                }
                self.mode = Mode::Normal;
                self.clamp_cursor_col();
                // Dismiss signature help when leaving insert mode
                self.lsp_signature_help = None;
                // Collapse all extra cursors.
                self.view_mut().extra_cursors.clear();
                // Refresh position-aware annotations (e.g. git blame) now that
                // we're back in Normal mode. cursor_move is suppressed during
                // Insert mode to avoid stale blame on uncommitted lines.
                self.fire_cursor_move_hook();
            }
            "BackSpace" => {
                if !self.view().extra_cursors.is_empty() {
                    // Multi-cursor BackSpace: delete before every eligible cursor.
                    if self.mc_backspace() {
                        *changed = true;
                    } else {
                        // All cursors at col==0 — do nothing in multi-cursor mode.
                    }
                } else {
                    let line = self.view().cursor.line;
                    let col = self.view().cursor.col;
                    let char_idx = self.buffer().line_to_char(line) + col;
                    if col > 0 {
                        self.delete_with_undo(char_idx - 1, char_idx);
                        self.view_mut().cursor.col -= 1;
                        *changed = true;
                    } else if line > 0 {
                        let prev_line_len = self.buffer().line_len_chars(line - 1);
                        let new_col = if prev_line_len > 0 {
                            prev_line_len - 1
                        } else {
                            0
                        };
                        self.delete_with_undo(char_idx - 1, char_idx);
                        self.view_mut().cursor.line -= 1;
                        self.view_mut().cursor.col = new_col;
                        *changed = true;
                    }
                }
                if *changed {
                    self.trigger_auto_completion();
                }
            }
            "Delete" => {
                if !self.view().extra_cursors.is_empty() {
                    if self.mc_delete_forward() {
                        *changed = true;
                    }
                } else {
                    let line = self.view().cursor.line;
                    let col = self.view().cursor.col;
                    let char_idx = self.buffer().line_to_char(line) + col;
                    if char_idx < self.buffer().len_chars() {
                        self.delete_with_undo(char_idx, char_idx + 1);
                        *changed = true;
                    }
                }
            }
            "Return" => {
                if !self.view().extra_cursors.is_empty() {
                    self.mc_return();
                    self.insert_text_buffer.push('\n');
                    *changed = true;
                } else {
                    let line = self.view().cursor.line;
                    let col = self.view().cursor.col;
                    let char_idx = self.buffer().line_to_char(line) + col;
                    let indent = if self.settings.auto_indent {
                        self.get_line_indent_str(line)
                    } else {
                        String::new()
                    };
                    let indent_len = indent.len();
                    let text = format!("\n{}", indent);
                    self.insert_with_undo(char_idx, &text);
                    self.insert_text_buffer.push('\n');
                    self.view_mut().cursor.line += 1;
                    self.view_mut().cursor.col = indent_len;
                    *changed = true;
                }
            }
            "Tab" => {
                if !self.view().extra_cursors.is_empty() {
                    let tab_text = if self.settings.expand_tab {
                        " ".repeat(self.settings.tabstop as usize)
                    } else {
                        "\t".to_string()
                    };
                    self.insert_text_buffer.push_str(&tab_text);
                    self.mc_insert(&tab_text);
                    *changed = true;
                } else {
                    let line = self.view().cursor.line;
                    let col = self.view().cursor.col;
                    let char_idx = self.buffer().line_to_char(line) + col;
                    if self.settings.expand_tab {
                        let n = self.settings.tabstop as usize;
                        let spaces = " ".repeat(n);
                        self.insert_with_undo(char_idx, &spaces);
                        self.insert_text_buffer.push_str(&spaces);
                        self.view_mut().cursor.col += n;
                    } else {
                        self.insert_with_undo(char_idx, "\t");
                        self.insert_text_buffer.push('\t');
                        self.view_mut().cursor.col += 1;
                    }
                    *changed = true;
                }
            }
            "Left" => self.move_left(),
            "Right" => self.move_right_insert(),
            "Up" => {
                if self.view().cursor.line > 0 {
                    self.view_mut().cursor.line -= 1;
                    self.clamp_cursor_col_insert();
                }
            }
            "Down" => {
                let max_line = self.buffer().len_lines().saturating_sub(1);
                if self.view().cursor.line < max_line {
                    self.view_mut().cursor.line += 1;
                    self.clamp_cursor_col_insert();
                }
            }
            "Home" => self.view_mut().cursor.col = 0,
            "End" => {
                let line = self.view().cursor.line;
                self.view_mut().cursor.col = self.get_line_len_for_insert(line);
            }
            _ => {
                // Try plugin insert-mode keymaps first (for non-printable or special keys)
                if unicode.is_none() && self.plugin_run_keymap("i", key_name) {
                    // keymap handled it — skip default character insertion
                } else if let Some(ch) = unicode {
                    if !self.view().extra_cursors.is_empty() {
                        // Multi-cursor character insert.
                        let mut buf = [0u8; 4];
                        let s = ch.encode_utf8(&mut buf).to_string();
                        self.mc_insert(&s);
                        self.insert_text_buffer.push(ch);
                        *changed = true;
                    } else {
                        let line = self.view().cursor.line;
                        let col = self.view().cursor.col;
                        let char_idx = self.buffer().line_to_char(line) + col;
                        let mut buf = [0u8; 4];
                        let s = ch.encode_utf8(&mut buf);
                        self.insert_with_undo(char_idx, s);
                        self.insert_text_buffer.push(ch);
                        self.view_mut().cursor.col += 1;
                        *changed = true;
                    }
                    // Trigger signature help after '(' or ','
                    if ch == '(' || ch == ',' {
                        self.ensure_lsp_manager();
                        self.lsp_request_signature_help();
                    }
                }
                if *changed {
                    self.trigger_auto_completion();
                }
            }
        }
    }

    /// Insert `text` at the current command-line cursor position and advance the cursor.
    /// Used by backends to paste clipboard content into the command line.
    pub fn command_insert_str(&mut self, text: &str) {
        let byte_off = cmd_char_to_byte(&self.command_buffer, self.command_cursor);
        self.command_buffer.insert_str(byte_off, text);
        self.command_cursor += text.chars().count();
    }

    fn handle_command_key(
        &mut self,
        key_name: &str,
        unicode: Option<char>,
        ctrl: bool,
    ) -> EngineAction {
        // --- Ctrl-R: activate / cycle reverse history search ---
        if ctrl && key_name == "r" {
            if self.history.command_history.is_empty() {
                return EngineAction::None;
            }
            if !self.history_search_active {
                // Enter history search: save current command buffer
                self.history_search_active = true;
                self.history_search_query = String::new();
                self.history_search_index = None;
                self.command_typing_buffer = self.command_buffer.clone();
            }
            // Find next (older) match from current index
            self.history_search_step(true);
            return EngineAction::None;
        }

        // --- Ctrl-G: cancel history search ---
        if ctrl && key_name == "g" && self.history_search_active {
            self.history_search_active = false;
            self.history_search_query.clear();
            self.history_search_index = None;
            self.command_buffer = self.command_typing_buffer.clone();
            self.command_cursor = self.command_buffer.chars().count();
            self.command_typing_buffer.clear();
            return EngineAction::None;
        }

        // --- Ctrl-A / Ctrl-E: move cursor to start/end of command line ---
        if ctrl && key_name == "a" && !self.history_search_active {
            self.command_cursor = 0;
            return EngineAction::None;
        }
        if ctrl && key_name == "e" && !self.history_search_active {
            self.command_cursor = self.command_buffer.chars().count();
            return EngineAction::None;
        }
        // --- Ctrl-K: kill to end of line ---
        if ctrl && key_name == "k" && !self.history_search_active {
            let byte_off = cmd_char_to_byte(&self.command_buffer, self.command_cursor);
            self.command_buffer.truncate(byte_off);
            return EngineAction::None;
        }

        match key_name {
            "Escape" => {
                if self.history_search_active {
                    // Cancel history search, restore original buffer
                    self.history_search_active = false;
                    self.history_search_query.clear();
                    self.history_search_index = None;
                    self.command_buffer = self.command_typing_buffer.clone();
                    self.command_cursor = self.command_buffer.chars().count();
                    self.command_typing_buffer.clear();
                } else {
                    self.mode = if self.is_vscode_mode() {
                        Mode::Insert
                    } else {
                        Mode::Normal
                    };
                    self.command_buffer.clear();
                    self.command_cursor = 0;
                    self.command_history_index = None;
                    self.command_typing_buffer.clear();
                }
                EngineAction::None
            }
            "Return" => {
                self.mode = Mode::Normal;
                // If in history search, the matched command is already in command_buffer
                self.history_search_active = false;
                self.history_search_query.clear();
                self.history_search_index = None;

                let cmd = self.command_buffer.clone();
                self.command_buffer.clear();
                self.command_cursor = 0;
                self.history.add_command(&cmd);
                self.command_history_index = None;
                self.command_typing_buffer.clear();
                let _ = self.session.save();
                let _ = self.history.save();
                let result = self.execute_command(&cmd);
                // If still in VSCode mode after the command, return to Insert (EDIT) mode.
                // (If the command switched to Vim mode, is_vscode_mode() will be false,
                //  so mode stays Normal — which is correct.)
                if self.is_vscode_mode() {
                    self.mode = Mode::Insert;
                }
                result
            }
            "Left" => {
                if !self.history_search_active && self.command_cursor > 0 {
                    self.command_cursor -= 1;
                }
                EngineAction::None
            }
            "Right" => {
                if !self.history_search_active {
                    let len = self.command_buffer.chars().count();
                    if self.command_cursor < len {
                        self.command_cursor += 1;
                    }
                }
                EngineAction::None
            }
            "Home" => {
                if !self.history_search_active {
                    self.command_cursor = 0;
                }
                EngineAction::None
            }
            "End" => {
                if !self.history_search_active {
                    self.command_cursor = self.command_buffer.chars().count();
                }
                EngineAction::None
            }
            "Delete" => {
                if !self.history_search_active {
                    let len = self.command_buffer.chars().count();
                    if self.command_cursor < len {
                        let byte_off = cmd_char_to_byte(&self.command_buffer, self.command_cursor);
                        let next_off =
                            cmd_char_to_byte(&self.command_buffer, self.command_cursor + 1);
                        self.command_buffer.drain(byte_off..next_off);
                    }
                }
                EngineAction::None
            }
            "Up" => {
                // Exit history search first
                self.history_search_active = false;
                self.history_search_query.clear();
                self.history_search_index = None;

                if self.history.command_history.is_empty() {
                    return EngineAction::None;
                }
                if self.command_history_index.is_none() {
                    self.command_typing_buffer = self.command_buffer.clone();
                    self.command_history_index = Some(self.history.command_history.len() - 1);
                } else if let Some(idx) = self.command_history_index {
                    if idx > 0 {
                        self.command_history_index = Some(idx - 1);
                    }
                }
                if let Some(idx) = self.command_history_index {
                    if let Some(cmd) = self.history.command_history.get(idx) {
                        self.command_buffer = cmd.clone();
                        self.command_cursor = self.command_buffer.chars().count();
                    }
                }
                EngineAction::None
            }
            "Down" => {
                // Exit history search first
                self.history_search_active = false;
                self.history_search_query.clear();
                self.history_search_index = None;

                if self.command_history_index.is_none() {
                    return EngineAction::None;
                }
                let idx = self.command_history_index.unwrap();
                if idx + 1 >= self.history.command_history.len() {
                    self.command_buffer = self.command_typing_buffer.clone();
                    self.command_cursor = self.command_buffer.chars().count();
                    self.command_history_index = None;
                } else {
                    self.command_history_index = Some(idx + 1);
                    if let Some(cmd) = self.history.command_history.get(idx + 1) {
                        self.command_buffer = cmd.clone();
                        self.command_cursor = self.command_buffer.chars().count();
                    }
                }
                EngineAction::None
            }
            "Tab" => {
                // Exit history search, then complete
                self.history_search_active = false;
                self.history_search_query.clear();
                self.history_search_index = None;

                let completions = self.complete_command(&self.command_buffer);
                if completions.is_empty() {
                    return EngineAction::None;
                } else if completions.len() == 1 {
                    self.command_buffer = completions[0].clone();
                    self.command_cursor = self.command_buffer.chars().count();
                } else {
                    let common = Self::find_common_prefix(&completions);
                    if common.len() > self.command_buffer.len() {
                        self.command_buffer = common;
                        self.command_cursor = self.command_buffer.chars().count();
                    } else {
                        self.message = format!("Completions: {}", completions.join(", "));
                    }
                }
                EngineAction::None
            }
            "BackSpace" => {
                if self.history_search_active {
                    // Remove last char from search query and re-search
                    self.history_search_query.pop();
                    self.history_search_index = None; // restart from most recent
                    self.history_search_step(false);
                } else {
                    self.command_history_index = None;
                    self.command_typing_buffer.clear();
                    if self.command_cursor > 0 {
                        self.command_cursor -= 1;
                        let byte_off = cmd_char_to_byte(&self.command_buffer, self.command_cursor);
                        let next_off =
                            cmd_char_to_byte(&self.command_buffer, self.command_cursor + 1);
                        self.command_buffer.drain(byte_off..next_off);
                    } else {
                        // Backspace at position 0 with empty buffer exits command mode.
                        // This matches Vim: you must press Backspace once on the empty
                        // line (not while there are still characters) to exit.
                        if self.command_buffer.is_empty() {
                            self.mode = Mode::Normal;
                        }
                    }
                }
                EngineAction::None
            }
            _ => {
                if self.history_search_active {
                    // Append char to search query and find match
                    if let Some(ch) = unicode {
                        if !ch.is_control() {
                            self.history_search_query.push(ch);
                            self.history_search_index = None; // restart from most recent
                            self.history_search_step(false);
                        }
                    }
                } else {
                    self.command_history_index = None;
                    self.command_typing_buffer.clear();
                    if let Some(ch) = unicode {
                        if !ch.is_control() {
                            let byte_off =
                                cmd_char_to_byte(&self.command_buffer, self.command_cursor);
                            self.command_buffer.insert(byte_off, ch);
                            self.command_cursor += 1;
                        }
                    }
                }
                EngineAction::None
            }
        }
    }

    /// Find a history match for the current `history_search_query`.
    /// If `next` is true, start searching one step older than `history_search_index`.
    /// Updates `command_buffer` with the match, or shows "no match" message.
    fn history_search_step(&mut self, next: bool) {
        let query = self.history_search_query.clone();
        let history = &self.history.command_history;
        if history.is_empty() {
            return;
        }

        // Determine start index: search from end (most recent) backwards
        let start = if next {
            // Step one older than current match
            match self.history_search_index {
                Some(0) => {
                    self.message = "(reverse-i-search): no more matches".to_string();
                    return;
                }
                Some(idx) => idx - 1,
                None => history.len() - 1,
            }
        } else {
            history.len() - 1
        };

        // Search backwards from start
        let found = (0..=start)
            .rev()
            .find(|&i| history[i].contains(query.as_str()));

        match found {
            Some(idx) => {
                self.history_search_index = Some(idx);
                self.command_buffer = history[idx].clone();
                self.command_cursor = self.command_buffer.chars().count();
                self.message.clear();
            }
            None => {
                self.message = format!("(reverse-i-search): no match for '{}'", query);
            }
        }
    }

    fn handle_search_key(&mut self, key_name: &str, unicode: Option<char>, ctrl: bool) {
        // Ctrl-A / Ctrl-E: move cursor to start/end
        if ctrl && key_name == "a" {
            self.command_cursor = 0;
            return;
        }
        if ctrl && key_name == "e" {
            self.command_cursor = self.command_buffer.chars().count();
            return;
        }
        // Ctrl-K: kill to end of search query
        if ctrl && key_name == "k" {
            let byte_off = cmd_char_to_byte(&self.command_buffer, self.command_cursor);
            self.command_buffer.truncate(byte_off);
            if self.settings.incremental_search {
                self.perform_incremental_search();
            }
            return;
        }
        match key_name {
            "Escape" => {
                self.mode = Mode::Normal;
                self.command_buffer.clear();
                self.search_history_index = None;
                self.search_typing_buffer.clear();

                // Restore cursor to original position (incremental search)
                if let Some(start_cursor) = self.search_start_cursor.take() {
                    self.view_mut().cursor = start_cursor;
                    // Clear search matches and query
                    self.search_matches.clear();
                    self.search_index = None;
                    self.search_query.clear();
                }
            }
            "Return" => {
                self.mode = Mode::Normal;
                let query = self.command_buffer.clone();
                self.command_buffer.clear();

                // Add to search history
                if !query.is_empty() {
                    // Push the pre-search position to the jump list so Ctrl-O returns here.
                    // With incremental search the cursor has already moved; push the saved
                    // start position (where the cursor was before the user typed `/`).
                    if let Some(start) = self.search_start_cursor {
                        let live = self.view().cursor;
                        self.view_mut().cursor = start;
                        self.push_jump_location();
                        self.view_mut().cursor = live;
                    }

                    self.search_start_cursor = None; // Clear saved cursor position

                    self.history.add_search(&query);
                    self.search_history_index = None;
                    self.search_typing_buffer.clear();

                    // Save session state
                    let _ = self.session.save();
                    let _ = self.history.save();

                    self.search_query = query;
                    self.run_search();
                    // If incremental search is enabled, cursor is already at the correct match
                    // Otherwise, jump to first match in the appropriate direction
                    if !self.settings.incremental_search {
                        match self.search_direction {
                            SearchDirection::Forward => self.search_next(),
                            SearchDirection::Backward => self.search_prev(),
                        }
                    }
                } else {
                    self.search_start_cursor = None;
                }
            }
            "Up" => {
                // Cycle to previous search
                if self.history.search_history.is_empty() {
                    return;
                }

                // First Up press: save current typing
                if self.search_history_index.is_none() {
                    self.search_typing_buffer = self.command_buffer.clone();
                    self.search_history_index = Some(self.history.search_history.len() - 1);
                } else if let Some(idx) = self.search_history_index {
                    if idx > 0 {
                        self.search_history_index = Some(idx - 1);
                    }
                }

                // Load history entry
                if let Some(idx) = self.search_history_index {
                    if let Some(query) = self.history.search_history.get(idx) {
                        self.command_buffer = query.clone();
                        self.command_cursor = self.command_buffer.chars().count();
                    }
                }
            }
            "Down" => {
                // Cycle to next search (or back to typing buffer)
                if self.search_history_index.is_none() {
                    return;
                }

                let idx = self.search_history_index.unwrap();
                if idx + 1 >= self.history.search_history.len() {
                    // Reached end, restore typing buffer
                    self.command_buffer = self.search_typing_buffer.clone();
                    self.command_cursor = self.command_buffer.chars().count();
                    self.search_history_index = None;
                } else {
                    self.search_history_index = Some(idx + 1);
                    if let Some(query) = self.history.search_history.get(idx + 1) {
                        self.command_buffer = query.clone();
                        self.command_cursor = self.command_buffer.chars().count();
                    }
                }
            }
            "Left" => {
                if self.command_cursor > 0 {
                    self.command_cursor -= 1;
                }
            }
            "Right" => {
                let len = self.command_buffer.chars().count();
                if self.command_cursor < len {
                    self.command_cursor += 1;
                }
            }
            "Home" => {
                self.command_cursor = 0;
            }
            "End" => {
                self.command_cursor = self.command_buffer.chars().count();
            }
            "Delete" => {
                self.search_history_index = None;
                self.search_typing_buffer.clear();
                let len = self.command_buffer.chars().count();
                if self.command_cursor < len {
                    let byte_off = cmd_char_to_byte(&self.command_buffer, self.command_cursor);
                    let next_off = cmd_char_to_byte(&self.command_buffer, self.command_cursor + 1);
                    self.command_buffer.drain(byte_off..next_off);
                    if self.settings.incremental_search {
                        self.perform_incremental_search();
                    }
                }
            }
            "BackSpace" => {
                // Reset history navigation when editing
                self.search_history_index = None;
                self.search_typing_buffer.clear();

                if self.command_cursor > 0 {
                    self.command_cursor -= 1;
                    let byte_off = cmd_char_to_byte(&self.command_buffer, self.command_cursor);
                    let next_off = cmd_char_to_byte(&self.command_buffer, self.command_cursor + 1);
                    self.command_buffer.drain(byte_off..next_off);
                }
                if self.command_buffer.is_empty() {
                    self.mode = Mode::Normal;
                    // Restore cursor to original position
                    if let Some(start_cursor) = self.search_start_cursor.take() {
                        self.view_mut().cursor = start_cursor;
                        self.search_matches.clear();
                        self.search_index = None;
                        self.search_query.clear();
                    }
                } else if self.settings.incremental_search {
                    // Incremental search: update search as user types
                    self.perform_incremental_search();
                }
            }
            _ => {
                // Reset history navigation when typing
                self.search_history_index = None;
                self.search_typing_buffer.clear();

                if let Some(ch) = unicode {
                    if !ch.is_control() {
                        let byte_off = cmd_char_to_byte(&self.command_buffer, self.command_cursor);
                        self.command_buffer.insert(byte_off, ch);
                        self.command_cursor += 1;
                        // Incremental search: update search as user types
                        if self.settings.incremental_search {
                            self.perform_incremental_search();
                        }
                    }
                }
            }
        }
    }

    fn handle_visual_key(
        &mut self,
        key_name: &str,
        unicode: Option<char>,
        ctrl: bool,
        changed: &mut bool,
    ) -> EngineAction {
        // Handle Escape to exit visual mode
        if key_name == "Escape" {
            self.mode = Mode::Normal;
            self.visual_anchor = None;
            self.count = None; // Clear count on mode exit
            return EngineAction::None;
        }

        // Leader key in visual mode
        if self.leader_partial.is_some() {
            return self.handle_leader_key(unicode);
        }
        if !ctrl && self.pending_key.is_none() && unicode == Some(self.settings.leader) {
            self.leader_partial = Some(String::new());
            return EngineAction::None;
        }

        // Handle digit accumulation for count (same logic as normal mode)
        if let Some(ch) = unicode {
            if ch.is_ascii_digit() {
                let digit = ch.to_digit(10).unwrap() as usize;
                // Special case: '0' alone should NOT start count accumulation (reserved for column 0)
                // But '0' after a digit (like "10") should accumulate
                if digit == 0 && self.count.is_none() {
                    // Let '0' be handled as a motion command (go to column 0)
                } else {
                    // Accumulate digit into count
                    let current = self.count.unwrap_or(0);
                    let new_count = current * 10 + digit;
                    if new_count > 10000 {
                        self.message = "Count limited to 10,000".to_string();
                        self.count = Some(10000);
                    } else {
                        self.count = Some(new_count);
                    }
                    return EngineAction::None;
                }
            }
        }

        // Handle Ctrl-V for visual block mode switching
        if ctrl && key_name == "v" {
            if self.mode == Mode::VisualBlock {
                // Exit to normal mode
                self.mode = Mode::Normal;
                self.visual_anchor = None;
                self.count = None;
            } else {
                // Switch to VisualBlock mode, preserve anchor
                self.mode = Mode::VisualBlock;
            }
            return EngineAction::None;
        }

        // Handle mode switching: v toggles to Visual, V toggles to VisualLine
        if let Some(ch) = unicode {
            match ch {
                'v' => {
                    if self.mode == Mode::Visual {
                        // Exit to normal mode
                        self.mode = Mode::Normal;
                        self.visual_anchor = None;
                        self.count = None; // Clear count on mode exit
                    } else {
                        // Switch to Visual mode, preserve anchor
                        self.mode = Mode::Visual;
                    }
                    return EngineAction::None;
                }
                'V' => {
                    if self.mode == Mode::VisualLine {
                        // Exit to normal mode
                        self.mode = Mode::Normal;
                        self.visual_anchor = None;
                        self.count = None; // Clear count on mode exit
                    } else {
                        // Switch to VisualLine mode, preserve anchor
                        self.mode = Mode::VisualLine;
                    }
                    return EngineAction::None;
                }
                _ => {}
            }
        }

        // Handle text objects (iw, aw, i", a(, etc.) - set pending key
        if let Some(ch) = unicode {
            if ch == 'i' || ch == 'a' {
                self.pending_key = Some(ch);
                return EngineAction::None;
            }
        }

        // Handle operators: d (delete), y (yank), c (change), u (lowercase), U (uppercase)
        // Note: count is NOT applied to visual operators - they operate on the selection
        if let Some(ch) = unicode {
            match ch {
                'd' => {
                    self.count = None; // Clear count (not used for visual operators)
                    self.delete_visual_selection(changed);
                    return EngineAction::None;
                }
                'y' => {
                    self.count = None; // Clear count (not used for visual operators)
                    self.yank_visual_selection();
                    return EngineAction::None;
                }
                'c' => {
                    self.count = None; // Clear count (not used for visual operators)
                    self.change_visual_selection(changed);
                    return EngineAction::None;
                }
                'u' => {
                    self.count = None; // Clear count (not used for visual operators)
                    self.lowercase_visual_selection(changed);
                    return EngineAction::None;
                }
                'U' => {
                    self.count = None; // Clear count (not used for visual operators)
                    self.uppercase_visual_selection(changed);
                    return EngineAction::None;
                }
                '>' => {
                    // Visual indent: indent all selected lines
                    self.count = None;
                    if let Some((start, end)) = self.get_visual_selection_range() {
                        let start_line = start.line;
                        let end_line = end.line;
                        let line_count = end_line - start_line + 1;
                        // Exit visual mode first
                        self.mode = Mode::Normal;
                        self.visual_anchor = None;
                        self.indent_lines(start_line, line_count, changed);
                        self.view_mut().cursor.line = start_line;
                        self.last_change = Some(Change {
                            op: ChangeOp::Indent,
                            text: String::new(),
                            count: line_count,
                            motion: None,
                        });
                    }
                    return EngineAction::None;
                }
                '<' => {
                    // Visual dedent: dedent all selected lines
                    self.count = None;
                    if let Some((start, end)) = self.get_visual_selection_range() {
                        let start_line = start.line;
                        let end_line = end.line;
                        let line_count = end_line - start_line + 1;
                        // Exit visual mode first
                        self.mode = Mode::Normal;
                        self.visual_anchor = None;
                        self.dedent_lines(start_line, line_count, changed);
                        self.view_mut().cursor.line = start_line;
                        self.last_change = Some(Change {
                            op: ChangeOp::Dedent,
                            text: String::new(),
                            count: line_count,
                            motion: None,
                        });
                    }
                    return EngineAction::None;
                }
                '~' => {
                    // Visual toggle case
                    self.count = None;
                    self.transform_visual_selection(
                        |s| {
                            s.chars()
                                .map(|c| {
                                    if c.is_uppercase() {
                                        c.to_lowercase().next().unwrap_or(c)
                                    } else if c.is_lowercase() {
                                        c.to_uppercase().next().unwrap_or(c)
                                    } else {
                                        c
                                    }
                                })
                                .collect()
                        },
                        changed,
                    );
                    return EngineAction::None;
                }
                ':' => {
                    self.mode = Mode::Command;
                    self.command_buffer = "'<,'>".to_string(); // Auto-populate visual range
                    self.command_cursor = self.command_buffer.chars().count();
                    self.count = None;
                    return EngineAction::None;
                }
                'o' => {
                    // o: swap cursor to other end of selection
                    self.count = None;
                    if let Some(anchor) = self.visual_anchor {
                        let cursor = self.view().cursor;
                        self.visual_anchor = Some(cursor);
                        self.view_mut().cursor = anchor;
                    }
                    return EngineAction::None;
                }
                'r' => {
                    // r{char}: replace all selected characters
                    self.pending_key = Some('r');
                    return EngineAction::None;
                }
                'O' => {
                    // O in VisualBlock: swap to opposite column corner
                    self.count = None;
                    if self.mode == Mode::VisualBlock {
                        if let Some(anchor) = self.visual_anchor {
                            let cursor_col = self.view().cursor.col;
                            let anchor_col = anchor.col;
                            self.view_mut().cursor.col = anchor_col;
                            self.visual_anchor = Some(Cursor {
                                line: anchor.line,
                                col: cursor_col,
                            });
                        }
                    } else {
                        // In Visual/VisualLine O is same as o
                        if let Some(anchor) = self.visual_anchor {
                            let cursor = self.view().cursor;
                            self.visual_anchor = Some(cursor);
                            self.view_mut().cursor = anchor;
                        }
                    }
                    return EngineAction::None;
                }
                _ => {}
            }
        }

        // Handle navigation keys (extend selection)
        // These use the same movement logic as normal mode
        if ctrl {
            match key_name {
                "d" => {
                    let count = self.take_count();
                    let half = self.viewport_lines() / 2;
                    let max_line = self.buffer().len_lines().saturating_sub(1);
                    self.view_mut().cursor.line =
                        (self.view().cursor.line + half * count).min(max_line);
                    self.clamp_cursor_col();
                    return EngineAction::None;
                }
                "u" => {
                    let count = self.take_count();
                    let half = self.viewport_lines() / 2;
                    self.view_mut().cursor.line =
                        self.view().cursor.line.saturating_sub(half * count);
                    self.clamp_cursor_col();
                    return EngineAction::None;
                }
                "f" => {
                    let count = self.take_count();
                    let viewport = self.viewport_lines();
                    let max_line = self.buffer().len_lines().saturating_sub(1);
                    self.view_mut().cursor.line =
                        (self.view().cursor.line + viewport * count).min(max_line);
                    self.clamp_cursor_col();
                    return EngineAction::None;
                }
                "b" => {
                    let count = self.take_count();
                    let viewport = self.viewport_lines();
                    self.view_mut().cursor.line =
                        self.view().cursor.line.saturating_sub(viewport * count);
                    self.clamp_cursor_col();
                    return EngineAction::None;
                }
                _ => {}
            }
        }

        // Handle multi-key sequences (gg, {, }, text objects)
        if let Some(pending) = self.pending_key.take() {
            if pending == 'i' || pending == 'a' {
                // Text object selection
                if let Some(obj_type) = unicode {
                    let cursor = self.view().cursor;
                    let cursor_pos = self.buffer().line_to_char(cursor.line) + cursor.col;

                    if let Some((start_pos, end_pos)) =
                        self.find_text_object_range(pending, obj_type, cursor_pos)
                    {
                        // Set visual selection to the text object range
                        let start_line = self.buffer().content.char_to_line(start_pos);
                        let start_line_char = self.buffer().line_to_char(start_line);
                        let start_col = start_pos - start_line_char;

                        let end_line = self
                            .buffer()
                            .content
                            .char_to_line(end_pos.saturating_sub(1).max(start_pos));
                        let end_line_char = self.buffer().line_to_char(end_line);
                        let end_col = (end_pos - 1).saturating_sub(end_line_char);

                        self.visual_anchor = Some(Cursor {
                            line: start_line,
                            col: start_col,
                        });
                        self.view_mut().cursor.line = end_line;
                        self.view_mut().cursor.col = end_col;

                        // Switch to character visual mode for text objects
                        self.mode = Mode::Visual;
                    }
                }
                return EngineAction::None;
            } else if pending == 'r' {
                // r{char}: replace all selected characters with the given character
                if let Some(replacement) = unicode {
                    self.replace_visual_selection(replacement, changed);
                }
                return EngineAction::None;
            } else if pending == 'g' && unicode == Some('g') {
                // gg in visual mode: with count, go to line N; without count, go to first line
                if let Some(count) = self.peek_count() {
                    self.count = None; // Consume count
                    let target_line = count.saturating_sub(1); // 1-indexed to 0-indexed
                    let max_line = self.buffer().len_lines().saturating_sub(1);
                    self.view_mut().cursor.line = target_line.min(max_line);
                } else {
                    self.view_mut().cursor.line = 0;
                }
                self.view_mut().cursor.col = 0;
                return EngineAction::None;
            }
        }

        // Single-key navigation
        match unicode {
            Some('h') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_left();
                }
            }
            Some('j') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_down();
                }
            }
            Some('k') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_up();
                }
            }
            Some('l') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_right();
                }
            }
            Some('w') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_word_forward();
                }
            }
            Some('b') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_word_backward();
                }
            }
            Some('e') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_word_end();
                }
            }
            Some('0') => self.view_mut().cursor.col = 0,
            Some('$') => {
                let line = self.view().cursor.line;
                self.view_mut().cursor.col = self.get_max_cursor_col(line);
            }
            Some('g') => {
                self.pending_key = Some('g');
            }
            Some('G') => {
                let last_line = self.buffer().len_lines().saturating_sub(1);
                self.view_mut().cursor.line = last_line;
                self.clamp_cursor_col();
            }
            Some('{') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_paragraph_backward();
                }
            }
            Some('}') => {
                let count = self.take_count();
                for _ in 0..count {
                    self.move_paragraph_forward();
                }
            }
            Some('%') => {
                self.move_to_matching_bracket();
            }
            _ => match key_name {
                "Left" => {
                    let count = self.take_count();
                    for _ in 0..count {
                        self.move_left();
                    }
                }
                "Down" => {
                    let count = self.take_count();
                    for _ in 0..count {
                        self.move_down();
                    }
                }
                "Up" => {
                    let count = self.take_count();
                    for _ in 0..count {
                        self.move_up();
                    }
                }
                "Right" => {
                    let count = self.take_count();
                    for _ in 0..count {
                        self.move_right();
                    }
                }
                "Home" => self.view_mut().cursor.col = 0,
                "End" => {
                    let line = self.view().cursor.line;
                    self.view_mut().cursor.col = self.get_max_cursor_col(line);
                }
                _ => {}
            },
        }

        EngineAction::None
    }

    // =======================================================================
    // Visual mode helpers
    // =======================================================================

    /// Get normalized visual selection range (start, end).
    /// Start is always before or equal to end.
    fn get_visual_selection_range(&self) -> Option<(Cursor, Cursor)> {
        let anchor = self.visual_anchor?;
        let cursor = self.view().cursor;

        // Normalize so start <= end
        let (start, end) = if anchor.line < cursor.line
            || (anchor.line == cursor.line && anchor.col <= cursor.col)
        {
            (anchor, cursor)
        } else {
            (cursor, anchor)
        };

        Some((start, end))
    }

    /// Extract the text from the visual selection.
    /// Returns (text, is_linewise).
    fn get_visual_selection_text(&self) -> Option<(String, bool)> {
        let (start, end) = self.get_visual_selection_range()?;

        match self.mode {
            Mode::VisualLine => {
                // Line mode: extract full lines from start.line to end.line (inclusive)
                let start_char = self.buffer().line_to_char(start.line);
                let end_line = end.line;
                let end_char = if end_line + 1 < self.buffer().len_lines() {
                    self.buffer().line_to_char(end_line + 1)
                } else {
                    self.buffer().len_chars()
                };

                let text = self
                    .buffer()
                    .content
                    .slice(start_char..end_char)
                    .to_string();

                // Ensure it ends with newline for linewise
                let text = if text.ends_with('\n') {
                    text
                } else {
                    format!("{}\n", text)
                };

                Some((text, true))
            }
            Mode::Visual => {
                // Character mode: extract from start to end (inclusive)
                let start_char = self.buffer().line_to_char(start.line) + start.col;
                let end_char = self.buffer().line_to_char(end.line) + end.col;

                // Include the character at the end position (Vim-like inclusive)
                let end_char_inclusive = (end_char + 1).min(self.buffer().len_chars());

                let text = self
                    .buffer()
                    .content
                    .slice(start_char..end_char_inclusive)
                    .to_string();

                Some((text, false))
            }
            Mode::VisualBlock => {
                // Block mode: extract rectangular region
                // Use anchor and cursor columns directly for block selection
                let anchor = self.visual_anchor?;
                let cursor = self.view().cursor;
                let start_col = anchor.col.min(cursor.col);
                let end_col = anchor.col.max(cursor.col);

                let mut lines = Vec::new();

                for line_idx in start.line..=end.line {
                    if let Some(line) = self.buffer().content.lines().nth(line_idx) {
                        let line_str = line.to_string();
                        let line_chars: Vec<char> = line_str.chars().collect();

                        // Extract the block portion of this line
                        let block_start = start_col.min(line_chars.len());
                        let block_end = (end_col + 1).min(line_chars.len());

                        let block_text: String = if block_start < line_chars.len() {
                            line_chars[block_start..block_end].iter().collect()
                        } else {
                            // Line is too short, just use empty string
                            String::new()
                        };

                        lines.push(block_text);
                    }
                }

                let text = lines.join("\n");
                Some((text, false))
            }
            _ => None,
        }
    }

    fn yank_visual_selection(&mut self) {
        // Capture the selection region for highlight before exiting visual mode
        let hl_region = self.get_visual_selection_range().map(|(start, end)| {
            let is_linewise = matches!(self.mode, Mode::VisualLine);
            (start, end, is_linewise)
        });

        if let Some((text, is_linewise)) = self.get_visual_selection_text() {
            // Store in selected register (or unnamed register)
            let reg = self.selected_register.unwrap_or('"');
            self.set_yank_register(reg, text, is_linewise);

            self.selected_register = None;
            self.message = format!("{} yanked", if is_linewise { "Line(s)" } else { "Text" });

            if let Some((start, end, lw)) = hl_region {
                self.record_yank_highlight(start, end, lw);
            }
        }

        // Exit visual mode
        self.mode = Mode::Normal;
        self.visual_anchor = None;
    }

    fn delete_visual_selection(&mut self, changed: &mut bool) {
        if let Some((text, is_linewise)) = self.get_visual_selection_text() {
            // Store in register
            let reg = self.selected_register.unwrap_or('"');
            self.set_delete_register(reg, text, is_linewise);
            self.selected_register = None;

            // Delete the selection
            let (start, end) = self.get_visual_selection_range().unwrap();

            self.start_undo_group();

            match self.mode {
                Mode::VisualLine => {
                    // Delete full lines
                    let start_char = self.buffer().line_to_char(start.line);
                    let end_char = if end.line + 1 < self.buffer().len_lines() {
                        self.buffer().line_to_char(end.line + 1)
                    } else {
                        self.buffer().len_chars()
                    };

                    self.delete_with_undo(start_char, end_char);

                    // Position cursor at start of line
                    self.view_mut().cursor.line = start.line;
                    self.view_mut().cursor.col = 0;
                }
                Mode::Visual => {
                    // Delete characters
                    let start_char = self.buffer().line_to_char(start.line) + start.col;
                    let end_char = self.buffer().line_to_char(end.line) + end.col + 1;

                    self.delete_with_undo(start_char, end_char.min(self.buffer().len_chars()));

                    // Position cursor at start
                    self.view_mut().cursor = start;
                }
                Mode::VisualBlock => {
                    // Delete rectangular block (work backwards to avoid offset issues)
                    // Use anchor and cursor columns directly for block selection
                    let anchor = self.visual_anchor.unwrap();
                    let cursor = self.view().cursor;
                    let start_col = anchor.col.min(cursor.col);
                    let end_col = anchor.col.max(cursor.col);

                    for line_idx in (start.line..=end.line).rev() {
                        let line_start_char = self.buffer().line_to_char(line_idx);
                        if let Some(line) = self.buffer().content.lines().nth(line_idx) {
                            let line_str = line.to_string();
                            let line_len = line_str.chars().count();

                            // Only delete if the line is long enough to have characters in the block
                            if start_col < line_len {
                                let block_end = (end_col + 1).min(line_len);
                                let del_start = line_start_char + start_col;
                                let del_end = line_start_char + block_end;
                                self.delete_with_undo(del_start, del_end);
                            }
                        }
                    }

                    // Position cursor at start of block
                    self.view_mut().cursor.line = start.line;
                    self.view_mut().cursor.col = start_col;
                }
                _ => {}
            }

            self.finish_undo_group();
            *changed = true;
            self.clamp_cursor_col();
        }

        // Exit visual mode
        self.mode = Mode::Normal;
        self.visual_anchor = None;
    }

    fn change_visual_selection(&mut self, changed: &mut bool) {
        // Change is like delete, but then enter insert mode
        self.delete_visual_selection(changed);

        // The delete already finished the undo group and set mode to Normal
        // Now start a new undo group for the insert mode typing
        self.start_undo_group();
        self.insert_text_buffer.clear();
        self.mode = Mode::Insert;
    }

    fn lowercase_visual_selection(&mut self, changed: &mut bool) {
        self.transform_visual_selection(|s| s.to_lowercase(), changed);
    }

    fn uppercase_visual_selection(&mut self, changed: &mut bool) {
        self.transform_visual_selection(|s| s.to_uppercase(), changed);
    }

    fn transform_visual_selection<F>(&mut self, transform: F, changed: &mut bool)
    where
        F: Fn(&str) -> String,
    {
        let (start, end) = match self.get_visual_selection_range() {
            Some(range) => range,
            None => return,
        };

        self.start_undo_group();

        match self.mode {
            Mode::VisualLine => {
                // Transform full lines
                for line_idx in start.line..=end.line {
                    if let Some(line) = self.buffer().content.lines().nth(line_idx) {
                        let line_str = line.to_string();
                        let transformed = transform(&line_str);

                        // Replace the line
                        let line_start_char = self.buffer().line_to_char(line_idx);
                        let line_end_char = line_start_char + line_str.chars().count();
                        self.delete_with_undo(line_start_char, line_end_char);
                        self.insert_with_undo(line_start_char, &transformed);
                    }
                }

                // Position cursor at start of first line
                self.view_mut().cursor.line = start.line;
                self.view_mut().cursor.col = 0;
            }
            Mode::Visual => {
                // Transform character selection
                if let Some((text, _)) = self.get_visual_selection_text() {
                    let transformed = transform(&text);

                    let start_char = self.buffer().line_to_char(start.line) + start.col;
                    let end_char = self.buffer().line_to_char(end.line) + end.col + 1;

                    self.delete_with_undo(start_char, end_char.min(self.buffer().len_chars()));
                    self.insert_with_undo(start_char, &transformed);

                    // Position cursor at start
                    self.view_mut().cursor = start;
                }
            }
            Mode::VisualBlock => {
                // Transform rectangular block (work backwards to maintain positions)
                let anchor = self.visual_anchor.unwrap();
                let cursor = self.view().cursor;
                let start_col = anchor.col.min(cursor.col);
                let end_col = anchor.col.max(cursor.col);

                for line_idx in (start.line..=end.line).rev() {
                    let line_start_char = self.buffer().line_to_char(line_idx);
                    if let Some(line) = self.buffer().content.lines().nth(line_idx) {
                        let line_str = line.to_string();
                        let line_chars: Vec<char> = line_str.chars().collect();

                        // Extract and transform the block portion
                        if start_col < line_chars.len() {
                            let block_end = (end_col + 1).min(line_chars.len());
                            let block_text: String =
                                line_chars[start_col..block_end].iter().collect();
                            let transformed = transform(&block_text);

                            let del_start = line_start_char + start_col;
                            let del_end = line_start_char + block_end;
                            self.delete_with_undo(del_start, del_end);
                            self.insert_with_undo(del_start, &transformed);
                        }
                    }
                }

                // Position cursor at start of block
                self.view_mut().cursor.line = start.line;
                self.view_mut().cursor.col = start_col;
            }
            _ => {}
        }

        self.finish_undo_group();
        *changed = true;
        self.clamp_cursor_col();

        // Exit visual mode
        self.mode = Mode::Normal;
        self.visual_anchor = None;
    }

    // =======================================================================
    // Repeat command (.)
    // =======================================================================

    fn repeat_last_change(&mut self, repeat_count: usize, changed: &mut bool) {
        let change = match &self.last_change {
            Some(c) => c.clone(),
            None => return, // No change to repeat
        };

        let final_count = if repeat_count > 1 {
            repeat_count
        } else {
            change.count
        };

        match change.op {
            ChangeOp::Insert => {
                // Repeat insert: insert the same text at current position
                self.start_undo_group();
                let line = self.view().cursor.line;
                let col = self.view().cursor.col;
                let char_idx = self.buffer().line_to_char(line) + col;

                // Insert the text final_count times
                let repeated_text = change.text.repeat(final_count);
                self.insert_with_undo(char_idx, &repeated_text);

                // Update cursor position based on inserted text
                let newlines = repeated_text.matches('\n').count();
                if newlines > 0 {
                    self.view_mut().cursor.line += newlines;
                    // Find column after last newline
                    if let Some(last_nl) = repeated_text.rfind('\n') {
                        self.view_mut().cursor.col = repeated_text[last_nl + 1..].chars().count();
                    }
                } else {
                    self.view_mut().cursor.col += repeated_text.chars().count();
                }
                self.finish_undo_group();
                *changed = true;
            }
            ChangeOp::Delete => {
                // Repeat delete with motion
                if let Some(motion) = &change.motion {
                    for _ in 0..final_count {
                        self.start_undo_group();
                        match motion {
                            Motion::Right => {
                                // Delete character(s) at cursor (like x)
                                let line = self.view().cursor.line;
                                let col = self.view().cursor.col;
                                let char_idx = self.buffer().line_to_char(line) + col;
                                let line_end = self.buffer().line_to_char(line)
                                    + self.buffer().line_len_chars(line);
                                let available = line_end - char_idx;
                                let to_delete = change.count.min(available);

                                if to_delete > 0 && char_idx < self.buffer().len_chars() {
                                    let deleted_chars: String = self
                                        .buffer()
                                        .content
                                        .slice(char_idx..char_idx + to_delete)
                                        .chars()
                                        .collect();
                                    let reg = self.active_register();
                                    self.set_register(reg, deleted_chars, false);
                                    self.clear_selected_register();
                                    self.delete_with_undo(char_idx, char_idx + to_delete);
                                    self.clamp_cursor_col();
                                    *changed = true;
                                }
                            }
                            Motion::DeleteLine => {
                                // Repeat dd
                                self.delete_lines(change.count, changed);
                            }
                            _ => {}
                        }
                        self.finish_undo_group();
                    }
                }
            }
            ChangeOp::Change => {
                // Repeat change operation - for now just handle simple cases
                // More complex handling would go here
            }
            ChangeOp::Substitute => {
                // Repeat s command
                for _ in 0..final_count {
                    let line = self.view().cursor.line;
                    let col = self.view().cursor.col;
                    let max_col = self.get_max_cursor_col(line);
                    if max_col > 0 || self.buffer().line_len_chars(line) > 0 {
                        let char_idx = self.buffer().line_to_char(line) + col;
                        let line_end =
                            self.buffer().line_to_char(line) + self.buffer().line_len_chars(line);
                        let available = line_end - char_idx;
                        let to_delete = change.count.min(available);

                        self.start_undo_group();
                        if to_delete > 0 && char_idx < self.buffer().len_chars() {
                            self.delete_with_undo(char_idx, char_idx + to_delete);
                            *changed = true;
                        }

                        // Insert the recorded text
                        if !change.text.is_empty() {
                            self.insert_with_undo(char_idx, &change.text);
                            *changed = true;
                        }
                        self.finish_undo_group();
                    }
                }
            }
            ChangeOp::SubstituteLine | ChangeOp::DeleteToEnd | ChangeOp::ChangeToEnd => {
                // Handle other operations
            }
            ChangeOp::Replace => {
                // Repeat r command
                if let Some(replacement_char) = change.text.chars().next() {
                    for _ in 0..final_count {
                        self.start_undo_group();
                        self.replace_chars(replacement_char, change.count, changed);
                        self.finish_undo_group();
                    }
                }
            }
            ChangeOp::ToggleCase => {
                // Repeat ~ command
                for _ in 0..final_count {
                    self.toggle_case_at_cursor(change.count, changed);
                }
            }
            ChangeOp::Join => {
                // Repeat J command
                for _ in 0..final_count {
                    self.join_lines(change.count, changed);
                }
            }
            ChangeOp::Indent => {
                // Repeat >> command
                let line = self.view().cursor.line;
                for _ in 0..final_count {
                    self.indent_lines(line, change.count, changed);
                }
            }
            ChangeOp::Dedent => {
                // Repeat << command
                let line = self.view().cursor.line;
                for _ in 0..final_count {
                    self.dedent_lines(line, change.count, changed);
                }
            }
        }
    }

