        press_char(&mut engine, 'v');
        press_char(&mut engine, 'a');
        press_char(&mut engine, 'w');

        assert_eq!(engine.mode, Mode::Visual);

        // Yank the selection
        press_char(&mut engine, 'y');
        let (content, _) = engine.registers.get(&'"').unwrap();
        assert_eq!(content, "two ");
