        // Simulate visual selection on lines 0-1
        engine.mode = Mode::VisualLine;
        engine.visual_anchor = Some(Cursor { line: 0, col: 0 });
        engine.view_mut().cursor = Cursor { line: 1, col: 0 };

        engine.execute_command("'<,'>s/bar/qux/");
