    fn test_cc_jump() {
        let mut engine = Engine::new();
        engine.quickfix_items = vec![
            make_qf_item("a.rs"),
            make_qf_item("b.rs"),
            make_qf_item("c.rs"),
        ];
        engine.quickfix_open = true;

        engine.execute_command("cc 2");
        assert_eq!(
            engine.quickfix_selected, 1,
            ":cc 2 should select index 1 (1-based)"
        );
    }

