        assert_eq!(engine_visual_rows_for_line(80, 80), 1); // exactly one row
        assert_eq!(engine_visual_rows_for_line(81, 80), 2); // one char overflow
        assert_eq!(engine_visual_rows_for_line(160, 80), 2); // exactly two rows
